-- Poems batch 98
INSERT OR IGNORE INTO poems (id,title,author,dynasty,collection,collection_id,rhythmic,tags,excerpt,length,source_path,paragraphs) VALUES
('e103b3cb-2172-4819-99be-119b1b9ac353','漁父詞  其一四','宋高宗','宋','宋诗','song-poetry','','[]','春入渭陽花氣多，春歸時節自清和。',32,'全唐诗/poet.song.115000.json','["春入渭陽花氣多，春歸時節自清和。", "衝曉霧，弄滄波，載與俱歸又若何。"]'),
('b66a1c36-b702-4379-a1ed-9a649646a4db','漁父詞  其一五','宋高宗','宋','宋诗','song-poetry','','[]','清灣幽島任盤紆，一舸橫斜得自如。',32,'全唐诗/poet.song.115000.json','["清灣幽島任盤紆，一舸橫斜得自如。", "唯有此，更無居，從教紅袖泣前魚。"]'),
('8be016bd-c8d9-43dc-b0ce-9d27e64fb90d','題丹桂畫扇賜從臣  其一','宋高宗','宋','宋诗','song-poetry','','[]','月宮移就日宮栽，引得輕紅入面來。',32,'全唐诗/poet.song.116000.json','["月宮移就日宮栽，引得輕紅入面來。", "好向烟霄承雨露，丹心一一爲君開。"]'),
('00857a9f-2df7-4f49-9367-efcb83b7686f','題丹桂畫扇賜從臣  其二','宋高宗','宋','宋诗','song-poetry','','[]','秋入幽叢桂影團，香深粟粟照林丹。',32,'全唐诗/poet.song.116000.json','["秋入幽叢桂影團，香深粟粟照林丹。", "應隨王母瑶池曉，染得朝霞下廣寒。"]'),
('e3d21728-d576-4a1e-ba5a-d46a2224de3f','虛堂','宋高宗','宋','宋诗','song-poetry','','[]','虛堂燕坐悄無言，欲斷殘香冷自煙。',32,'全唐诗/poet.song.116000.json','["虛堂燕坐悄無言，欲斷殘香冷自煙。", "秋色滿山林桂靜，一輪霜月瀉寒泉。"]'),
('9ff1bce9-a436-4d55-a641-1eb219340500','崇恩顯義院五首  其一','宋高宗','宋','宋诗','song-poetry','','[]','春鶑葉底引圓吭，臨罷黄庭日更長。',32,'全唐诗/poet.song.116000.json','["春鶑葉底引圓吭，臨罷黄庭日更長。", "滿院柳花寒食後，旋鑽新火爇爐香。"]'),
('0d4bf331-60d3-4d9e-94f6-4ce3fa1f12c5','崇恩顯義院五首  其二','宋高宗','宋','宋诗','song-poetry','','[]','都城日落馬蕭蕭，雨壓春風暗柳條。',32,'全唐诗/poet.song.116000.json','["都城日落馬蕭蕭，雨壓春風暗柳條。", "天際歸艎那可望，只將心寄海門潮。"]'),
('c9390c2f-935b-4a42-a478-8e3c57005a1c','崇恩顯義院五首  其三','宋高宗','宋','宋诗','song-poetry','','[]','松竹幽禽尺素間，恍然真向雪中看。',32,'全唐诗/poet.song.116000.json','["松竹幽禽尺素間，恍然真向雪中看。", "動摇已自清風足，何况丹青寫歲寒。"]'),
('38288057-58b3-427d-8e80-319391d1848d','崇恩顯義院五首  其四','宋高宗','宋','宋诗','song-poetry','','[]','管妙絃清韻入神，老人合眼醉醺醺。',32,'全唐诗/poet.song.116000.json','["管妙絃清韻入神，老人合眼醉醺醺。", "成知不及當來曲，猶覺聞時勝不聞。"]'),
('c48a8121-fa64-45bf-8003-e865a3c4d219','崇恩顯義院五首  其五','宋高宗','宋','宋诗','song-poetry','','[]','海神來過隠風迴，浪打天門石壁開。',32,'全唐诗/poet.song.116000.json','["海神來過隠風迴，浪打天門石壁開。", "浙江八月何如此，清似連山噴雪來。"]'),
('07c13c3a-4897-4bf0-8cb4-11e8318ae7a3','秋日','宋高宗','宋','宋诗','song-poetry','','[]','爽氣澄蘭沼，秋風動桂林。',48,'全唐诗/poet.song.116000.json','["爽氣澄蘭沼，秋風動桂林。", "露凝千片玉，菊散一叢金。", "日岫高低影，雲空點綴陰。", "蓬瀛不可望，泉石且娛心。"]'),
('2ef99248-3eb4-4a1d-9b9c-af8cefbc176c','吳郡王冷泉圖贊','宋高宗','宋','宋诗','song-poetry','','[]','富貴不驕，戚畹稱賢。',40,'全唐诗/poet.song.116000.json','["富貴不驕，戚畹稱賢。", "掃除膏粱，放曠林泉。", "滄浪濯足，風度蕭然。", "國之元舅，人中神仙。"]'),
('5fa158af-75cc-443b-93c8-227b8ed732f2','紹興己巳南郊禮成','宋高宗','宋','宋诗','song-poetry','','[]','清壇祗謁禮郊丘，輔相賢勞其款留。',64,'全唐诗/poet.song.116000.json','["清壇祗謁禮郊丘，輔相賢勞其款留。", "初訝密雲低覆冒，遽看霽景上飛浮。", "氣回俎豆羣工泰，喜入貔貅萬馬秋。", "赫赫天心允昭格，協謀同德頼嘉猷。"]'),
('90cae8a3-6f25-4439-9cf3-fd738a6a4a26','皇甫真人像贊','宋高宗','宋','宋诗','song-poetry','','[]','皇甫高士，眉字列仙。',40,'全唐诗/poet.song.116000.json','["皇甫高士，眉字列仙。", "以道興世，孰計其年。", "閑雲在空，孤鶴行天。", "掀髯一笑，同乎自然。"]'),
('792746f7-7bda-4116-af17-52047b46ddad','詩四首  其一','宋高宗','宋','宋诗','song-poetry','','[]','入門無平田，石路穿細嶺。',168,'全唐诗/poet.song.116000.json','["入門無平田，石路穿細嶺。", "陰風生澗壑，古木翳渾井。", "湛盧誰復見，秋水光耿耿。", "鐵花秀巖壁，殺氣禁蛙黽。", "幽幽生公堂，左右立頑礦。", "當年或未信，異類服精猛。", "胡爲百歲後，仙鬼互馳騁。", "窈然留清詩，讀者爲悲哽。", "東軒有佳致，雲水麗千頃。", "熙熙覽生物，春意頗凄冷。", "我來屬無事，暖日相與永。", "喜鵲翻初旦，愁鳶蹲落景。", "坐見漁樵還，新月溪上影。", "悟彼良自咍，歸田行可請。"]'),
('6da70a51-0c3d-48d8-b3fd-7309b6adcc63','詩四首  其二','宋高宗','宋','宋诗','song-poetry','','[]','高居大士是龍象，草堂大人非熊羆。',64,'全唐诗/poet.song.116000.json','["高居大士是龍象，草堂大人非熊羆。", "不逢壞衲乞香飯，唯見白頭垂釣絲。", "鴛鴦終日愛水鏡，菡萏晚風凋舞衣。", "開徑老禪來煮茗，還尋密竹逕中歸。"]'),
('56c24e55-ab80-4b47-b66a-f70bbc034f05','詩四首  其三','宋高宗','宋','宋诗','song-poetry','','[]','陳留春色掩思詩，一日搜腸一百迴。',64,'全唐诗/poet.song.116000.json','["陳留春色掩思詩，一日搜腸一百迴。", "燕子初歸風不定，桃花欲動雨頻來。", "人間多待須微祿，夢裏相逢記此杯。", "白竹扇前客醉舞，煙村渺渺欠高臺。"]'),
('48ed367b-3aca-4849-ba82-4bf3acfd5b63','詩四首  其四','宋高宗','宋','宋诗','song-poetry','','[]','種竹不必高，摇綠當我楹。',120,'全唐诗/poet.song.116000.json','["種竹不必高，摇綠當我楹。", "向來三家墅，無此笙簫聲。", "皇天有老眼，爲閟十月晴。", "護我蕭蕭碧，偉事鄰翁驚。", "同林偶落此，相向意甚平。", "何須俟迷日，可笑世俗情。", "明年萬夭矯，穿地聽雷鳴。", "但恨種竹人，南山合歸耕。", "他時夢中路，留眼記所更。", "蒼雲屯十里，不見陳留城。"]'),
('8b5d3bf0-6456-430a-b4f3-e14abfa17994','題李唐畫賜王都提舉并賜長壽酒','宋高宗','宋','宋诗','song-poetry','','[]','恩霑長壽酒，歸遺同心人。',24,'全唐诗/poet.song.116000.json','["恩霑長壽酒，歸遺同心人。", "滿酌共君醉，一杯千萬春。"]'),
('4243b2a4-31ec-451f-9c32-31e897e27922','題馬麟亭臺圖卷','宋高宗','宋','宋诗','song-poetry','','[]','後院深沉景物幽，奇花名卉弄春柔。',32,'全唐诗/poet.song.116000.json','["後院深沉景物幽，奇花名卉弄春柔。", "翠華經歲無遊幸，多少亭臺廢不修。"]'),
('5a87409f-36f6-4da6-9364-770946842fcd','題馬麟畫','宋高宗','宋','宋诗','song-poetry','','[]','南望青山滿禁闈，曉陪鴛鷺正差池。',32,'全唐诗/poet.song.116000.json','["南望青山滿禁闈，曉陪鴛鷺正差池。", "共愛朝來何處雪，蓬萊宮裏拂松枝。"]'),
('4affe543-ae41-4141-9951-8f1fada464cb','徐熙設色花鳥','宋高宗','宋','宋诗','song-poetry','','[]','人言道院屬江西，古一真人卧水湄。',32,'全唐诗/poet.song.116000.json','["人言道院屬江西，古一真人卧水湄。", "可是瑞蓮花葉大，載他書冊泛漣漪。"]'),
('43669420-63f1-434b-909c-bd06c07ea266','題馬遠畫冊五首  其一','宋高宗','宋','宋诗','song-poetry','','[]','桃李無言春告歸，落紅如海亂鶑啼。',32,'全唐诗/poet.song.116000.json','["桃李無言春告歸，落紅如海亂鶑啼。", "西村渡口斜陽裏，渺渺烟波綠拍堤。"]'),
('0542517b-1eed-47ff-a523-57812d130a88','題馬遠畫冊五首  其二','宋高宗','宋','宋诗','song-poetry','','[]','閒來洞口訪劉君，緩步輕抬玉線裙。',32,'全唐诗/poet.song.116000.json','["閒來洞口訪劉君，緩步輕抬玉線裙。", "細白桃花擲流水，更無言語倚彤雲。"]'),
('93747c37-5148-4669-ba15-12e331093eb9','題馬遠畫冊五首  其三','宋高宗','宋','宋诗','song-poetry','','[]','高山流水意無窮，三尺雲絃膝上桐。',32,'全唐诗/poet.song.116000.json','["高山流水意無窮，三尺雲絃膝上桐。", "默默此時誰會得，坐憑江閣看飛鴻。"]'),
('81041eff-5239-4359-baf8-1a6159165c78','題馬遠畫冊五首  其四','宋高宗','宋','宋诗','song-poetry','','[]','月午江空桂花落，華陽道士雲衣薄。',32,'全唐诗/poet.song.116000.json','["月午江空桂花落，華陽道士雲衣薄。", "石壇香散步虛聲，杉露清泠滴棲鶴。"]'),
('cab76dd1-b5e9-47fe-9f70-cf65e42d0c8a','題馬遠畫冊五首  其五','宋高宗','宋','宋诗','song-poetry','','[]','不禱自安緣壽骨，人間難得是清名。',32,'全唐诗/poet.song.116000.json','["不禱自安緣壽骨，人間難得是清名。", "淺斟仙酒紅生頰，永保長生道自成。"]'),
('a0f6140a-9921-4a84-b036-15c78b5a0c74','題畫冊花草四首 蠟梅','宋高宗','宋','宋诗','song-poetry','','[]','香蜜裁葩分外工，疎枝幾點綴雛蜂。',32,'全唐诗/poet.song.116000.json','["香蜜裁葩分外工，疎枝幾點綴雛蜂。", "嬌黄染就宮粧樣，香煖尤宜愛日烘。"]'),
('5a2f1b7e-bfff-40af-9162-69250679a05b','題畫冊花草四首 修竹芙蓉','宋高宗','宋','宋诗','song-poetry','','[]','寒花婀娜露凝香，風葉摇秋鳳尾凉。',32,'全唐诗/poet.song.116000.json','["寒花婀娜露凝香，風葉摇秋鳳尾凉。", "夢入畫堂銀燭下，翠屏深處隠紅粧。"]'),
('2d631e50-d50c-4aba-a82f-686b501e58a6','題畫冊花草四首 墨竹','宋高宗','宋','宋诗','song-poetry','','[]','墨花垂兔頴，千古尚漓漓。',48,'全唐诗/poet.song.116000.json','["墨花垂兔頴，千古尚漓漓。", "翠羽風前葉，秋聲雨一枝。", "詩題春粉節，䙀脫玉嬰兒。", "湘浦人何在，空聞鳳管吹。"]'),
('5d523dd2-fef3-43f2-9277-399bc2dbf3d0','題畫冊花草四首 雪中山茶','宋高宗','宋','宋诗','song-poetry','','[]','名出本南山，來依瓊苑間。',48,'全唐诗/poet.song.116000.json','["名出本南山，來依瓊苑間。", "陳主歌前樹，楊妃醉後顔。", "爲嫌脂太赤，故著粉微斑。", "共言攀折處，已獲寶枝還。"]'),
('61612310-e38e-4a62-91ad-35009c8c6ed4','題趙伯駒團扇月宮圖冊','宋高宗','宋','宋诗','song-poetry','','[]','清凉境界火雲藏，但覺仙家日更長。',32,'全唐诗/poet.song.116000.json','["清凉境界火雲藏，但覺仙家日更長。", "千歲壽松誰宴坐，星君午夜吐光芒。"]'),
('b50fd528-26da-40e6-9215-e1f8e5e75746','題馬麟畫冊','宋高宗','宋','宋诗','song-poetry','','[]','已過穀雨十六日，猶見牡丹開淺紅。',32,'全唐诗/poet.song.116000.json','["已過穀雨十六日，猶見牡丹開淺紅。", "曾不爭先及開早，能陪芍藥倒薰風。"]'),
('ad057d95-70bd-481c-9c49-6f8a6bcd6f84','題閻次平小景','宋高宗','宋','宋诗','song-poetry','','[]','西來白水滿南池，走馬池邊日暮時。',32,'全唐诗/poet.song.116000.json','["西來白水滿南池，走馬池邊日暮時。", "橋底荷花無限思，清香乞與路人知。"]'),
('9b9a074c-ffbf-44ee-aec5-0641e8c7fb64','白葛蒲聯句','宋高宗','宋','宋诗','song-poetry','','[]','惟不識泥土，堆根抱玉泉。',24,'全唐诗/poet.song.116000.json','["惟不識泥土，堆根抱玉泉。", "雖離巖谷伴，也則翠千年。"]'),
('fd9d2006-7b9f-4dbf-9fd9-bcd1f843f71f','幸天長賜僧廣寶','宋高宗','宋','宋诗','song-poetry','','[]','大界宜春賞，禪門不掩關。',48,'全唐诗/poet.song.116000.json','["大界宜春賞，禪門不掩關。", "宸遊雙闕外，僧引百花間。", "車馬喧長路，烟雲浄遠山。", "觀空復觀俗，皇鑑此中閒。"]'),
('f1a42894-a539-4c0a-bd34-6999df6ede18','賜僧守璋二首  其一','宋高宗','宋','宋诗','song-poetry','','[]','古寺春山青更妍，長松修竹翠含烟。',32,'全唐诗/poet.song.116000.json','["古寺春山青更妍，長松修竹翠含烟。", "汲泉擬欲增茶興，暫就僧房借榻眠。"]'),
('87bb8fe4-2caa-4d01-80b7-f10385871bee','賜僧守璋二首  其二','宋高宗','宋','宋诗','song-poetry','','[]','久坐方知春晝長，靜中心地自清凉。',32,'全唐诗/poet.song.116000.json','["久坐方知春晝長，靜中心地自清凉。", "人言圓覺何曾覺，但見塵勞盡日忙。"]'),
('88026a92-1d8b-46d9-bbed-64ab02c45324','詩二首  其一','宋高宗','宋','宋诗','song-poetry','','[]','隨宜飲酒聊充腹，取次衣裘亦暖身。',64,'全唐诗/poet.song.116000.json','["隨宜飲酒聊充腹，取次衣裘亦暖身。", "未必得年非瘦薄，無妨長福是單貧。", "老龜豈羨犧牲飽，蟠木寧爭桃李春。", "隨分自安心自斷，是非何必問閒人。"]'),
('9bd64034-ec2f-4deb-aeb1-42fbe89ca8b3','詩二首  其二','宋高宗','宋','宋诗','song-poetry','','[]','地黄飼老馬，可使光鑒人。',120,'全唐诗/poet.song.116000.json','["地黄飼老馬，可使光鑒人。", "吾聞樂天語，喻馬施之身。", "我衰正伏櫪，垂耳氣不振。", "移栽附沃壤，蕃茂爭新春。", "沈水得穉根，重湯養陳薪。", "投以東阿清，和以北海醇。", "崖蜜助甘泠，山薑發芳辛。", "融爲寒食餳，嚥作瑞露珍。", "丹田自宿火，渴肺還生津。", "願餉內熱子，一洗胸中塵。"]'),
('dc1720f2-7eb3-46cb-9504-02048324753a','題唐鄭虔山居說聽圖','宋高宗','宋','宋诗','song-poetry','','[]','言者不知知者默，此語吾聞於老君。',32,'全唐诗/poet.song.116000.json','["言者不知知者默，此語吾聞於老君。", "若道老君是知者，緣何自著五千文。"]'),
('b7e73607-02cf-4217-b879-9f98e6eceb21','題趙幹北窗高卧圖','宋高宗','宋','宋诗','song-poetry','','[]','林間無事可裝懷，晝睡功勞酒一盃。',32,'全唐诗/poet.song.116000.json','["林間無事可裝懷，晝睡功勞酒一盃。", "殘夢不能全省記，半隨風雨過東街。"]'),
('cba2ea80-2573-4aad-bd9d-38ccaba77aa3','題燕文貴柳莊觀荷圖','宋高宗','宋','宋诗','song-poetry','','[]','萬片綠荷流水西，亂風飄雨濕人衣。',32,'全唐诗/poet.song.116000.json','["萬片綠荷流水西，亂風飄雨濕人衣。", "前村竹樹田家密，時見軥輈屋後飛。"]'),
('f2e67967-ebfd-404d-943d-7647fec2c03a','題劉松年竹樓說聽圖','宋高宗','宋','宋诗','song-poetry','','[]','小書樓下千竿竹，深火爐前一盞燈。',32,'全唐诗/poet.song.116000.json','["小書樓下千竿竹，深火爐前一盞燈。", "此處與誰相伴宿，燒丹道士坐禪僧。"]'),
('099ea5d6-db3e-4fe9-a717-57861fbdaf04','題劉松年畫團扇二首  其一','宋高宗','宋','宋诗','song-poetry','','[]','南山晴翠入波光，一派溪聲繞路長。',32,'全唐诗/poet.song.116000.json','["南山晴翠入波光，一派溪聲繞路長。", "最愛早春沙岸煖，東風輕浪拍鴛鴦。"]'),
('8824b47b-9926-4c4e-ab00-14a262ccc1b1','題劉松年畫團扇二首  其二','宋高宗','宋','宋诗','song-poetry','','[]','荷葉如錢三月時，幅巾藜杖一追隨。',32,'全唐诗/poet.song.116000.json','["荷葉如錢三月時，幅巾藜杖一追隨。", "爾來勝事知多少，惟有風標公子知。"]'),
('27affd94-d27f-45e1-9177-048960ae87c1','題黄筌芙蓉圖','宋高宗','宋','宋诗','song-poetry','','[]','照水枝枝蜀錦囊，年年澤國爲誰芳。',32,'全唐诗/poet.song.116000.json','["照水枝枝蜀錦囊，年年澤國爲誰芳。", "朱顔自得西風意，不管千林一夜霜。"]'),
('82e18b4e-ade7-4905-839c-d5b0029ca112','賜劉能真三首  其一','宋高宗','宋','宋诗','song-poetry','','[]','簡易高人道，崇玄性自真。',48,'全唐诗/poet.song.116000.json','["簡易高人道，崇玄性自真。", "身常居太極，心已遠凡塵。", "玉陛辭榮祿，瑶臺役鬼神。", "辛勤三十載，羨爾道心淳。"]'),
('55c17688-f7b1-42d1-8479-7177d4e2b5de','賜劉能真三首  其二','宋高宗','宋','宋诗','song-poetry','','[]','太白巃嵷東南馳，衆嶺環合青分披。',64,'全唐诗/poet.song.116000.json','["太白巃嵷東南馳，衆嶺環合青分披。", "烟雲厚薄皆可愛，木石疎密自相宜。", "陽春已歸鳥語樂，溪水不動魚行遲。", "生民無不得處所，與茲魚鳥皆熙熙。"]'),
('0152aaa1-661f-4be3-b9d5-f1e6718ef17e','賜劉能真三首  其三','宋高宗','宋','宋诗','song-poetry','','[]','憶昔辰江阻颶風，于今神馬又成龍。',32,'全唐诗/poet.song.116000.json','["憶昔辰江阻颶風，于今神馬又成龍。", "炎興指日中原復，賸是茅君翊翼功。"]'),
('fb60b0a1-753f-4dc3-b31a-4a6ef5d21893','文宣王及其弟子贊  其一','宋高宗','宋','宋诗','song-poetry','','[]','大哉聖宣，斯文在茲。',60,'全唐诗/poet.song.116000.json','["大哉聖宣，斯文在茲。", "帝王之式，古今之師。", "志則春秋，道由忠恕。", "賢於堯舜，日月其譽。", "維時載雍，戢此武功。", "肅昭盛儀，海㝢聿崇。"]'),
('8b5cdfcf-f0ce-4bf8-8625-eb4dea449c7e','文宣王及其弟子贊  其二','宋高宗','宋','宋诗','song-poetry','','[]','德行首科，顯冠學徒。',40,'全唐诗/poet.song.116000.json','["德行首科，顯冠學徒。", "不遷不貳，樂道以居。", "食埃甚忠，在陋自如。", "宜稱賢哉，豈止不愚。"]'),
('c6e99368-3903-4c49-8cef-303c124a951c','文宣王及其弟子贊  其三','宋高宗','宋','宋诗','song-poetry','','[]','天經地義，孝哉閔騫。',40,'全唐诗/poet.song.116000.json','["天經地義，孝哉閔騫。", "父母昆弟，莫間其言。", "汙君不仕，志氣軒軒。", "復我汶上，出處休焉。"]'),
('d5f43c0f-caca-4a58-8646-016249feb1b8','文宣王及其弟子贊  其四','宋高宗','宋','宋诗','song-poetry','','[]','懿德賢行，有一則尊。',40,'全唐诗/poet.song.116000.json','["懿德賢行，有一則尊。", "子也履之，成性存存。", "騂角有用，犁牛莫論。", "刑政之言，惠施元元。"]'),
('82ef4911-fa58-409c-8ce4-3afe4e55a592','文宣王及其弟子贊  其五','宋高宗','宋','宋诗','song-poetry','','[]','德以充性，行以澡身。',40,'全唐诗/poet.song.116000.json','["德以充性，行以澡身。", "二事在躬，日躋而新。", "並驅賢科，得顔與隣。", "不幸斯疾，命也莫伸。"]'),
('c44c43ec-5c89-492f-9dcf-1dc2447daff7','文宣王及其弟子贊  其六','宋高宗','宋','宋诗','song-poetry','','[]','循良之要，在於有政。',40,'全唐诗/poet.song.116000.json','["循良之要，在於有政。", "可使爲宰，千室百乘。", "師門育材，治心扶性。", "退則進之，琢磨之柄。"]'),
('9406d08d-c1b1-4acc-9804-ae55f7971fe2','文宣王及其弟子贊  其七','宋高宗','宋','宋诗','song-poetry','','[]','道義正己，文學擅科。',40,'全唐诗/poet.song.116000.json','["道義正己，文學擅科。", "爲宰武城，聯以弦歌。", "割雞之試，牛刀謂何。", "前言戲爾，博約則多。"]'),
('dc8a8cf4-2eaa-45b8-a175-e3bd3d4a1fe8','文宣王及其弟子贊  其八','宋高宗','宋','宋诗','song-poetry','','[]','辯以飾詐，言以致文。',40,'全唐诗/poet.song.116000.json','["辯以飾詐，言以致文。", "苟弗執禮，宜奠釋紛。", "朽木糞牆，置不足言。", "言語之科，粗然有聞。"]'),
('0bb6d05b-6a08-445b-9b04-de7f803e7ce1','文宣王及其弟子贊  其九','宋高宗','宋','宋诗','song-poetry','','[]','升堂惟光，千乘惟權。',40,'全唐诗/poet.song.116000.json','["升堂惟光，千乘惟權。", "陵暴知非，委質可賢。", "折獄言簡，結纓禮全。", "惡言不耳，仲尼頼焉。"]'),
('9a7a4cbb-ac78-433a-a024-3213249829f5','文宣王及其弟子贊  其一○','宋高宗','宋','宋诗','song-poetry','','[]','謙德知二，器實瑚璉。',40,'全唐诗/poet.song.116000.json','["謙德知二，器實瑚璉。", "動必幾先，孰並其辯。", "一使存魯，五國有變。", "終相其主，譽處悠遠。"]'),
('c2ef7e92-fa3f-452b-a072-133d0c64bf2b','文宣王及其弟子贊  其一一','宋高宗','宋','宋诗','song-poetry','','[]','文學之目，名重一時。',40,'全唐诗/poet.song.116000.json','["文學之目，名重一時。", "爲君子儒，作魏侯師。", "不可後禮，始可言詩。", "假蓋小嫌，聖亦不疵。"]'),
('84a76d9a-3482-45d7-9e15-3fd06cae9ddc','文宣王及其弟子贊  其一二','宋高宗','宋','宋诗','song-poetry','','["\u6cf0\u5c71"]','禮之有本，子能啟問。',40,'全唐诗/poet.song.116000.json','["禮之有本，子能啟問。", "大哉斯言，光昭明訓。", "德輝泰山，誣祭莫奮。", "崇茲祀典，盍永令聞。"]'),
('c15e3578-45d9-4e7a-9f14-d8b11a519aac','文宣王及其弟子贊  其一三','宋高宗','宋','宋诗','song-poetry','','[]','養才以道，聖人兼濟。',40,'全唐诗/poet.song.116000.json','["養才以道，聖人兼濟。", "始謂不仁，問鮑良喜。", "寓志農圃，似睽仁義。", "學稼之辭，豈姑捨是。"]'),
('41504ac4-d29c-4c88-a7ed-7d928843f554','文宣王及其弟子贊  其一四','宋高宗','宋','宋诗','song-poetry','','[]','惟子有道，天與異容。',40,'全唐诗/poet.song.116000.json','["惟子有道，天與異容。", "狀雖云惡，德則其豐。", "南止江沱，學者雲從。", "取士自茲，貌或非公。"]'),
('91738a61-665c-4768-bc56-a0eedbe2d2ff','文宣王及其弟子贊  其一五','宋高宗','宋','宋诗','song-poetry','','[]','夫孝要道，周訓群生。',40,'全唐诗/poet.song.116000.json','["夫孝要道，周訓群生。", "以綱百行，以通神明。", "因子侍師，答問成經。", "事親之實，代爲儀刑。"]'),
('1a0b6881-dac8-4b34-9554-3a7215fdebbe','文宣王及其弟子贊  其一六','宋高宗','宋','宋诗','song-poetry','','[]','子長宏度，高出倫輩。',40,'全唐诗/poet.song.116000.json','["子長宏度，高出倫輩。", "雖在縲紲，知非其罪。", "純德備行，夫子所采。", "以子妻之，尤知英概。"]'),
('54ea69d3-5066-4c6f-9dfd-5ecc81a607d9','文宣王及其弟子贊  其一七','宋高宗','宋','宋诗','song-poetry','','[]','猗爾子上，魯邦之望。',40,'全唐诗/poet.song.116000.json','["猗爾子上，魯邦之望。", "以德則貴，惟道是唱。", "師聰師明，友直友諒。", "伯於祝阿，儒風斯暢。"]'),
('e1720833-d760-4d18-90a3-2d6b069c1215','文宣王及其弟子贊  其一八','宋高宗','宋','宋诗','song-poetry','','[]','軾彼窮閻，達士所賓。',40,'全唐诗/poet.song.116000.json','["軾彼窮閻，達士所賓。", "邦無道穀，進退孰倫。", "敝衣非病，無財乃貧。", "賜雖不懌，清節照人。"]'),
('1f3a073e-14db-4157-a682-551d2a8b24c9','文宣王及其弟子贊  其一九','宋高宗','宋','宋诗','song-poetry','','[]','人稟秀德，氣貌或同。',40,'全唐诗/poet.song.116000.json','["人稟秀德，氣貌或同。", "而子儼然，溫溫其容。", "兩端發問，未答機鋒。", "以禮節和，斯言可宗。"]'),
('58839971-116c-4c43-bb9c-16d3b1229a9d','文宣王及其弟子贊  其二○','宋高宗','宋','宋诗','song-poetry','','[]','伯夫滎陽，實惟令德。',40,'全唐诗/poet.song.116000.json','["伯夫滎陽，實惟令德。", "優入聖門，過不留跡。", "道以目傳，妙則心識。", "倚歟偉歟，後代之則。"]'),
('b3666275-d99f-4bff-80a7-c162e4d08bc1','文宣王及其弟子贊  其二一','宋高宗','宋','宋诗','song-poetry','','[]','邈矣子季，睢陽是伯。',40,'全唐诗/poet.song.116000.json','["邈矣子季，睢陽是伯。", "屏息受業，延教登席。", "未踐四科，困涉六籍。", "祀典載之，好是正直。"]'),
('dfc974f2-b47a-4710-a3d6-6d7736044788','文宣王及其弟子贊  其二二','宋高宗','宋','宋诗','song-poetry','','[]','樂善哲士，伯于汧陽。',40,'全唐诗/poet.song.116000.json','["樂善哲士，伯于汧陽。", "傳道克正，垂名久臧。", "執德以洪，用心必剛。", "袤廣業履，式贊素王。"]'),
('c3183438-ffc1-405d-87b7-19054d60cdb0','文宣王及其弟子贊  其二三','宋高宗','宋','宋诗','song-poetry','','[]','惟時義方，有子誠孝。',40,'全唐诗/poet.song.116000.json','["惟時義方，有子誠孝。", "怡怡聖域，俱膺是道。", "暮春舞雩，詠歌至教。", "師故與之，和悅宜召。"]'),
('022f41fd-dc4f-4936-b64f-d4ee02054c0a','文宣王及其弟子贊  其二四','宋高宗','宋','宋诗','song-poetry','','[]','天清日明，密雨曷有。',40,'全唐诗/poet.song.116000.json','["天清日明，密雨曷有。", "師命持蓋，子亦善扣。", "惟夫子博，三才允究。", "學者之樂，所得遂茂。"]'),
('07b93a2c-b4cc-4306-a6c3-402aeff63e9d','文宣王及其弟子贊  其二五','宋高宗','宋','宋诗','song-poetry','','[]','周衰僞隆，政在群公。',40,'全唐诗/poet.song.116000.json','["周衰僞隆，政在群公。", "廉恥道微，家臣聿崇。", "不爲屈節，撝默自容。", "子於是時，凜然清風。"]'),
('102703bb-7bbf-4931-9f10-bbd8babf8233','文宣王及其弟子贊  其二六','宋高宗','宋','宋诗','song-poetry','','[]','遐想子期，挾策聖帷。',40,'全唐诗/poet.song.116000.json','["遐想子期，挾策聖帷。", "涉道是嗜，惟士可縻。", "在德既賢，在名廼垂。", "洋洋之風，逮今四馳。"]'),
('89a5a2ed-a920-4f47-a664-6da777bee0e1','文宣王及其弟子贊  其二七','宋高宗','宋','宋诗','song-poetry','','[]','念昔顓孫，商德與隣。',40,'全唐诗/poet.song.116000.json','["念昔顓孫，商德與隣。", "學以干祿，問以書紳。", "參前倚衡，忠信是遵。", "色取行違，作戒後人。"]'),
('ce8b84f9-c39d-4faf-9918-9a1715fc8faa','文宣王及其弟子贊  其二八','宋高宗','宋','宋诗','song-poetry','','[]','婉彼子羔，受業先聖。',40,'全唐诗/poet.song.116000.json','["婉彼子羔，受業先聖。", "宗廟之問，一出乎正。", "克篤於孝，非愚乃令。", "師知其生，有輝賢行。"]'),
('e1212bf2-0743-4705-8ece-59d23030a1db','文宣王及其弟子贊  其二九','宋高宗','宋','宋诗','song-poetry','','[]','伯茲雩婁，務學實著。',40,'全唐诗/poet.song.116000.json','["伯茲雩婁，務學實著。", "三千之位，七十是預。", "匪善莫行，惟德乃據。", "紀干前書，式彰厥譽。"]'),
('7d93f80c-87ee-4932-a64b-297c87b9c2ee','文宣王及其弟子贊  其三○','宋高宗','宋','宋诗','song-poetry','','[]','秦有子南，蜚聲述作。',40,'全唐诗/poet.song.116000.json','["秦有子南，蜚聲述作。", "守道之淵，成德之博。", "範若鑄金，契猶發藥。", "歷世明祀，少梁寵爵。"]'),
('f0ea0ee2-befb-4cd1-8b29-4a76ad742517','文宣王及其弟子贊  其三一','宋高宗','宋','宋诗','song-poetry','','[]','惟禽之問，從容其鯉。',40,'全唐诗/poet.song.116000.json','["惟禽之問，從容其鯉。", "求以異聞，詩禮云爾。", "請一得三，誠退而喜。", "且知將聖，不私其子。"]'),
('c0735b7d-b368-4eeb-a4d5-8f835c7a36d4','文宣王及其弟子贊  其三二','宋高宗','宋','宋诗','song-poetry','','[]','室家壯年，無子則逐。',40,'全唐诗/poet.song.116000.json','["室家壯年，無子則逐。", "見於信史，全齊之俗。", "原本厥初，師言可復。", "以學則知，揆之宜篤。"]'),
('6325d9f8-8c69-49c4-9948-929eb8d92377','文宣王及其弟子贊  其三三','宋高宗','宋','宋诗','song-poetry','','[]','紀伯子魯，聖學是務。',40,'全唐诗/poet.song.116000.json','["紀伯子魯，聖學是務。", "厲己斯的，好問乃裕。", "周旋中規，容止可度。", "允矣昔賢，後世所慕。"]'),
('f1debb23-5b95-44c4-89d0-f91b13c7720e','文宣王及其弟子贊  其三四','宋高宗','宋','宋诗','song-poetry','','[]','賢行顔叔，親承尼父。',40,'全唐诗/poet.song.116000.json','["賢行顔叔，親承尼父。", "志銳所期，道尊是輔。", "泥在鈞陶，木就規矩。", "終縻好爵，揚名東武。"]'),
('f6825310-c47f-4157-89ed-62f8d5a718d9','文宣王及其弟子贊  其三五','宋高宗','宋','宋诗','song-poetry','','[]','在昔石邑，能知所尊。',40,'全唐诗/poet.song.116000.json','["在昔石邑，能知所尊。", "懋依有德，克述無言。", "鼓篋槐市，揚名里門。", "此道久視，彼美長存。"]'),
('31faa2ba-e8fa-4cd6-8e06-138c41e61055','文宣王及其弟子贊  其三六','宋高宗','宋','宋诗','song-poetry','','[]','琅邪之伯，其惟子驕。',40,'全唐诗/poet.song.116000.json','["琅邪之伯，其惟子驕。", "微言既彰，德音孔昭。", "已觀雩舞，同聽齊韶。", "歷千百禩，跂想高標。"]'),
('828fa21e-a447-42fd-ba77-bc3c81a5aae0','文宣王及其弟子贊  其三七','宋高宗','宋','宋诗','song-poetry','','[]','彼美邽子，先聖是承。',40,'全唐诗/poet.song.116000.json','["彼美邽子，先聖是承。", "牆仞已及，堂陛將升。", "良玉斯琢，寒水必氷。", "錫壤平陸，茂實騫騰。"]'),
('44948692-8361-4f9e-bf81-6ad0edb55532','文宣王及其弟子贊  其三八','宋高宗','宋','宋诗','song-poetry','','[]','任城建伯，其表曰選。',40,'全唐诗/poet.song.116000.json','["任城建伯，其表曰選。", "淑問雅馳，才華清遠。", "競辰力行，愛日黽勉。", "孔教崇崇，令緒顯顯。"]'),
('f7f0ab3e-186a-4ea4-a6b1-af16e82af3db','文宣王及其弟子贊  其三九','宋高宗','宋','宋诗','song-poetry','','[]','人誰無子，爾嗣標奇。',40,'全唐诗/poet.song.116000.json','["人誰無子，爾嗣標奇。", "行爲世範，學爲人師。", "請車誠非，顧匪其私。", "千載之下，足以示慈。"]'),
('37455358-fdbe-4d5e-ba02-44785b8c8677','文宣王及其弟子贊  其四○','宋高宗','宋','宋诗','song-poetry','','[]','肅肅曹伯，王室之裔。',40,'全唐诗/poet.song.116000.json','["肅肅曹伯，王室之裔。", "積習樂道，切瑳明義。", "惟善則主，爾德是類。", "史筆有煥，令名永紀。"]'),
('1a401b20-ad28-44c2-b798-2a7750d27cea','文宣王及其弟子贊  其四一','宋高宗','宋','宋诗','song-poetry','','[]','至聖立教，子祺安雅。',40,'全唐诗/poet.song.116000.json','["至聖立教，子祺安雅。", "擅譽魯邦，啟祚鉅野。", "煒矣風猷，時哉用捨。", "出倫離類，後學是假。"]'),
('0e4bd985-7da1-4594-bd91-34762da2da8e','文宣王及其弟子贊  其四二','宋高宗','宋','宋诗','song-poetry','','[]','褒錫朱虛，在器輪輿。',40,'全唐诗/poet.song.116000.json','["褒錫朱虛，在器輪輿。", "儒室振領，聖門曳裾。", "賢業得藴，美材以攄。", "百世不刊，載觀成書。"]'),
('a2010541-d2cc-4443-80aa-d5a4d0148492','文宣王及其弟子贊  其四三','宋高宗','宋','宋诗','song-poetry','','[]','惟子挺生，道德之門。',40,'全唐诗/poet.song.116000.json','["惟子挺生，道德之門。", "佩服至論，鯉則弟昆。", "三得三亡，所問殊溫。", "君子歸宓，義不掩恩。"]'),
('80ac9cf2-a9b9-43b0-8454-0cd4f8e73361','文宣王及其弟子贊  其四四','宋高宗','宋','宋诗','song-poetry','','[]','仰止狄皙，抱負淵通。',40,'全唐诗/poet.song.116000.json','["仰止狄皙，抱負淵通。", "游泳德化，揚厲素風。", "偉識既異，持教乃隆。", "厥志茂焉，毖祀無窮。"]'),
('3a642dbe-7f8d-4353-9c0b-6c5d4e6308eb','文宣王及其弟子贊  其四五','宋高宗','宋','宋诗','song-poetry','','[]','子斂受封，爰居武城。',40,'全唐诗/poet.song.116000.json','["子斂受封，爰居武城。", "亹亹其聞，翩翩其英。", "摳衣時習，願學日明。", "誕敷孔教，爵里疏榮。"]'),
('c31e0f59-a64b-48f8-9af0-706a293ec3a2','文宣王及其弟子贊  其四六','宋高宗','宋','宋诗','song-poetry','','[]','剛毅近仁，志操莫渝。',40,'全唐诗/poet.song.116000.json','["剛毅近仁，志操莫渝。", "性匪祝鮀，面豈子都。", "有一於此，剛名可圖。", "云慾則柔，蓋生之徒。"]'),
('97e77ca5-7e57-443a-9d71-6087f0a4c613','文宣王及其弟子贊  其四七','宋高宗','宋','宋诗','song-poetry','','[]','式是壤伯，昭乎聖徒。',40,'全唐诗/poet.song.116000.json','["式是壤伯，昭乎聖徒。", "執經請益，載道若無。", "詩書規矩，學問楷模。", "得時而駕，領袖諸儒。"]'),
('a2dcdc4a-0440-45ca-abf3-79582783eb5c','文宣王及其弟子贊  其四八','宋高宗','宋','宋诗','song-poetry','','[]','開國乘氏，有德斯彰。',40,'全唐诗/poet.song.116000.json','["開國乘氏，有德斯彰。", "叅稽百行，贊理三綱。", "自拔行閒，榮名甚光。", "在史藹藹，歷久彌芳。"]'),
('cef2aa58-455f-475c-98ba-f5dc5d875620','文宣王及其弟子贊  其四九','宋高宗','宋','宋诗','song-poetry','','[]','惟彼子之，錫伯期思。',40,'全唐诗/poet.song.116000.json','["惟彼子之，錫伯期思。", "與賢並進，得聖而師。", "彬彬雅道，翼翼令儀。", "上目至言，廟食不隳。"]'),
('c2f97031-483a-4965-8ea3-1ce3447c15ca','文宣王及其弟子贊  其五○','宋高宗','宋','宋诗','song-poetry','','[]','有懷子折，全魯之彥。',40,'全唐诗/poet.song.116000.json','["有懷子折，全魯之彥。", "儒行既名，聊伯乃建。", "兢兢受道，奕奕峩弁。", "懿選嘉訪，世享馨薦。"]'),
('01b888ba-8c74-4a75-9e68-714140eee97a','文宣王及其弟子贊  其五一','宋高宗','宋','宋诗','song-poetry','','[]','先覺既位，簪履並馳。',40,'全唐诗/poet.song.116000.json','["先覺既位，簪履並馳。", "尚德君子，爾乃兼之。", "羿奡可慚，禹稷可師。", "三復此道，載觀白圭。"]'),
('f2a28977-c7f3-44fd-9fd1-6ec823828dec','文宣王及其弟子贊  其五二','宋高宗','宋','宋诗','song-poetry','','[]','黄伯著祀，公孫是云。',40,'全唐诗/poet.song.116000.json','["黄伯著祀，公孫是云。", "彌縫中道，協輔斯文。", "藏修方異，漸漬其勤。", "史詞不忘，播爲清芬。"]'),
('a1b3033f-3da4-4a17-9f3a-da65d44e2ae0','文宣王及其弟子贊  其五三','宋高宗','宋','宋诗','song-poetry','','[]','兄弟之邦，士有廉庸。',40,'全唐诗/poet.song.116000.json','["兄弟之邦，士有廉庸。", "涵泳素教，表揭儒宗。", "杏壇探賾，洙泗從容。", "作興一時，莒父其封。"]'),
('717bde34-f377-4b52-b6c5-2dcd8b3e08f0','文宣王及其弟子贊  其五四','宋高宗','宋','宋诗','song-poetry','','[]','瑕丘祚邑，子期是爲。',40,'全唐诗/poet.song.116000.json','["瑕丘祚邑，子期是爲。", "親訓有日，廣業于時。", "四教允隆，五常以持。", "比肩俊傑，聞望斯垂。"]'),
('d395b2ad-f021-4c5c-8ef1-947bdc1f2af1','文宣王及其弟子贊  其五五','宋高宗','宋','宋诗','song-poetry','','[]','易之爲書，彌合天地。',40,'全唐诗/poet.song.116000.json','["易之爲書，彌合天地。", "五十乃學，師則有是。", "子能受授，洗心傳世。", "知機其神，宜被厥祀。"]'),
('0262f841-dd66-4ad8-b517-93d7ad83220e','文宣王及其弟子贊  其五六','宋高宗','宋','宋诗','song-poetry','','[]','手足甚親，志異出處。',40,'全唐诗/poet.song.116000.json','["手足甚親，志異出處。", "魋將爲亂，子廼脫去。", "在污能絜，危而有慮。", "內省若斯，何憂何懼。"]'),
('e14d2b84-b853-49cc-aadf-ac17aca52e4b','文宣王及其弟子贊  其五七','宋高宗','宋','宋诗','song-poetry','','[]','有衛伯玉，夫子與居。',40,'全唐诗/poet.song.116000.json','["有衛伯玉，夫子與居。", "寡過未能，薦贊使乎。", "以屍諫君，友則史魚。", "果得進賢，爛然簡書。"]'),
('9fae89fe-9509-4939-9b9f-6556d07640a0','文宣王及其弟子贊  其五八','宋高宗','宋','宋诗','song-poetry','','[]','學者行道，敝縕亦稱。',40,'全唐诗/poet.song.116000.json','["學者行道，敝縕亦稱。", "使齊光華，偶爲肥輕。", "周急之言，君子所令。", "答問允嚴，理皆先經。"]'),
('4d977a1a-fc56-4e64-b2f1-b053c5f4f921','文宣王及其弟子贊  其五九','宋高宗','宋','宋诗','song-poetry','','[]','人有賢否，道有廢興。',40,'全唐诗/poet.song.116000.json','["人有賢否，道有廢興。", "子如命何，營營震驚。", "季孫雖惑，景伯莫平。", "師資一言，秩祀亦懲。"]'),
('3c5baf9c-f3e7-4444-af31-456a1d9f58b2','文宣王及其弟子贊  其六○','宋高宗','宋','宋诗','song-poetry','','[]','仕進之道，要在究習。',40,'全唐诗/poet.song.116000.json','["仕進之道，要在究習。", "具臣而居，咎欲誰執。", "斯未能信，謙以有立。", "闕里說之，多士莫及。"]'),
('1d45abe1-58b4-44b3-a94f-5193d2e85832','文宣王及其弟子贊  其六一','宋高宗','宋','宋诗','song-poetry','','[]','君子若人，單父之政。',40,'全唐诗/poet.song.116000.json','["君子若人，單父之政。", "引肘寤君，放魚稟令。", "傅郭勿穫，遂能制命。", "百代理邑，用規觀聽。"]'),
('b2dc2d8c-acc1-44d9-99b9-480e04908c25','文宣王及其弟子贊  其六二','宋高宗','宋','宋诗','song-poetry','','[]','師席高振，大成是集。',40,'全唐诗/poet.song.116000.json','["師席高振，大成是集。", "至道克傳，賢達斯執。", "善道云袤，儒風可立。", "漁陽之士，得跂而及。"]'),
('04a41337-2a88-43e1-bf51-aaae2c2fac53','文宣王及其弟子贊  其六三','宋高宗','宋','宋诗','song-poetry','','[]','侁侁申周，四科與儔。',40,'全唐诗/poet.song.116000.json','["侁侁申周，四科與儔。", "逸駕文圃，鼓枻儒流。", "冠珮既燕，言動允休。", "邵陵得封，可想清修。"]'),
('a62127bd-8753-417f-9003-be8b47e8c278','文宣王及其弟子贊  其六四','宋高宗','宋','宋诗','song-poetry','','[]','多能鄙事，聖人曲意。',40,'全唐诗/poet.song.116000.json','["多能鄙事，聖人曲意。", "惟其知之，是以不試。", "宗魯雖友，弔必以義。", "尚師嘉言，祀亦罔替。"]'),
('9a6a4825-4cd8-4ad7-a6d6-ac2e0e2e17c3','文宣王及其弟子贊  其六五','宋高宗','宋','宋诗','song-poetry','','[]','孔父秦父，相尚以力。',40,'全唐诗/poet.song.116000.json','["孔父秦父，相尚以力。", "俱生賢嗣，相與以德。", "是父是子，致詰疇克。", "會弁儒林，令名無極。"]'),
('6c2d8c5e-d58c-4f03-9822-e0957ed03e88','文宣王及其弟子贊  其六六','宋高宗','宋','宋诗','song-poetry','','[]','勉勉子車，封邑淳于。',40,'全唐诗/poet.song.116000.json','["勉勉子車，封邑淳于。", "親炙避席，唯諾趨隅。", "發微既博，雅道是扶。", "抑可尚也，不亦美乎。"]'),
('4e429298-17cd-4fda-a094-9e8f031b1b6d','文宣王及其弟子贊  其六七','宋高宗','宋','宋诗','song-poetry','','[]','孰封于蕭，實惟子柳。',40,'全唐诗/poet.song.116000.json','["孰封于蕭，實惟子柳。", "夙飫格言，克遵善誘。", "明德斯馨，賢業所就。", "以侑於儒，傳芳逾茂。"]'),
('f8e4d826-0fe1-4eab-9bb8-a23044849aca','文宣王及其弟子贊  其六八','宋高宗','宋','宋诗','song-poetry','','[]','雍容子皙，已望堂室。',40,'全唐诗/poet.song.116000.json','["雍容子皙，已望堂室。", "幼則有造，成則祖述。", "文采日化，儒效力弼。", "永觀厥成，德音秩秩。"]'),
('02263fa5-e123-488d-821a-b2499c42ba89','文宣王及其弟子贊  其六九','宋高宗','宋','宋诗','song-poetry','','[]','東平子産，性著盛時。',40,'全唐诗/poet.song.116000.json','["東平子産，性著盛時。", "奉師於塾，講道之微。", "答問其敏，婉妙以思。", "升降陛廉，尚想英姿。"]'),
('abb0917e-6ae1-4c2c-b8f9-178290fd169b','文宣王及其弟子贊  其七○','宋高宗','宋','宋诗','song-poetry','','[]','溫溫子里，入聞至聖。',40,'全唐诗/poet.song.116000.json','["溫溫子里，入聞至聖。", "攬道之華，秉德之柄。", "深造閫域，不乖言行。", "全齊之封，竹素爲盛。"]'),
('b58731b2-59a0-42e6-952b-39a37a612b6d','文宣王及其弟子贊  其七一','宋高宗','宋','宋诗','song-poetry','','[]','伯彼臨淄，左行稱賢。',40,'全唐诗/poet.song.116000.json','["伯彼臨淄，左行稱賢。", "睎蹤十哲，秀穎三千。", "心悅誠服，家至戶傳。", "樂只君子，文聲益宣。"]'),
('1c837775-f4ca-4301-b950-b847720ee7ec','文宣王及其弟子贊  其七二','宋高宗','宋','宋诗','song-poetry','','[]','彭衙高士，經籍是親。',40,'全唐诗/poet.song.116000.json','["彭衙高士，經籍是親。", "贊成德藝，協於彜倫。", "厎績聖道，斯肖素臣。", "優哉游哉，學以致身。"]'),
('c95f9c68-9a48-478b-9f7c-017fb9fd4075','文宣王及其弟子贊  其七三','宋高宗','宋','宋诗','song-poetry','','[]','樂氏子聲，錫爵昌平。',40,'全唐诗/poet.song.116000.json','["樂氏子聲，錫爵昌平。", "信道之萬，見善乃明。", "引領高節，載惟思誠。", "先賢聿集，出爲時英。"]'),
('46fd52e0-ef0e-4ee5-9d21-d155316f5dc8','賜樞密院樓炤','宋高宗','宋','宋诗','song-poetry','','[]','朕念邦家歷萬几，幸卿相與久維持。',64,'全唐诗/poet.song.116000.json','["朕念邦家歷萬几，幸卿相與久維持。", "孜孜廣道諏詢處，蹇蹇封章納誨時。", "半世奇勳惟我重，一生忠節自天知。", "南歸奚事將爲贈，金石詩篇壯羽儀。"]'),
('b3e0d917-510f-41b7-8a46-afaa3b8859d4','句  其一','宋高宗','宋','宋诗','song-poetry','','[]','天末歸帆何處宿，釣船獨在蓼花傍。',16,'全唐诗/poet.song.116000.json','["天末歸帆何處宿，釣船獨在蓼花傍。"]'),
('11c17752-e8cb-4718-9547-35dfba0bc863','句  其二','宋高宗','宋','宋诗','song-poetry','','[]','秋江煙暝泊孤舟。',8,'全唐诗/poet.song.116000.json','["秋江煙暝泊孤舟。"]'),
('b7a0746b-f777-42c5-8ec8-cab42da60b08','句  其三','宋高宗','宋','宋诗','song-poetry','','[]','有美三宮德，無嫌並后心。',12,'全唐诗/poet.song.116000.json','["有美三宮德，無嫌並后心。"]'),
('ece94f5a-156f-4f44-b9ba-d8c6991fe05f','句  其四','宋高宗','宋','宋诗','song-poetry','','[]','趁此一軒風月好，橘香酒熟待君來。',16,'全唐诗/poet.song.116000.json','["趁此一軒風月好，橘香酒熟待君來。"]'),
('485683be-227c-4e7c-a05a-29cf0d3c727f','句  其五','宋高宗','宋','宋诗','song-poetry','','[]','氣迴俎豆群工泰，喜入貔貅萬馬秋。',16,'全唐诗/poet.song.116000.json','["氣迴俎豆群工泰，喜入貔貅萬馬秋。"]'),
('e081bdc2-c4be-4512-9660-ae6db17176bf','句  其六','宋高宗','宋','宋诗','song-poetry','','[]','白雲斷處斜陽轉，幾曲青山獻畫屏。',16,'全唐诗/poet.song.116000.json','["白雲斷處斜陽轉，幾曲青山獻畫屏。"]'),
('ac45aaa1-468b-49aa-a188-11b8e375c201','句  其七','宋高宗','宋','宋诗','song-poetry','','[]','池上疎烟籠翡翠，水邊遲日戲蜻蜓。',16,'全唐诗/poet.song.116000.json','["池上疎烟籠翡翠，水邊遲日戲蜻蜓。"]'),
