('f401f3ed-d739-4941-a72f-be24ef7ebc86','句','趙植','宋','宋诗','song-poetry','','[]','芳草連雲暮色深。',8,'全唐诗/poet.song.116000.json','["芳草連雲暮色深。"]'),
('cf7f3f0b-1b25-4863-90d4-62de4826e95d','題家信後','高選','宋','宋诗','song-poetry','','[]','十載慇懃訓子情，禮闈今幸占微名。',64,'全唐诗/poet.song.116000.json','["十載慇懃訓子情，禮闈今幸占微名。", "彤庭策獻三千字，鵬海風摶九萬程。", "帽插宮花瓊宴罷，身沾仙露賜衣榮。", "瞻雲北闕人迢遞，空憶高堂雪鬢生。"]'),
('276ebed9-2cb6-42c3-b4a2-c244f550d7c3','瑞安縣詠懷','高選','宋','宋诗','song-poetry','','[]','一經逢聖世，銜詔下神州。',48,'全唐诗/poet.song.116000.json','["一經逢聖世，銜詔下神州。", "才陋慚無補，官卑得自由。", "刑威存撫字，賦役敢誅求。", "何日乘公暇，溪山策騎遊。"]'),
('93adedd6-a7e6-4768-966c-706e8d5ca72f','太息','高選','宋','宋诗','song-poetry','','[]','天運逢南度，和成勢已移。',48,'全唐诗/poet.song.116000.json','["天運逢南度，和成勢已移。", "山河憐破碎，草木亦傷悲。", "鐵騎馳中土，烽塵隘北陲。", "哀臣雙淚眼，豈畏朔風吹。"]'),
('594349f6-6d19-4dd9-9109-5a8f51575e69','吉祥寺','韓元傑','宋','宋诗','song-poetry','','[]','黄塵久厭市朝夢，青蒻已孤鷗鷺盟。',32,'全唐诗/poet.song.116000.json','["黄塵久厭市朝夢，青蒻已孤鷗鷺盟。", "誰解携琴來此宿，夜深隨意寫江聲。"]'),
('3c26d939-1c94-49a6-a6a7-4504ee56c415','程倅春行','汪若容','宋','宋诗','song-poetry','','[]','綠楊芳草正留連，急雨催詩濕錦韉。',32,'全唐诗/poet.song.116000.json','["綠楊芳草正留連，急雨催詩濕錦韉。", "野老不知行樂意，背人無語自耕田。"]'),
('e6b0be41-9d35-4aa7-9bee-e1790d25789e','登巾子山有懷舊遊','王衜','宋','宋诗','song-poetry','','[]','路轉岧嶤瞰古城，闌干曲處眼偏明。',64,'全唐诗/poet.song.116000.json','["路轉岧嶤瞰古城，闌干曲處眼偏明。", "嵐光不與江流斷，凉意還從竹外生。", "好事樽罍初不減，舊題歲月已堪驚。", "會須更待天邊月，醉看浮圖波面橫。"]'),
('e1ae912a-2d04-4179-a84a-aab33875082b','題天台明巖','王衜','宋','宋诗','song-poetry','','[]','自古懸崖深蔽日，此心圓鏡本無塵。',32,'全唐诗/poet.song.116000.json','["自古懸崖深蔽日，此心圓鏡本無塵。", "會知明暗非關石，便是巖中得道人。"]'),
('c73a32bb-61e0-419f-a88d-077af1c2eac3','偈頌七首  其一','釋師一','宋','宋诗','song-poetry','','[]','魔作佛，壞爛虛空元有骨。',40,'全唐诗/poet.song.116000.json','["魔作佛，壞爛虛空元有骨。", "佛作魔，須彌頂上湧清波。", "魔佛二邊俱坐却，瘥病不假馿駝藥。"]'),
('2021dcbc-1412-4aa5-a2f3-247f1ac1d95c','偈頌七首  其二','釋師一','宋','宋诗','song-poetry','','[]','喜與水雲會，甘與水雲同。',24,'全唐诗/poet.song.116000.json','["喜與水雲會，甘與水雲同。", "雲屯水聚處，塞破太虛空。"]'),
('f31b0faf-c705-4a8a-9489-fe57f519205e','偈頌七首  其三','釋師一','宋','宋诗','song-poetry','','[]','破暑黄梅雨，清神白乳茶。',24,'全唐诗/poet.song.116000.json','["破暑黄梅雨，清神白乳茶。", "萬緣俱不到，物外野僧家。"]'),
('fb1cee75-eb75-417a-961d-eb87915b864c','偈頌七首  其四','釋師一','宋','宋诗','song-poetry','','[]','相逢握手不論心，心性吾儕眼裏金。',64,'全唐诗/poet.song.116000.json','["相逢握手不論心，心性吾儕眼裏金。", "三箇柴頭煨品字，與君閒話古叢林。", "柴頭煨盡已更闌，樓上鐘聲落月寒。", "一把柳絲取不得，和煙搭在玉欄干。"]'),
('8e2f6270-c39f-4bf1-af0a-1d57d5a4fcb5','偈頌七首  其五','釋師一','宋','宋诗','song-poetry','','[]','凍雲欲雪未雪，普賢象駕崢嶸。',28,'全唐诗/poet.song.116000.json','["凍雲欲雪未雪，普賢象駕崢嶸。", "嶺梅半合半開，少室風光漏泄。"]'),
('49cba081-af21-444d-93d9-17d17227fd40','偈頌七首  其六','釋師一','宋','宋诗','song-poetry','','[]','萬年藤上一枝春，用祝光堯萬乘君。',32,'全唐诗/poet.song.116000.json','["萬年藤上一枝春，用祝光堯萬乘君。", "身固壽康長不老，大平時代自由身。"]'),
('dd466375-74c4-40de-89ea-838666c9283a','偈頌七首  其七','釋師一','宋','宋诗','song-poetry','','[]','燕去梁閒靜，鴻來眼界寬。',24,'全唐诗/poet.song.116000.json','["燕去梁閒靜，鴻來眼界寬。", "遶庭何所有，風撼竹珊珊。"]'),
('5b787341-45de-4876-9e48-964c2cbba1cc','頌古八首  其一','釋師一','宋','宋诗','song-poetry','','[]','趙老家風不熱瞞，問他大道答長安。',32,'全唐诗/poet.song.116000.json','["趙老家風不熱瞞，問他大道答長安。", "有誰平步歸家去，多是區區自作難。"]'),
('96338fdb-7b49-429a-aef9-481b7d4504bc','頌古八首  其二','釋師一','宋','宋诗','song-poetry','','[]','一拶銀山鐵壁摧，大悲院裏趕村齊。',32,'全唐诗/poet.song.116000.json','["一拶銀山鐵壁摧，大悲院裏趕村齊。", "善財拄杖如無用，乞與佯狂老萬回。"]'),
('767ba349-3e6c-4956-9d94-9d3ec2b85fbe','頌古八首  其三','釋師一','宋','宋诗','song-poetry','','[]','藏身無跡更無藏，脫體無依便廝當。',32,'全唐诗/poet.song.116000.json','["藏身無跡更無藏，脫體無依便廝當。", "古鏡不勞還自照，淡煙和露濕秋光。"]'),
('c6530abe-4fe6-4228-ba2e-17d339a45324','頌古八首  其四','釋師一','宋','宋诗','song-poetry','','[]','三喚須知意不輕，平生肝膽一時傾。',32,'全唐诗/poet.song.116000.json','["三喚須知意不輕，平生肝膽一時傾。", "負吾負汝還知否，縱有丹青畫不成。"]'),
('4da72646-8d18-4874-b9ea-045cc6e35ae4','頌古八首  其五','釋師一','宋','宋诗','song-poetry','','[]','不起一念須彌山，特立當頭著眼看。',32,'全唐诗/poet.song.116000.json','["不起一念須彌山，特立當頭著眼看。", "拈一縷絲輕絆倒，家家門底路長安。"]'),
('f3c7d417-4dce-4b43-b748-9e70c6734997','頌古八首  其六','釋師一','宋','宋诗','song-poetry','','[]','家山指出路非遥，萬仞嵯峨插碧霄。',32,'全唐诗/poet.song.116000.json','["家山指出路非遥，萬仞嵯峨插碧霄。", "一片白雲橫谷口，幾多歸鳥自迷巢。"]'),
('e696bb52-eee9-4e54-89c3-baeed022fcf4','頌古八首  其七','釋師一','宋','宋诗','song-poetry','','[]','巖頭婆子鐵肝心，擊碎乾坤覓賞音。',32,'全唐诗/poet.song.116000.json','["巖頭婆子鐵肝心，擊碎乾坤覓賞音。", "眨上眉毛如不薦，岳陽惡浪轉增深。"]'),
('0201ae1d-c1e7-460d-a557-edd67c25e0b4','頌古八首  其八','釋師一','宋','宋诗','song-poetry','','[]','十八佳人美態嬌，綉衣輕整暗香飄。',32,'全唐诗/poet.song.116000.json','["十八佳人美態嬌，綉衣輕整暗香飄。", "擡身花圃徐徐立，引得黄鶑下柳條。"]'),
('9a041507-f940-48f9-b271-6ece0b13b834','頌古','釋師一','宋','宋诗','song-poetry','','[]','超談胡餠應時機，遂塊知非師子兒。',32,'全唐诗/poet.song.116000.json','["超談胡餠應時機，遂塊知非師子兒。", "敗葉霜風都掃盡，古松方見歲寒枝。"]'),
('754dff18-c8ae-4e60-a232-2c865146ff45','頌古十八首  其一','釋師一','宋','宋诗','song-poetry','','[]','食訖跏趺坐石牀，斗間間氣燭天光。',32,'全唐诗/poet.song.116000.json','["食訖跏趺坐石牀，斗間間氣燭天光。", "幾多業識茫茫者，衲被蒙頭在醉鄉。"]'),
('34e75a76-58b3-4033-8453-db77d331d623','頌古十八首  其二','釋師一','宋','宋诗','song-poetry','','[]','渾身燥痒倩人搔，入骨搔來身已勞。',32,'全唐诗/poet.song.116000.json','["渾身燥痒倩人搔，入骨搔來身已勞。", "一下被伊搔著了，平生痒處一時消。"]'),
('d096196d-1de1-4cd1-b554-c3f7adbb7850','頌古十八首  其三','釋師一','宋','宋诗','song-poetry','','[]','約去栽松箇老人，還來傳法喜童真。',32,'全唐诗/poet.song.116000.json','["約去栽松箇老人，還來傳法喜童真。", "有娘生面無爺姓，劫外靈苗不犯春。"]'),
('63124f29-6e6b-4589-8eb0-0db1c2a811cf','頌古十八首  其四','釋師一','宋','宋诗','song-poetry','','[]','壁間書偈言無物，腰石當知力有餘。',32,'全唐诗/poet.song.116000.json','["壁間書偈言無物，腰石當知力有餘。", "莫道懶翁無伎倆，糠中舂出走盤珠。"]'),
('5aff105b-51e2-4f7e-ba08-4d7b05c990de','頌古十八首  其五','釋師一','宋','宋诗','song-poetry','','[]','不是風兮不是旛，碧天雲靜月團團。',32,'全唐诗/poet.song.116000.json','["不是風兮不是旛，碧天雲靜月團團。", "幾多乞巧癡男女，猶向牀頭甕裏看。"]'),
('516bdb21-6ffb-4a8a-a9ed-d275c3e60031','頌古十八首  其六','釋師一','宋','宋诗','song-poetry','','[]','不是旛兮不是風，軒轅寶鑑出懷中。',32,'全唐诗/poet.song.116000.json','["不是旛兮不是風，軒轅寶鑑出懷中。", "森羅萬象難逃影，戀窟狐狸失却蹤。"]'),
('241a7367-2228-4a2d-8d42-4f70a83073a0','頌古十八首  其七','釋師一','宋','宋诗','song-poetry','','[]','孰云意在钁頭邊，一擊圓通徹大千。',32,'全唐诗/poet.song.116000.json','["孰云意在钁頭邊，一擊圓通徹大千。", "大笑低頭歸去後，饑餐且莫與人傳。"]'),
('a5357b6b-0630-4897-aa7b-2cf341dad02d','頌古十八首  其八','釋師一','宋','宋诗','song-poetry','','[]','張弓架箭幾何年，接得三平機不全。',32,'全唐诗/poet.song.116000.json','["張弓架箭幾何年，接得三平機不全。", "若使當時能羿射，免教落節向弓弦。"]'),
('02064817-b88e-4eb5-9ebf-ad9025a9dc3f','頌古十八首  其九','釋師一','宋','宋诗','song-poetry','','[]','魯祖逢人面壁，老大慵懶追隨。',28,'全唐诗/poet.song.116000.json','["魯祖逢人面壁，老大慵懶追隨。", "後之參徒罔測，一向打瓦鑽龜。"]'),
('27a1eeaf-9f47-4ef6-839c-f0bbdf49e5aa','頌古十八首  其一○','釋師一','宋','宋诗','song-poetry','','[]','龐公孰謂問頭親，馬祖言猶泥齒唇。',32,'全唐诗/poet.song.116000.json','["龐公孰謂問頭親，馬祖言猶泥齒唇。", "吸盡西江禁不住，嶮崖句裏笑翻身。"]'),
('1889d185-89a9-4c6b-b6a1-d812168828c0','頌古十八首  其一一','釋師一','宋','宋诗','song-poetry','','[]','拶透機先子欲酬，迅雷楫下汗如流。',32,'全唐诗/poet.song.116000.json','["拶透機先子欲酬，迅雷楫下汗如流。", "踏翻船子水悠悠，直入千峯不轉頭。"]'),
('14a9f2bf-e59b-4743-842f-ba3cfd5c1a6a','頌古十八首  其一二','釋師一','宋','宋诗','song-poetry','','[]','曾扣西來問翠微，經行駐步大慈悲。',32,'全唐诗/poet.song.116000.json','["曾扣西來問翠微，經行駐步大慈悲。", "當時投子如能薦，惡水重將更潑誰。"]'),
('1aa00054-b16b-478b-afa3-e0ea6f576b12','頌古十八首  其一三','釋師一','宋','宋诗','song-poetry','','[]','一著機先用得親，可憐窮子眼無筋。',32,'全唐诗/poet.song.116000.json','["一著機先用得親，可憐窮子眼無筋。", "須知八法論書處，前箭猶輕後箭深。"]'),
('5b9dfa8c-22ca-4376-bac3-b862ac97c5b1','頌古十八首  其一四','釋師一','宋','宋诗','song-poetry','','[]','玉麟带角離霄漢，金鳳啣花下綵樓。',32,'全唐诗/poet.song.116000.json','["玉麟带角離霄漢，金鳳啣花下綵樓。", "野老不嫌公子醉，相將携手御街遊。"]'),
('01d606ed-a577-48e0-a9d7-7dde23dac5d4','頌古十八首  其一五','釋師一','宋','宋诗','song-poetry','','[]','野水舟橫芳草渡，人來舞棹或呈橈。',32,'全唐诗/poet.song.116000.json','["野水舟橫芳草渡，人來舞棹或呈橈。", "撈蝦摝蜆隨時過，却向何時得六鼇。"]'),
('d5e7a69e-ed0e-4276-88ea-5da10114e6f2','頌古十八首  其一六','釋師一','宋','宋诗','song-poetry','','[]','舉手攀南斗，移身倚北辰。',24,'全唐诗/poet.song.116000.json','["舉手攀南斗，移身倚北辰。", "出頭天外看，須是箇般人。"]'),
('ad40dd69-c923-454c-86af-fd4bb7cf90d8','頌古十八首  其一七','釋師一','宋','宋诗','song-poetry','','[]','掃地潑水相公來，聲高隘喝綉旗開。',32,'全唐诗/poet.song.116000.json','["掃地潑水相公來，聲高隘喝綉旗開。", "天上玉麟來瑞世，堪作人間將相才。"]'),
('b9c1f5e8-9d41-4063-a023-f894ffd81c7c','頌古十八首  其一八','釋師一','宋','宋诗','song-poetry','','[]','三人證龜成鱉，毗嵐一吹吹滅。',28,'全唐诗/poet.song.116000.json','["三人證龜成鱉，毗嵐一吹吹滅。", "從茲暗裏穿針，鼻孔七花八裂。"]'),
('eff3212e-482b-4bd1-9aca-dc31254aed82','頌古一首','釋師一','宋','宋诗','song-poetry','','[]','九夏安居不論心，胡蘆水上捺教沉。',31,'全唐诗/poet.song.116000.json','["九夏安居不論心，胡蘆水上捺教沉。", "忽湧向西邊出，驚起沙鷗亂白蘋。"]'),
('14a14ade-5cc1-4581-a2f3-69612108f460','詩一首','袁思永','宋','宋诗','song-poetry','','[]','萬疊雲山擁郡樓，憑欄下瞰卧龍湫。',32,'全唐诗/poet.song.116000.json','["萬疊雲山擁郡樓，憑欄下瞰卧龍湫。", "二年吏役何曾到，孤負清風月白秋。"]'),
('8e8c680e-a897-4738-8c9d-3759fa335920','句','彭奭','宋','宋诗','song-poetry','','[]','六龍極北瞻明主，三鳳河東愧腐儒。',16,'全唐诗/poet.song.116000.json','["六龍極北瞻明主，三鳳河東愧腐儒。"]'),
('8e6983ae-a24d-4338-a01c-750bdf695a0c','呈南堂靜禪師','莫將','宋','宋诗','song-poetry','','[]','從來姿韻愛風流，幾笑時人向外求。',32,'全唐诗/poet.song.116000.json','["從來姿韻愛風流，幾笑時人向外求。", "萬別千差無覓處，得來元在鼻尖頭。"]'),
('b8a49c88-59c1-4daa-94c0-bceb5a623a53','井田封建圖','陳子常','宋','宋诗','song-poetry','','[]','爲成者十復爲終，終十還爲百里同。',32,'全唐诗/poet.song.116000.json','["爲成者十復爲終，終十還爲百里同。", "祇爲諸儒泥方法，不知起數總皆縱。"]'),
('9ed69909-d5cd-4366-9be2-8fb7eb885415','題馬世功豁野堂','左璵','宋','宋诗','song-poetry','','[]','歡言赴幽期，作意理烟艇。',96,'全唐诗/poet.song.116000.json','["歡言赴幽期，作意理烟艇。", "曳纜松篁陰，未覺心地迥。", "捨舟登爽塏，微步水雲浄。", "扶輿登斯堂，遐眺方一騁。", "開軒納野色，秋思浩千頃。", "心隨片雲遠，目送孤鴻影。", "坐久襟宇寬，萬事詎容省。", "永願陪清游，棲身白鷗境。"]'),
('0ad7dab9-a491-4b74-9ed6-4ac81e9564b1','句','胡汾','宋','宋诗','song-poetry','','[]','輪中如有物，光外更無空。',12,'全唐诗/poet.song.116000.json','["輪中如有物，光外更無空。"]'),
('5d6dceff-88f7-43e0-ab2b-659fe786e168','贈李用之','种道人','宋','宋诗','song-poetry','','[]','道成元未是，再至却須成。',24,'全唐诗/poet.song.116000.json','["道成元未是，再至却須成。", "但看西行日，歸來一餉榮。"]'),
('12ae76b1-62be-4dbf-a7e6-d2592f30b48c','御苑採茶歌十首  其一','熊蕃','宋','宋诗','song-poetry','','[]','雲腴貢使手親調，旋放春天採玉條。',32,'全唐诗/poet.song.116000.json','["雲腴貢使手親調，旋放春天採玉條。", "伐鼓危亭驚曉夢，嘯呼齊上苑東橋。"]'),
('e0e24c77-2040-4777-98c0-660943ad54fe','御苑採茶歌十首  其二','熊蕃','宋','宋诗','song-poetry','','[]','采采東方尚未明，玉芽同護見心誠。',32,'全唐诗/poet.song.116000.json','["采采東方尚未明，玉芽同護見心誠。", "時歌一曲青山裏，便是春風陌上聲。"]'),
('a37b950b-0e50-4acd-9ff6-affdf2ae72b4','御苑採茶歌十首  其三','熊蕃','宋','宋诗','song-poetry','','[]','共抽靈草報天恩，貢令分明使指尊。',32,'全唐诗/poet.song.116000.json','["共抽靈草報天恩，貢令分明使指尊。", "邏卒日循雲塹繞，山靈亦守御園門。"]'),
('51578bc0-00d5-4782-9805-e7cbe77f16ed','御苑採茶歌十首  其四','熊蕃','宋','宋诗','song-poetry','','[]','紛綸爭徑蹂新苔，回首龍園曉色開。',32,'全唐诗/poet.song.116000.json','["紛綸爭徑蹂新苔，回首龍園曉色開。", "一尉鳴鉦三令趣，急持煙籠下山來。"]'),
('e59b4b28-3c98-4534-ba27-e3fd92c201e8','御苑採茶歌十首  其五','熊蕃','宋','宋诗','song-poetry','','[]','紅日新升氣轉和，翠籃相逐下層坡。',32,'全唐诗/poet.song.116000.json','["紅日新升氣轉和，翠籃相逐下層坡。", "茶官正要靈芽潤，不管新來带露多。"]'),
('3761c3f5-3c6e-4081-8481-67e3c2782aaa','御苑採茶歌十首  其六','熊蕃','宋','宋诗','song-poetry','','[]','翠虬新範絳紗籠，看羅春生玉節風。',32,'全唐诗/poet.song.116000.json','["翠虬新範絳紗籠，看羅春生玉節風。", "葉氣雲蒸千嶂綠，歡聲雷震萬山紅。"]'),
('d95fe041-5285-44c0-a0e8-cb209371d01e','御苑採茶歌十首  其七','熊蕃','宋','宋诗','song-poetry','','[]','鳳山日日滃非煙，賸得三春雨露天。',32,'全唐诗/poet.song.116000.json','["鳳山日日滃非煙，賸得三春雨露天。", "棠坼淺紅酣一笑，柳垂淡綠困三眠。"]'),
('35332c1a-3446-43a2-9968-ef30be961e38','御苑採茶歌十首  其八','熊蕃','宋','宋诗','song-poetry','','[]','龍焙夕薰凝紫霧，鳳池曉濯带蒼煙。',32,'全唐诗/poet.song.116000.json','["龍焙夕薰凝紫霧，鳳池曉濯带蒼煙。", "水芽只自宣和有，一洗槍旗二百年。"]'),
('2f14394e-c68e-46b5-b1f6-24662a90b4ea','御苑採茶歌十首  其九','熊蕃','宋','宋诗','song-poetry','','[]','脩貢年年採萬株，只今勝雪與初殊。',32,'全唐诗/poet.song.116000.json','["脩貢年年採萬株，只今勝雪與初殊。", "宣和殿裏春風好，喜動天顔是玉腴。"]'),
('19bcbecc-7fa9-41d5-92bf-e1f8532550f5','御苑採茶歌十首  其一○','熊蕃','宋','宋诗','song-poetry','','[]','外臺慶曆有仙官，龍鳳纔聞制小團。',32,'全唐诗/poet.song.116000.json','["外臺慶曆有仙官，龍鳳纔聞制小團。", "爭得似金模寸璧，春風第一薦宸餐。"]'),
('bfd96518-e6d3-48f5-b52c-95a487ecaf12','登金山','熊蕃','宋','宋诗','song-poetry','','[]','注海銀成壑，浮空玉作堆。',48,'全唐诗/poet.song.116000.json','["注海銀成壑，浮空玉作堆。", "鼇翻三島出，鷲駕一峯來。", "塔影波摇動，鐘聲潮拍回。", "猶嗟禪伯老，虛人妙高臺。"]'),
('83dd2dd3-1ea0-440b-b497-066a1c43dacf','句  其一','熊蕃','宋','宋诗','song-poetry','','[]','雨珠波上擲，霞錦浪中翻。',12,'全唐诗/poet.song.116000.json','["雨珠波上擲，霞錦浪中翻。"]'),
('b52712c5-d2a2-4830-aaf4-2cc7f48de79b','句  其二','熊蕃','宋','宋诗','song-poetry','','[]','禹鑿隋穿今古利，吳檣楚楫去來空。',16,'全唐诗/poet.song.116000.json','["禹鑿隋穿今古利，吳檣楚楫去來空。"]'),
('c7f43194-fb9f-44ce-a2c6-8f6350a18b86','句  其三','熊蕃','宋','宋诗','song-poetry','','[]','僻疑昏有虎，靜怪曉無雞。',12,'全唐诗/poet.song.116000.json','["僻疑昏有虎，靜怪曉無雞。"]'),
('723850db-302b-45cc-bb04-3481e91139c1','大滌洞天留題','趙珂夫','宋','宋诗','song-poetry','','[]','九鎖山藏一洞天，棲真大滌洞巍然。',64,'全唐诗/poet.song.116000.json','["九鎖山藏一洞天，棲真大滌洞巍然。", "雲根石出仙人迹，天柱峰流漱玉泉。", "丹鳳岩前遊熟路，翠蛟亭上揖來賢。", "我兒禱旱朝龍井，一雨昭蘇大有年。"]'),
('426a3c9b-faa0-45e8-9cc5-78f92455fda5','李鄴侯贊','陳長方','宋','宋诗','song-poetry','','[]','四海九州，如一戯具。',180,'全唐诗/poet.song.116000.json','["四海九州，如一戯具。", "運之失機，人與俱仆。", "嗟世小兒，坐旁窺觀。", "擬指其手，目動心寒。", "偉茲鄴侯，把握是器。", "南西北東，唯所欲置。", "先擣范陽，困賊兩河。", "遠猷不施，遺孽遂多。", "藉其餘智，指令李郭。", "尚洗甲兵，二都清廓。", "再造有唐，如漢子房。", "留封亦謝，高卧嵩陽。", "老居上宰，前星嵲屼。", "誠動昏庸，陰銷篡奪。", "寒暑迭運，今三百年。", "巖巖英風，儼若在前。", "我思古人，心焉密勿。", "偉茲鄴侯，才不世出。"]'),
('defaced5-447d-4d6c-9661-07103632610f','李西平畫像贊','陳長方','宋','宋诗','song-poetry','','[]','德宗貪功失君德，四海力欲干戈平。',240,'全唐诗/poet.song.116000.json','["德宗貪功失君德，四海力欲干戈平。", "但喜馬公窘田悅，滔俊角出飛秋鷹。", "綿綿延延到希烈，乘間索賦無時停。", "涇師門外一朝起，舟中敵國又朱泚。", "倉忙出走幸奉天，大器傾移飜手爾。", "西平忠武根于天，奮身一旅當無前。", "東猘西虺致首尾，屹立左右相周旋。", "馬鳴蕭蕭嚮都鄙，師行引繩士如水。", "傳呼齊道相公來，談笑王城藏袖裏。", "包戈卧鼓含元廷，青天洗出妖祲清。", "遠坊窮巷鷄與犬，寂寂不驚刁斗聲。", "德宗胸中暗如墨，懷光效忠終反側。", "海內洶湧等沸羹，不有西平那復國。", "嗟乎西平誠功高，景鐘太常書勳勞。", "爲臣爾爾乃其職，慎勿滿假矜賢豪。"]'),
('305e0e06-d629-4ab8-9d56-2ed7170dda06','李衛公贊','陳長方','宋','宋诗','song-poetry','','[]','虬鬚天人世不有，兩河股裂羣兇手。',128,'全唐诗/poet.song.116000.json','["虬鬚天人世不有，兩河股裂羣兇手。", "健兒誰復知大家，養子朝朝飲牛酒。", "廟堂坐論贊皇公，三鎮便同牛馬走。", "濯手爲雨噫爲風，斡旋六合臂運肘。", "奇章器僅等罍樽，公人中龍彼犬豚。", "數百年來號牛李，氣塞不堪今重論。", "感時念古寸心切，更覺會昌勳業尊。", "未應精爽焄蒿盡，試哦楚些招斷魂。"]'),
('3cc820c0-8c22-4faf-ad8b-9979ccb73a2f','程伊川贊','陳長方','宋','宋诗','song-poetry','','[]','道如皎日，絲毫不隔。',140,'全唐诗/poet.song.116000.json','["道如皎日，絲毫不隔。", "人自迷之，轉南爲北。", "寥寥千載，𧥄𧥄百家。", "精罷力憊，言多道遐。", "惟吾夫子，神交累聖。", "一念全德，千差盡正。", "發古關鍵，推與人同。", "學焉得此，作聖之功。", "浩乎無倪，體之甚邇。", "力扶斯文，仆而復起。", "我瞻遺像，非沒非存。", "傳之後裔，愈久彌尊。", "有功生民，不下神禹。", "非知道者，將誰告語。"]'),
('9b2f9b62-590d-4ac1-9478-d1082c13cef5','張橫渠贊','陳長方','宋','宋诗','song-poetry','','["\u6cf0\u5c71"]','祖龍吐毒，烈火四焚。',180,'全唐诗/poet.song.116000.json','["祖龍吐毒，烈火四焚。", "先王載籍，畢罹其屯。", "劉漢崛興，訪索丘墳。", "羣儒掇拾，百不一存。", "綿蕝之野，陋兮叔孫。", "胸謀腹斷，己學自尊。", "致彼古禮，寥落無聞。", "勇哉先生，絕類離倫。", "追千歲上，以禮立身。", "隠居關右，化行于民。", "賓嘉喪祭，唯古之循。", "坐令鄒魯，復見咸秦。", "巖巖泰山，烈烈秋暾。", "先生謹嚴，比德實均。", "嗟世習非，誠難具論。", "棄禮自快，紛其如雲。", "感今陳古，歌以斯文。", "庶由高躅，起我後昆。"]'),
('1f7fe595-67c6-4340-889a-ccfc83c19389','聞思大士入定相善財童子致恭揭諦神後衛因爲之贊','陳長方','宋','宋诗','song-poetry','','[]','幪頭疊足，歛目而禪。',120,'全唐诗/poet.song.116000.json','["幪頭疊足，歛目而禪。", "聞思盡處，當念超然。", "不起於座，遍羣生前。", "如行空月，影落百川。", "提孩念道，訪求知識。", "海山絕處，慈容忽覿。", "一俛仰間，今吾非昔。", "回首百城，山川歷歷。", "大士儼若，非空非有。", "毀讚莫及，孰衛孰守。", "唯此力人，雄風赳赳。", "是亦孔門，禦侮之友。"]'),
('56f845dd-5afb-4225-a57c-8da84b6451be','真武贊','陳長方','宋','宋诗','song-poetry','','[]','北方之神非此形，世俗强爲圖其真。',32,'全唐诗/poet.song.116000.json','["北方之神非此形，世俗强爲圖其真。", "天一生水罔與冥，草玄揚雲知彼情。"]'),
('8b5950d9-e17c-45c6-9b3b-3e21f7e214ad','張子房','陳長方','宋','宋诗','song-poetry','','[]','子房非漢臣，憫世爲一起。',56,'全唐诗/poet.song.116000.json','["子房非漢臣，憫世爲一起。", "借力用沛公，東西唯所指。", "注措豈因黄石書，出處非由赤松子。", "博浪沙中擊祖龍，欲報君仇遑恤己。"]'),
('42933b9c-e4ba-4ed1-9d8e-c633085aca18','陸宣公','陳長方','宋','宋诗','song-poetry','','[]','赤符兆此水，黄圖蒙楚氛。',156,'全唐诗/poet.song.116000.json','["赤符兆此水，黄圖蒙楚氛。", "上天眷李氏，未許鯨鯢吞。", "胚胎出仁人，來佐文皇孫。", "如鳳不鷙搏，坐使衆鳥君。", "奉天累卵危，柱石繄公存。", "奈何兒曹癡，但侈李渾勳。", "或云詔令下，雪泣山南軍。", "瑣瑣計功閥，淺識難與論。", "君看商辛罪，詎可臣周文。", "朝有一微子，國勢南山尊。", "道大與時背，晚棄天之垠。", "溟渤泄毫芒，世已高清芬。", "窮通一吷耳，止止毋重云。"]'),
('415c474b-2820-4f29-9eb9-0225045006a2','寄黄端冕時從張丞相幕中','陳長方','宋','宋诗','song-poetry','','[]','三年不相面，思君夕十起。',84,'全唐诗/poet.song.116000.json','["三年不相面，思君夕十起。", "君趨大江東，此情隨逝水。", "仲尼方過宋，亦主司城子。", "欲行平生言，詎知不由此。", "男兒一語契，發軔見千里。", "崎嶇馬迹間，輸誠勞舌齒。", "浩歌歸去來，長劍無須倚。"]'),
('c3bc9eba-9f4b-4033-a6f6-bf61b74c8ed2','文儒見和四詩欽歎高妙謹用韻爲答卒章問訊汝霖幸呈似也  其一','陳長方','宋','宋诗','song-poetry','','[]','我貧如曲逆，甕牖門垂席。',84,'全唐诗/poet.song.116000.json','["我貧如曲逆，甕牖門垂席。", "莽蒼且三餐，鵬鷃俱自適。", "功業薰天地，等是一戲劇。", "高堂親鵠髮，甘脆尚謀食。", "空餘聖門事，黽勉愧强力。", "前修皎日星，一一是標的。", "未敢如求賜，自畫兼願息。"]'),
('23969723-5349-4bf6-89bf-ab7d22c42b67','文儒見和四詩欽歎高妙謹用韻爲答卒章問訊汝霖幸呈似也  其二','陳長方','宋','宋诗','song-poetry','','[]','公居吳淞濱，聲名到童兒。',84,'全唐诗/poet.song.116000.json','["公居吳淞濱，聲名到童兒。", "弓旌羔雁招，尚落滄海遺。", "淡然如秋容，杳渺無津涯。", "扁舟載西子，獨此見子皮。", "兼收及我輩，一視白與緇。", "他年高士傳，讀者當見思。", "不但首陽士，廉稱百世師。"]'),
('99313f19-ea6c-4a1e-a909-ca8d48e919bc','文儒見和四詩欽歎高妙謹用韻爲答卒章問訊汝霖幸呈似也  其三','陳長方','宋','宋诗','song-poetry','','[]','記公當日事，天上冠羣英。',84,'全唐诗/poet.song.116000.json','["記公當日事，天上冠羣英。", "偕計旅庭實，稚齒先飛聲。", "胸中五色絹，補衮澤斯民。", "云胡卷而歸，不效岐山鳴。", "翛然脫外累，志尚惟清寧。", "坐使嘉穀富，無復生蝗螟。", "因公古人風，併得千載情。"]'),
('0f79a116-d132-442a-8c7c-6fd5ee85b0c0','文儒見和四詩欽歎高妙謹用韻爲答卒章問訊汝霖幸呈似也  其四','陳長方','宋','宋诗','song-poetry','','[]','好在蘇夫子，琴書安穩不。',84,'全唐诗/poet.song.116000.json','["好在蘇夫子，琴書安穩不。", "尺書寄雙鯉，一一無沉浮。", "不見才幾日，沃若桑已稠。", "應與曜菴人，靜話同茶甌。", "目送歸飛鴻，縹渺天南頭。", "趣合略畦畛，道同當共謀。", "何時暫來旋，促駕毋停輈。"]'),
('b3a9b9e8-27b9-42ad-a843-c9e13ceebdd7','讀蕭相國傳嘉召平出處之合義作召平詩','陳長方','宋','宋诗','song-poetry','','[]','秦刑次骨政如虎，六合瓦分訪前主。',191,'全唐诗/poet.song.116000.json','["秦刑次骨政如虎，六合瓦分訪前主。", "龍蛇五年垓下定，尺地寸天皆漢土。", "青門抱甕等齊民，齎志肯教重屈身。", "採薇昔日首陽下，豈謂周武慙商辛。", "爲臣委質貳乃辟，况我陪封存故國。", "不知荒虐但知君，可卷隨人心匪席。", "每開汗簡爲潸然，出處真成不愧天。", "袖手叵堪餘伎癢，往弔酇侯消未然。", "高皇漫道羣雄祖，何似蕭王更英武。", "一相不能推赤心，終至遭君玩掌股。", "君不見臧文仲，厚祿知賢不能共。", "千古難辭竊位譏，我爲酇侯還忸怩。"]'),
('aff1cd11-0ef5-4841-9f3b-f76160852080','孔明','陳長方','宋','宋诗','song-poetry','','[]','阿衡專美有商初，誰氏彷彿前規橅。',192,'全唐诗/poet.song.116000.json','["阿衡專美有商初，誰氏彷彿前規橅。", "漢末諸君憤城狐，外召紹卓爲韓盧。", "毒流三輔被京都，鈇鑕至乃誅無鬚。", "紛紜少定淚塢誅，諸君自名穀與孤。", "海內各各援鼓桴，才如粟毛爭馳驅。", "孔明高卧南陽廬，視之過前初若無。", "三顧幡然去枌榆，實類有莘彼丈夫。", "玄德沒地存孤雛，昏暗僅比曹丕奴。", "扶之立國西南區，君臣內外靡咨吁。", "茲事可直桐宮居，孔明乃古阿衡徒。", "何人欲並齊夷吾，是將魚目方璠璵。", "九原可作誰歸與，嗚呼斯人真起予。"]'),
('3e4d84ac-9811-4c0f-9b89-d4437481d0bc','題趙坦之唐人所畫二馬','陳長方','宋','宋诗','song-poetry','','[]','前身道林後曹覇，筆下馬生非可畫。',160,'全唐诗/poet.song.116000.json','["前身道林後曹覇，筆下馬生非可畫。", "心賞神駿今繪神，戲弄丹青疑造化。", "風鬃霧鬣何足云，電行山立更逼真。", "脫遺皮毛見驥德，妙處了非由寫形。", "兔園喜事佳公子，王濟風流略相似。", "畫中一見猶好之，不但千金致燕市。", "明窗展拭須韻語，杜陵無人欲誰付。", "鄧公驄馬二三羣，夢想風標覬神遇。", "此詩此畫今不逢，見畫與詩元自同。", "誰知一洗凡馬句，今在生綃半幅中。"]'),
('26ff4205-1102-406c-906d-4d4e3a8123ed','讀張文潜黄魯直中興頌有作','陳長方','宋','宋诗','song-poetry','','[]','文皇光明大式圍，招來羣策常低眉。',192,'全唐诗/poet.song.116000.json','["文皇光明大式圍，招來羣策常低眉。", "恩流動植到肌骨，民心與作邦家基。", "歲月日逝閲天寶，樁撞家居恣纖兒。", "婦后一日投三子，內間更納壽王妃。", "三綱俱紊今若此，漁陽叛將來猶遲。", "騎騾入蜀事慘惻，靈武即位尤堪悲。", "五郎父子較名義，直與安史分毫釐。", "若非貞觀基局牢，分披已作周東西。", "臨淮電擊亦漫爾，汾陽韜畧將何爲。", "後來更出顔元輩，深詞大刻中興碑。", "艱難不少念厥祖，坐蒙前福仍夸毗。", "鑑觀陳迹動歎息，願上文王聖德詩。"]'),
('6f1f6cec-c096-4850-84f2-ed351787fbe4','古劍行','陳長方','宋','宋诗','song-poetry','','[]','不辨干將與莫耶，仗之使我心無邪。',128,'全唐诗/poet.song.116000.json','["不辨干將與莫耶，仗之使我心無邪。", "光芒紫氣射牛斗，知音今不乏張華。", "百鍊精剛歐冶手，一仗尚能清九有。", "有時陰靄天地昏，匣中飛電金蛇走。", "切玉如泥未足珍，終當化去烏足神。", "願與朱雲斬邪佞，豈甘埋沒延平津。", "莫道承平便無用，長使姦雄毛骨竦。", "上决浮雲日月明，疾視羞爲一夫勇。"]'),
('870fecfb-68aa-492a-abb5-f8305fa03ca2','贈畫者徐琛','陳長方','宋','宋诗','song-poetry','','[]','我行江南江北山，真賞會心那可數。',240,'全唐诗/poet.song.116000.json','["我行江南江北山，真賞會心那可數。", "獨愛黄陵古廟前，四水粘天迷浦溆。", "胸中歷歷着山川，有句如枝不容吐。", "欲將寫作無聲詩，筆底愧非韋與許。", "今年南走到閩越，歸踏雪峯由後路。", "蛇行山腹動十里，屏列奇峯疑八柱。", "連雲直擬穿天心，飛瀑橫看如急雨。", "盤渦雷吼又奔注，小立只憂蛟鰐怒。", "何異周南太史家，西上九疑東訪禹。", "君能點染出江山，造物鑪錘困掀侮。", "李成不作郭熙死，誰謂今人不如古。", "五日一水十日石，得意無煩用心苦。", "君觀宋迪傳深趣，元在頹牆破環堵。", "正如草聖得神逸，擔夫爭道公孫舞。", "吾言有味君細聽，領畧當同少林祖。"]'),
('64aca3eb-c7ad-4c02-b045-4e2e36dbab68','邊公明盡屏葷茹因成古風約叔度良佐周翰同賦公明學佛而不專意性理故及之','陳長方','宋','宋诗','song-poetry','','[]','君不見何曾萬錢不下筯，一食淋漓汙刀俎。',182,'全唐诗/poet.song.116000.json','["君不見何曾萬錢不下筯，一食淋漓汙刀俎。", "又不見王濟春醪人抱甕，盈缶蒸豚漬人乳。", "百年光景電畫水，口腹何須事如許。", "夫君景德公侯家，鳴鐘列鼎相矜誇。", "奈何烏帽嵌岩底，栽松藝菊餐烟霞。", "年來刪薙到口腹，不待聞韶便忘肉。", "前身知是永禪師，想似當年房相國。", "庖厨漸遠世緣輕，定水泓澄久更明。", "蒲團好究風幡句，率陀未是公歸處。", "一日還家不移步，方信今吾了非故。", "作詩相賀雜苦語，愛人以德吾非據。"]'),
('a97f66cc-2f01-44ba-8899-28d724be73cf','別葉子','陳長方','宋','宋诗','song-poetry','','[]','歸袂飄飄舉，春風催去船。',48,'全唐诗/poet.song.116000.json','["歸袂飄飄舉，春風催去船。", "又爲旬日別，已覺寸心懸。", "詩社須摩詰，兄家念惠連。", "千金輕一諾，季布豈空傳。"]'),
('acc5fcaf-6e37-470e-9d71-b2426237409a','王正自挽詩  其一','陳長方','宋','宋诗','song-poetry','','[]','道史詞華麗，蘭臺地望高。',48,'全唐诗/poet.song.116000.json','["道史詞華麗，蘭臺地望高。", "鴛行方接翼，牛刃極吹毛。", "豈料飛梭語，長令空谷逃。", "棲遲俄委化，驚惋首重搔。"]'),
('e652d139-c5e2-4e98-b05a-b83bde1c059f','王正自挽詩  其二','陳長方','宋','宋诗','song-poetry','','[]','登門纔幾日，祖奠亦歔欷。',48,'全唐诗/poet.song.116000.json','["登門纔幾日，祖奠亦歔欷。", "毀譽付公是，游談空昨非。", "厲階由怨府，意廣數危機。", "世味元如許，休嗟志願違。"]'),
('271b67da-ed7d-4cd4-91e7-272e207ae3fe','楊漢公挽詞二首  其一','陳長方','宋','宋诗','song-poetry','','[]','今世稱能吏，如君第幾人。',48,'全唐诗/poet.song.116000.json','["今世稱能吏，如君第幾人。", "銅章恩屢易，象板命惟新。", "華表歸無日，泉臺冷不春。", "承家在諸子，勉力紹前塵。"]'),
('2995dd04-18e8-46b4-adc5-adace51be250','楊漢公挽詞二首  其二','陳長方','宋','宋诗','song-poetry','','[]','一日官聯舊，千秋事契存。',48,'全唐诗/poet.song.116000.json','["一日官聯舊，千秋事契存。", "窆棺蕭寺側，築屋白雲根。", "綿力慚無助，丹心徒重論。", "凄凉楚些韻，誰解與招魂。"]'),
('7a2c71fb-76ed-4b16-ba9a-36dd7f5e3503','去冬因元鎮有見懷詩草草用韻錄上併謝妙藥名墨之惠','陳長方','宋','宋诗','song-poetry','','[]','南來仙驥一回翔，古墨丹砂併送將。',64,'全唐诗/poet.song.116000.json','["南來仙驥一回翔，古墨丹砂併送將。", "從此微軀常得健，學君揮翰詎能忘。", "霜寒碧澗行蹤少，月落青林去夢長。", "相見只愁俱白髮，敢辭不飲負清觴。"]'),
('b4ae0c6d-0a87-434f-bada-94e7c5a99024','送李尹叔解印','陳長方','宋','宋诗','song-poetry','','[]','數年美政在棠陰，考績如公合賜金。',64,'全唐诗/poet.song.116000.json','["數年美政在棠陰，考績如公合賜金。", "莫問逢迎妨俗眼，但知惠愛盡吾心。", "攀車共願輪生角，追路端如鹿走林。", "我亦一廛清霅尾，慚無妙筆寫徽音。"]'),
('1d523053-81c2-43f2-9ec1-cfe44ae7fda1','寄胡仲連三丈','陳長方','宋','宋诗','song-poetry','','[]','吳中耆舊固無多，底事年來病作魔。',64,'全唐诗/poet.song.116000.json','["吳中耆舊固無多，底事年來病作魔。", "無妄那知能召疾，蹈仁誰謂反傷和。", "阻操几杖候安否，宜遣音書問若何。", "不藥行將致康復，銅人公可手摩挲。"]'),
('0990239a-9eaa-42e7-9569-e242f9b3e46c','觀亡弟同之書札感懷','陳長方','宋','宋诗','song-poetry','','[]','處處君書畫，難堪淚雨沱。',24,'全唐诗/poet.song.116000.json','["處處君書畫，難堪淚雨沱。", "如何遵養力，不似世緣多。"]'),
('b1c37147-6778-47cf-b50e-b725cec7960c','書中庸示邊周翰','陳長方','宋','宋诗','song-poetry','','[]','紙上遺書字宛然，千年微意有誰傳。',32,'全唐诗/poet.song.116000.json','["紙上遺書字宛然，千年微意有誰傳。", "曾將靈鑰開關鈕，珍重成周二老賢。"]'),
('47833140-26a2-4a42-ac2f-5c652eaf5721','酈生長揖','陳長方','宋','宋诗','song-poetry','','[]','輟洗高陽一酒徒，沛公雅意在雄圖。',32,'全唐诗/poet.song.116000.json','["輟洗高陽一酒徒，沛公雅意在雄圖。", "終煩前箸還銷印，王表知君淺丈夫。"]'),
('fa223757-c888-414f-bd18-4a79075e746a','張釋之諫文帝','陳長方','宋','宋诗','song-poetry','','[]','樂極生悲倚瑟歌，一言悟主亦何多。',32,'全唐诗/poet.song.116000.json','["樂極生悲倚瑟歌，一言悟主亦何多。", "晏嬰往日規齊景，廷尉風流更不磨。"]'),
('f779293e-eda5-491e-8d9c-cd04b2deb019','霍光賞符璽郎','陳長方','宋','宋诗','song-poetry','','[]','黄四娘家花滿蹊，姓名因寄杜陵詩。',32,'全唐诗/poet.song.116000.json','["黄四娘家花滿蹊，姓名因寄杜陵詩。", "孟堅父子編摩久，符璽中郎竟爲誰。"]'),
('019fd336-ce64-43ff-a08b-41a604ae94e6','金日磾見馬','陳長方','宋','宋诗','song-poetry','','[]','黼座天臨粉黛中，苑前過馬貌惟恭。',32,'全唐诗/poet.song.116000.json','["黼座天臨粉黛中，苑前過馬貌惟恭。", "那知漠北休屠子，前古由余可比蹤。"]'),
('6a42f001-5d4c-41e4-ad64-6ffad492008a','馮倢伃','陳長方','宋','宋诗','song-poetry','','[]','倉惶環柱祖龍子，失筯驚雷劉使君。',32,'全唐诗/poet.song.116000.json','["倉惶環柱祖龍子，失筯驚雷劉使君。", "肯信綠眉蟬鬢客，當熊意氣壓三軍。"]'),
('ed2db163-5ee6-4f89-84dc-d668eced8e22','王昭君','陳長方','宋','宋诗','song-poetry','','[]','巫峽江邊歲屢更，漢宮日月亦崢嶸。',32,'全唐诗/poet.song.116000.json','["巫峽江邊歲屢更，漢宮日月亦崢嶸。", "此身端可清邊患，誰惜龍沙以北行。"]'),
('b7054f50-dfd7-4247-94af-97df33cde808','山簡習池','陳長方','宋','宋诗','song-poetry','','[]','夷甫清言百不知，山公日醉習家池。',32,'全唐诗/poet.song.116000.json','["夷甫清言百不知，山公日醉習家池。", "晉朝將相元如此，石勒劉淵自奮飛。"]'),
('9c15693c-4117-45d3-b50a-1d0e38b99cd6','明皇覽鑑妃子剪髮圖','陳長方','宋','宋诗','song-poetry','','[]','引鑑能知天下肥，此時未納壽王妃。',32,'全唐诗/poet.song.116000.json','["引鑑能知天下肥，此時未納壽王妃。", "龍眠解向丹青裏，寫出開元治亂機。"]'),
('4517b876-946d-4021-ae97-dca606b6ba66','胡少明兩書索二程先生畫像寄小詩二首  其一','陳長方','宋','宋诗','song-poetry','','[]','微言固已成糟粕，紙上形容轉更踈。',32,'全唐诗/poet.song.116000.json','["微言固已成糟粕，紙上形容轉更踈。", "要識平生真面目，百無所似若爲書。"]'),
('58aeda1b-a7fd-48f0-8bdb-8a43f2305bbf','胡少明兩書索二程先生畫像寄小詩二首  其二','陳長方','宋','宋诗','song-poetry','','[]','牛首蒙倛兩誤傳，與人同處最難言。',32,'全唐诗/poet.song.116000.json','["牛首蒙倛兩誤傳，與人同處最難言。", "孟軻出語不驚坐，熟復方能知委源。"]'),
('27122c90-83d0-4da3-bf7c-a77f5864e9f4','懷少明  其一','陳長方','宋','宋诗','song-poetry','','[]','故人漂泊客江鄉，夜雨相思夜更長。',32,'全唐诗/poet.song.116000.json','["故人漂泊客江鄉，夜雨相思夜更長。", "經歲不來來又去，端如鴻燕遞相望。"]'),
('d7cc3658-299c-425f-ad84-3c6fdce882da','懷少明  其二','陳長方','宋','宋诗','song-poetry','','[]','江蘆葉葉生秋思，相對閑窗伴晚風。',32,'全唐诗/poet.song.116000.json','["江蘆葉葉生秋思，相對閑窗伴晚風。", "想得塗菘胡伯武，此時情味與誰同。"]'),
('35f0d90d-94cc-4fbe-99d0-850d59cb1fe5','答虞明中','陳長方','宋','宋诗','song-poetry','','[]','若道平生未始離，誰知此語已成非。',32,'全唐诗/poet.song.116000.json','["若道平生未始離，誰知此語已成非。", "饒君向此知端的，未免猶成我與伊。"]'),
('a716eb0c-c9cf-473a-bcd2-308a81866e13','示弟','陳長方','宋','宋诗','song-poetry','','[]','欲知天理即私心，切莫將來兩處尋。',32,'全唐诗/poet.song.116000.json','["欲知天理即私心，切莫將來兩處尋。", "翻手爲雲覆手雨，只今猶昔昔猶今。"]'),
('7c894b09-1e42-4c44-b574-aaadbf6d6f40','觀雲','陳長方','宋','宋诗','song-poetry','','[]','浮雲聚散復西東，此處容君一線通。',32,'全唐诗/poet.song.116000.json','["浮雲聚散復西東，此處容君一線通。", "全體露時如不領，問君何日解相逢。"]'),
('76d93f66-3627-4cf1-8e49-e61fe4d5c714','題牛圖','陳長方','宋','宋诗','song-poetry','','[]','卧嚙枯萁對晚風，微勞畎畝未須雄。',32,'全唐诗/poet.song.116000.json','["卧嚙枯萁對晚風，微勞畎畝未須雄。", "吾君痛迫劉文叔，好試當年新野功。"]'),
('bab5207e-890e-4233-87c4-a6c7bd9a3132','牧羊圖','陳長方','宋','宋诗','song-poetry','','[]','畫史含毫欲下時，筆端新意有誰知。',32,'全唐诗/poet.song.116000.json','["畫史含毫欲下時，筆端新意有誰知。", "滿山羖䍽燕然北，快取奇功慎莫遲。"]'),
('754086d3-7a98-49d5-a646-0e7ea0396a65','題定武本蘭亭  其一','陳長方','宋','宋诗','song-poetry','','[]','昭陵一入見無從，鎸石猶將贋本供。',32,'全唐诗/poet.song.116000.json','["昭陵一入見無從，鎸石猶將贋本供。", "八法典刑今在此，華山天外立三峯。"]'),
('a4c2fe80-3816-4a94-be3c-213315545ebd','題定武本蘭亭  其二','陳長方','宋','宋诗','song-poetry','','[]','不須苦恨厭家雞，自是鹽車後月題。',32,'全唐诗/poet.song.116000.json','["不須苦恨厭家雞，自是鹽車後月題。", "弄筆數行書紙背，莫教人喚庾安西。"]'),
('452c9b26-bb70-4975-898d-00475b786956','題定武本蘭亭  其三','陳長方','宋','宋诗','song-poetry','','[]','此甥此舅兩風流，翰墨相傳不誤投。',32,'全唐诗/poet.song.116000.json','["此甥此舅兩風流，翰墨相傳不誤投。", "大似曹溪付衣鉢，臨池他日看銀鉤。"]'),
('7bdef0c7-cf97-4f29-9766-75db14b7372c','歌贈葉季質','陳長方','宋','宋诗','song-poetry','','[]','葉子哦詩風雨寒，時時和墨摇筆端。',176,'全唐诗/poet.song.116000.json','["葉子哦詩風雨寒，時時和墨摇筆端。", "江山萬里入寸紙，杳靄孤鴻殘照閒。", "滄洲散髮徑欲往，已覺置我江之干。", "一身幺麽僅如許，胸次奈君湖海寬。", "酒狂稍稍芒角露，掃出怪石蒼松盤。", "他人崎嶇作能事，君獨笑談聊一戲。", "青鞋布襪自尋山，四十無家疑度世。", "莫歌長鋏歸來乎，不須苦吟頻撚鬚。", "但將美酒澆磈磊，里社年豐皆可酤。", "醉來橫眠醒讀書，長康非癡君豈愚。", "身閒無事肯過我，更作天姥當庭除。"]'),
('43eab77d-0373-4e85-b396-3ea3895b187a','和葉季質以唐律兩篇見屬','陳長方','宋','宋诗','song-poetry','','[]','風流王右轄，蕭散鄭丹邱。',48,'全唐诗/poet.song.116000.json','["風流王右轄，蕭散鄭丹邱。", "此事今難再，如公可並遊。", "千篇詩價重，十日酒船浮。", "聖主方東幸，山中莫滯留。"]'),
('0c027b0f-3278-4aa7-acb0-722c8e67d56d','書楊舜韶詩後','陳長方','宋','宋诗','song-poetry','','[]','吳城磊落見長身，屈指文章第幾人。',64,'全唐诗/poet.song.116000.json','["吳城磊落見長身，屈指文章第幾人。", "歲月消磨百年後，音容間絕九泉新。", "慚無健筆作佳傳，空對遺編獨慘神。", "符也克家端的否，會須收拾寄蒼珉。"]'),
('0c918808-bc01-4bf6-ae3b-f7778bd7a117','問學有感','陳長方','宋','宋诗','song-poetry','','[]','閒花亂蕊競紅青，誰信風光不繫停。',32,'全唐诗/poet.song.116000.json','["閒花亂蕊競紅青，誰信風光不繫停。", "問此果能知逝者，便須觸處盡相應。"]'),
('5e5d4858-f43e-45fa-9066-b5ce7121a55f','九里松','李石','宋','宋诗','song-poetry','','[]','荷花湖上船，松影沙外渡。',108,'全唐诗/poet.song.116000.json','["荷花湖上船，松影沙外渡。", "松行又九里，凉蘚引深步。", "石橋枕溪斜，中有入山路。", "意行忘屈曲，拄杖扣層戶。", "入門已欣然，但恐所見阻。", "更須上高樓，霽影蒙薄霧。", "急風層巔起，霧破山缺處。", "青林一點明，炯炯白鳥度。", "獨坐不須禪，山水得妙悟。"]'),
('5f64be70-dad3-4fcf-83ee-a1fc347f2148','山圖','李石','宋','宋诗','song-poetry','','[]','丹砂山中期，交梨海上約。',156,'全唐诗/poet.song.116000.json','["丹砂山中期，交梨海上約。", "崎嶇九折坂，準擬一丸藥。", "至今山仙翁，已跨紫霄鶴。", "鶴去當歸來，塵世憶如昨。", "天使自天降，招去遊五岳。", "洞府日月長，流水花片落。", "我來似天意，一官不足縛。", "道氣迄未充，何以痊瘴惡。", "雲霞閟靈蘂，霧雨罩仙萼。", "臭稗雜菁英，凡草混荃若。", "未免七十毒，誰敢試口嚼。", "上焉憂國病，下者念民瘼。", "安得如昔人，一舉翔寥落。"]'),
('8dd1c682-04ab-46b1-bf13-d7f8ebdd0a0c','同鄧使君賞雙頭牡丹','李石','宋','宋诗','song-poetry','','[]','兼金必貴雙，玨玉不獨隻。',120,'全唐诗/poet.song.116000.json','["兼金必貴雙，玨玉不獨隻。", "嫣然彼叢生，佳處亦求匹。", "沙寒水成練，雪洞山立壁。", "春回小洛陽，淑氣自融液。", "主人似維摩，拈花許入室。", "不礙清浄眼，粉黛眩青赤。", "聯香颯輕吹，並影旭朝日。", "有如猗蘭心，相同不相敵。", "偶來飲此酒，對花情有激。", "試哦常棣章，反經道如一。"]'),
('e8131920-474f-4283-95bd-b9d900c77ab9','黎墨','李石','宋','宋诗','song-poetry','','[]','少休大夫封，應夢上公祿。',132,'全唐诗/poet.song.116000.json','["少休大夫封，應夢上公祿。", "向來巖壑姿，高節媲青竹。", "低徊文繡地，自謂遷進速。", "邇者爲客卿，翰苑文史足。", "炎炎雖可鄙，炳炳有足錄。", "一朝汙濁流，錢券滿吾蜀。", "童山要進取，萬石壓車軸。", "通侯寵富民，都尉侈搜粟。", "雖蒙須臾榮，不蓋平生辱。", "社櫟乃天全，不及不才木。", "春秋戒求名，吾詩紀山麓。"]'),
('1f5c8e47-58cc-48c2-b8f2-511f094216f4','王顯之求名其二子曰忠厚曰忠恕','李石','宋','宋诗','song-poetry','','[]','有子固可賀，無子誰爲羞。',132,'全唐诗/poet.song.116000.json','["有子固可賀，無子誰爲羞。", "堯聖傳世念，厲醜似己憂。", "有子與無子，人事天爲謀。", "王家烏衣巷，葉葉追前修。", "乃翁萬卷書，一一手校讎。", "厚恕命爾名，萬金美田疇。", "種德日復日，藨蔉期深秋。", "字表名所出，遠意孔與周。", "陶公責端宣，晉人警師仇。", "君家膝上郎，有如昔徐侯。", "富貴二雛語，豈有卑微休。"]'),
('a7ea0b18-d984-4290-b2f4-40ebc14ac132','西堂前老松狀如偃蓋或云即摩頂松也松産茯苓爲人竊去松今不存因栽數小松補其處書此詩壁上','李石','宋','宋诗','song-poetry','','[]','阿師從何來，最是兩肩苦。',120,'全唐诗/poet.song.116000.json','["阿師從何來，最是兩肩苦。", "一頭載梵書，一頭荷慈母。", "至今江上松，東西隨仰俯。", "此松豈有情，摩頂記佛語。", "松根白衣僊，日夜瑞光吐。", "翩然紫霄上，蟄龍起雷雨。", "我來悟前緣，父老指環堵。", "風花即几席，經草隨步武。", "重栽渺生意，合抱階尺土。", "他年十八公，此地記初祖。"]'),
('79dd3d1c-7fad-4be3-9b66-4ebfe4131c6a','木芙蓉','李石','宋','宋诗','song-poetry','','[]','榮枯一氣內，造化本自公。',108,'全唐诗/poet.song.116000.json','["榮枯一氣內，造化本自公。", "春花與秋蔕，孰云有不同。", "試看木芙蕖，雨露滋芳叢。", "嫣然生百巧，秀色傾房櫳。", "婢子有不愜，偃蹇霜枝紅。", "溪柳疎其西，池荷亞其東。", "等作一物看，曾是煩春工。", "開闔寓至理，歲事號秋風。", "惟有桃李場，感歎無言中。"]'),
('0467bd35-4770-47bf-9fd6-84740cdd82ec','人日集蟆頤視堰','李石','宋','宋诗','song-poetry','','[]','大江拆兩股，小江分一支。',180,'全唐诗/poet.song.116000.json','["大江拆兩股，小江分一支。", "秋水七八月，老蟆喜持頤。", "往往自誇大，未覺海若嗤。", "灌溉雖小惠，湮溺已可危。", "父老指水跡，棲苴掛林枝。", "高田混坑谷，漠漠沙風吹。", "城堞不數步，長堤漫委蛇。", "我非河洛想，頗爲梁益悲。", "神禹豈不到，吾蜀幾爲池。", "人日有故事，敢後壺漿期。", "野叟餽魚兔，鼓舞亦致詞。", "一笑謝父老，何由救民饑。", "但得麥早熟，眼底無瘡痍。", "老守爲爾醉，燈火江之湄。", "老蟆亦放光，跳月天南垂。"]'),
('d542765a-b28b-48a3-8ad1-d5d53df9f042','小桃','李石','宋','宋诗','song-poetry','','[]','方春花氣蘇，誰忍犯霜曉。',120,'全唐诗/poet.song.116000.json','["方春花氣蘇，誰忍犯霜曉。", "漫山千樹桃，縮頸聽春鳥。", "獨此開數株，此桃也不小。", "晨霞碎林霏，絳雪壓枝裊。", "梅魂正零落，月影夜悄悄。", "陳新接物態，俯仰映池沼。", "蓬萊有大桃，歲月較多少。", "自從偷兒得，弱水隔浩渺。", "且與傾綠尊，乍見喜圍繞。", "尚有芥子微，須彌寄毫杪。"]'),
('b9db4684-c61d-4cc0-8aa6-19e8e51b401d','送張道士遊西山至道觀','李石','宋','宋诗','song-poetry','','[]','雪打窗外竹，共卧窗間床。',132,'全唐诗/poet.song.116000.json','["雪打窗外竹，共卧窗間床。", "起來忍饑凍，對坐唯爐香。", "寫之三尺琴，遶屋聲琅琅。", "相從無此好，要俶西山裝。", "西山接飛鴻，路入雲水鄉。", "六月餘積雪，冬木含春芳。", "羣仙競來往，御風騎鳳凰。", "我昔曾見之，瞳子瞭且光。", "張子長鬣師，沆瀣入肺腸。", "爲取橋下履，仍傳枕中方。", "此時覓刀圭，念我雙鬢蒼。"]'),
('b7922a44-5b25-4d8a-8b76-6164e63f8d07','送浩姪成都學官','李石','宋','宋诗','song-poetry','','[]','憶昔官博士，所得英俊多。',240,'全唐诗/poet.song.116000.json','["憶昔官博士，所得英俊多。", "斥去典蜀學，蜀士煩搜羅。", "二井轉轆轤，猶能挹餘波。", "袍子白紛紛，有如鏡重磨。", "愛汝似二父，此地曾經過。", "分職有十師，聖門嚴四科。", "儻非一萬卷，難取三百禾。", "我有十詠詩，考古煩吟哦。", "鼓鐘樂高文，羽翼崇雄軻。", "似聞禮殿栢，久矣尋斧柯。", "古物天爲惜，蒸薪鬼所呵。", "堂堂公議地，歲月窮羲娥。", "忍此恣橫說，後來敢誰何。", "我集四庫書，琬琰藏洛河。", "此外有石經，參酌正舛訛。", "熟讀懋汝學，師友相切磋。", "汝有屋三間，竹墅連松坡。", "日夜望汝成，門戶高嵯峩。", "我貧自有道，一竿釣漁蓑。", "後生問老子，守死山之阿。"]'),
('de8ae5a3-f073-4284-9eeb-1238b60f2601','病中謝三山問訊','李石','宋','宋诗','song-poetry','','[]','我昔擇師友，所至多朋儔。',264,'全唐诗/poet.song.116000.json','["我昔擇師友，所至多朋儔。", "道義自然合，如以膠漆投。", "一官既已得，勢利尋戈矛。", "向者市道交，日親成日讎。", "僅餘山林士，共結方外游。", "一語不及俗，自是無悔尤。", "况乃生死事，同參無異謀。", "何暇及汝曹，惴惴性命憂。", "此間地步窄，椰子包山丘。", "三山妙僧傑，道眼寬處求。", "憐我本逐客，饑凍妻孥羞。", "有如呼雲鶴，拍拍青泥溝。", "儻非香火緣，詎肯相恤收。", "阿璋栴檀林，手挽銀河流。", "便欲洗俗輩，歡喜解我愁。", "阿興兩隨我，五湖盟白鷗。", "對師思亡友，中書爛銀鈎。", "阿鑑殊可人，出世依大侯。", "禪學瑄演輩，圭峯家法優。", "人人蹴龍象，一笑風馬牛。", "死鼠豈鳳食，徒然嚇鵂鶹。", "行藏汝自用，吾生去來休。"]'),
('227a7d1f-dc09-4138-a31d-d480685167b0','大水寓武信二首  其一','李石','宋','宋诗','song-poetry','','[]','前時布穀鳴，早種不入土。',108,'全唐诗/poet.song.116000.json','["前時布穀鳴，早種不入土。", "翻然變陰沴，兩旬作淫雨。", "半夜水囓堤，一决不及禦。", "貧民無燈火，下牀已沒股。", "曉登樹杪呼，出沒見屋膂。", "舟車或幸災，桂玉豈易煮。", "天數苟有定，民患誰適與。", "我窮一席地，此憂豈暇汝。", "爲汝愁天公，閉戶不欲語。"]'),
('79c08cba-ed4a-45ce-8cbe-0f9dcf9371b1','大水寓武信二首  其二','李石','宋','宋诗','song-poetry','','[]','民無穴居智，不如彼狐狸。',96,'全唐诗/poet.song.116000.json','["民無穴居智，不如彼狐狸。", "奔流决戶入，尚懷囊橐資。", "倉卒老穉計，共此高樹栖。", "茫茫無舟筏，渺渺失陵陂。", "號呼性命急，千鈞懸一絲。", "引手幸免魚，十五爲流尸。", "古今民父母，唯有愷悌詩。", "吾詩本不作，聊以箴厥堤。"]'),
('774401d4-4657-4551-b2b4-f473a4a77272','齊人畫禮器','李石','宋','宋诗','song-poetry','','[]','漆器侈初俗，長袖喧都城。',144,'全唐诗/poet.song.116000.json','["漆器侈初俗，長袖喧都城。", "如何古邃殿，天開垂日星。", "奇奇與怪怪，惝怳不識名。", "我嘗閲此畫，肇自齊永明。", "人間務備物，未易窮丹青。", "憶昨因郊丘，盛禮嚴天庭。", "器服各異數，如此係大成。", "仰瞻萬乘聖，遠想三代英。", "蟣蝨容著足，鴛鷺參結綪。", "西歸訪江梅，鈞天夢初醒。", "心焉感此畫，眼角泫欲零。", "所見恐未夥，蜀都問君平。"]'),
('d4295169-d24d-4fec-94ab-f455b3cba05e','送吳道明推官并問趙莊叔何公禮兄弟','李石','宋','宋诗','song-poetry','','[]','送客涪水上，我家珠水湄。',120,'全唐诗/poet.song.116000.json','["送客涪水上，我家珠水湄。", "我適歸未得，此別那不思。", "高才府從事，芙蕖映清池。", "堂堂萬卷書，樂此簿領卑。", "公退得繞膝，戲綵笑脫頤。", "山路宿雨乾，籬落黄橘垂。", "歸鞍三百里，處處吟酒旗。", "趙子與南陽，衡門各棲遲。", "下馬恐問及，說與黄梅期。", "尚念鴻鴈行，冷落秋風吹。"]'),
('d774ff9d-4591-46cc-9183-6a03d25e49b5','送黄安國同年','李石','宋','宋诗','song-poetry','','[]','沙水夜仍白，江月曉未收。',96,'全唐诗/poet.song.116000.json','["沙水夜仍白，江月曉未收。", "聯船共一岸，撼枕聞開頭。", "五湖翻然歸，鳧鴈蘆花秋。", "低徊弄氷雪，笑面會有由。", "有如此江波，大小同一浮。", "纖花不自惜，風捲隨輕鷗。", "誰能徇殘啄，五羖肥幾牛。", "我欲知行津，上峽詢耡耰。"]'),
('4d3522b4-b38b-48ba-910a-e0eb2784ba50','李漕和詩次韻','李石','宋','宋诗','song-poetry','','[]','斯文百官富，未易衆目窺。',120,'全唐诗/poet.song.116000.json','["斯文百官富，未易衆目窺。", "共此一鳥過，誰其補三遺。", "粗能述前輩，抗說不敢卑。", "一朝得印可，寵若華衮辭。", "神仙點金手，爲脫瓦礫姿。", "微吟氷雪鏤，落墨星虹垂。", "老成今幾人，縻以歲月遲。", "未用五字工，護此兩鬢絲。", "聖賢無盡藏，一一生物滋。", "丐公且藏舌，尚結他時知。"]'),
('33525d99-3ca6-495e-86ba-604db6e2ec16','驟雨','李石','宋','宋诗','song-poetry','','[]','荒風吼其前，大雷擊其後。',192,'全唐诗/poet.song.116000.json','["荒風吼其前，大雷擊其後。", "人言黄昏雨，此意無乃驟。", "飄飄豈惡聲，側耳聽簷溜。", "一睡喜暫凉，破窗落星宿。", "明朝看東方，老火已復晝。", "起行視畦隴，微露泫深秀。", "枯溝澀不流，焦塊濡未透。", "看看歲云秋，槁死念誰救。", "濫興桑羊誅，妄使土龍鬭。", "彼巫乃誣爾，拜舞雜符呪。", "舉頭亦茫茫，萬一幸天漏。", "雲行則雨施，坎畫自羲后。", "爲霖有真源，中路困坑竇。", "眼前蒼狗姿，津潤豈能潄。", "何當捲江海，九萬廣天覆。", "有禱恐未遲，帝閽吾欲叩。"]'),
('74d1cb3d-cc3f-46c9-acd8-e0bed9a4f222','王晦叔許惠歙硯作詩迫之','李石','宋','宋诗','song-poetry','','[]','書生總不羈，豈是謬進取。',108,'全唐诗/poet.song.116000.json','["書生總不羈，豈是謬進取。", "偶然一舟具，初不作出處。", "三年客江湖，風浪恣掀舞。", "君門九天上，一一守菟虎。", "是間無先容，何忍棄外府。", "萬卷久已破，一字未及吐。", "歸來賦蜀都，筆下带吳語。", "傳聞兩坑石，妙處天可補。", "試遣長鬚來，拜賜君已許。"]'),
('c7161040-0594-47e7-a9d4-95983eaaa3b4','次韻何景山愛山亭','李石','宋','宋诗','song-poetry','','[]','好山在樓頭，行人在樓下。',96,'全唐诗/poet.song.116000.json','["好山在樓頭，行人在樓下。", "愛山乃貴名，過者豈易假。", "而况主與客，君漫我亦且。", "九峯紫閣間，可玩不可把。", "嵐光接雲氣，溜溜溢杯斚。", "茲山於吾人，儻有一日雅。", "從今兩舍地，時復枉車馬。", "何必滄洲圖，醉語剩揮寫。"]'),
('9c3521b0-6671-4a23-ab8a-b8df0e23b56d','携子孫到四明洞節敘有感','李石','宋','宋诗','song-poetry','','[]','四明本山名，與洞屹相向。',288,'全唐诗/poet.song.116000.json','["四明本山名，與洞屹相向。", "取山以名洞，足以迎景貺。", "我非濟時才，香火三遣放。", "再爲玉局吏，聖恩覃曠蕩。", "有如鑑湖乞，均逸江海上。", "圓也如乃翁，歷歷耗心匠。", "三徑同蔣詡，五柳比元亮。", "一日培壅力，百年基址壯。", "桃李遵舊蹊，松竹緣疊嶂。", "林花拂朝晴，山鳥激清響。", "園人收果實，夏秋各有餉。", "誰云橐駝種，已有猢孫藏。", "翁前携客來，未免策拄杖。", "崎嶇到洞門，衰病筋力彊。", "洞中亦虛白，喜氣含萬象。", "俎豆具倉猝，一杯復一唱。", "山果與山花，足以備清賞。", "杯盤旨味薄，筆墨醉語妄。", "醉中忽擡眼，雲巢仍在望。", "投杯攬衣起，涕淚立惆悵。", "雲巢我師友，白玉已黄壤。", "相距洞與山，風雨燈燭晃。", "有如對牀夜，了不隔尋丈。", "他日吾子孫，丹青二老像。"]'),
('9f93a12a-fa01-4df9-aa0b-1e9ac98a4076','題三昧泉','李石','宋','宋诗','song-poetry','','[]','乳崖霜雪根，金地白蓮蘂。',144,'全唐诗/poet.song.116000.json','["乳崖霜雪根，金地白蓮蘂。", "泉上碧眼師，秋月照清泚。", "玉籨開明鏡，肝膽兩寃鬼。", "若爲人面創，如以佛手洗。", "遂解七國仇，化爲三昧水。", "我來愧塵纓，與世無愧喜。", "平生一瓢心，屬饜豈爲己。", "定知蜀山龍，雲雨高卧裏。", "微絲出游戲，僧飯冰入齒。", "灌溉丹穴深，窈窕滄海底。", "人怨旱火焦，雷公費鞭箠。", "請師拄杖頭，攪山喚龍起。"]'),
('b315cee3-a6cc-4a0b-a750-5ae86ebf5c9b','伊川祠呈程詠之','李石','宋','宋诗','song-poetry','','[]','彈我清風絃，酌我明月樽。',72,'全唐诗/poet.song.116000.json','["彈我清風絃，酌我明月樽。", "栖遲元祐鬼，零落伊水魂。", "金玉百世師，丹青幾代孫。", "氷雪耀荒谷，雲霧迷空村。", "斯人阨衰世，吾道誰與論。", "仙人白石溪，夫子青山根。"]'),
('fad92da8-ec8f-40b2-988f-7661f6f56ee1','遊黄州東坡','李石','宋','宋诗','song-poetry','','[]','斯文元祐間，一代人物好。',96,'全唐诗/poet.song.116000.json','["斯文元祐間，一代人物好。", "我生嗟已後，不及見此老。", "朅來東坡上，雪堂亞荒草。", "此州三家村，大江流浩浩。", "四海矜重名，六丁護殘藁。", "傷心逐客令，失脚空山道。", "昔爲魑魅憎，今作神明禱。", "小橋行吟處，風葉付誰掃。"]'),
('680e13f1-8eb7-40e8-85e5-bd758ee586e4','何司法惠示樂善新編賦詩爲謝','李石','宋','宋诗','song-poetry','','[]','不讀非相篇，人心謂如面。',96,'全唐诗/poet.song.116000.json','["不讀非相篇，人心謂如面。", "陰機蜮窺影，巧攫狙伺便。", "誰於牛毛端，萬念回一善。", "此間有堂奧，次第躬履踐。", "自言不爲惡，凜凜三語掾。", "世塗多疾人，奇藥得瞑眩。", "貽我南陽書，補作東平傳。", "魯國焉取斯，爲語宓子賤。"]'),
('fe6e6167-d099-4875-9b0e-9075f747b5c1','三游洞','李石','宋','宋诗','song-poetry','','[]','危磴俯寒水，陰崖擘蒼烟。',96,'全唐诗/poet.song.116000.json','["危磴俯寒水，陰崖擘蒼烟。", "上開氷雪窟，下垂珠玉淵。", "何時雷斧手，拓此壺中天。", "自然渾沌竅，不受百巧鎸。", "地勝集靈氣，木石含清堅。", "三子果誰歟，流輩孰後先。", "我來叩玉扃，欲訪雲雨仙。", "呼龍龍未醒，日高貪睡眠。"]'),
('67197dc4-34be-47f7-b719-ec60429d5383','送王瞻叔總領','李石','宋','宋诗','song-poetry','','["\u897f\u6e56"]','吳山浮海青，蜀山粘雪白。',144,'全唐诗/poet.song.116000.json','["吳山浮海青，蜀山粘雪白。", "兩山相西東，渺渺萬里隔。", "一官誰卑高，博士省中客。", "歲月成後先，去住作分拆。", "先生何時來，六經尚遺澤。", "衣鉢肯付我，頗任弟子責。", "鬚髯襄陽翁，龍鳳出窟宅。", "典刑耆舊內，卿月耀詞伯。", "歸路入西湖，官梅已堪摘。", "好將軟紅書，博此千頃窄。", "夷吾王郎孫，江左書竹帛。", "臨風失驚呼，看刷九霄翮。"]'),
('3f430ffb-4517-4c87-9265-837743954645','題王氏欵竹亭','李石','宋','宋诗','song-poetry','','[]','夏蟲不知氷，朝菌不見月。',96,'全唐诗/poet.song.116000.json','["夏蟲不知氷，朝菌不見月。", "吹息天地間，隨分了寒熱。", "誰爲欵歲晚，久久媲清節。", "君家小令君，千金僦別業。", "不殊山陰宅，孫子今幾葉。", "勝取三百廛，共坐六十劫。", "春林扇溫風，夏簟落蒼雪。", "重來得更僕，千偈不須說。"]'),
('03d5cb99-98cd-463f-af8b-28307754cad5','湖嶼','李石','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','我昔泛洞庭，白波大如屋。',120,'全唐诗/poet.song.116000.json','["我昔泛洞庭，白波大如屋。", "水天兩相際，渺渺浸坤軸。", "小舟掀簸中，嘔眩篷底伏。", "忽然得島嶼，便欲縋船宿。", "西歸收驚魂，且濯泥土足。", "東湖一席地，江脈自絃蓄。", "烟雨相吐吞，几席染湖淥。", "汀洲紅白花，游泳雜鳬鶩。", "橫流溢四海，未暇較吳蜀。", "駭我時世情，風波戒平陸。"]'),
('9f060c3e-3a0a-41ce-a2e1-f8bacd187309','海山堂','李石','宋','宋诗','song-poetry','','[]','海水際天水，海山蔚空青。',120,'全唐诗/poet.song.116000.json','["海水際天水，海山蔚空青。", "萬里供遠目，隨處來戶庭。", "庭中森紫翠，戶內含虛明。", "澄波汲引入，螺黛疊甃成。", "空光集雲氣，岑碧延日星。", "逍遥等一物，大小隨所經。", "高霞渺三韓，衆水涵四溟。", "仙馭來何遲，上天跨鯤鯨。", "用意敢自隘，萬慮凝秋清。", "夙緣有悟契，矯首鴻鵠征。"]'),
('978ba293-6cc3-4e50-9d28-e9cc0c9232e0','蓋公堂','李石','宋','宋诗','song-poetry','','[]','林靜有集鳥，水濶多潛魚。',120,'全唐诗/poet.song.116000.json','["林靜有集鳥，水濶多潛魚。", "未能急期會，乃更談清虛。", "吾家柱下史，不讀城旦書。", "偶挾一語契，到官十日初。", "僊人氷雪容，訪我雲霞居。", "掃地蔭修竹，引水澆芙蕖。", "吏最果不足，丞負良有餘。", "深文到穴鼠，百巧呈山狙。", "從今結繩內，只可禁網疎。", "雖非膠西室，有此指南車。"]'),
('2068d766-1704-4742-8aaf-e44280275e66','仙巢','李石','宋','宋诗','song-poetry','','[]','仙人九天上，驂鸞紲飛虬。',120,'全唐诗/poet.song.116000.json','["仙人九天上，驂鸞紲飛虬。", "飄飄紫霄御，下作人間遊。", "二十四洞天，海上橫十洲。", "乾門鑿井絡，丹梯雲氣浮。", "中有三仙山，璫珮鳴琳璆。", "羣仙各分化，一笑芳菲留。", "我作招仙詩，披風上巢樓。", "仙鳥銜玉書，仙花拂人頭。", "手挽北斗柄，揖取銀河流。", "六合正泥滓，一洗蒼生憂。"]'),
('183f4462-acba-4746-817c-1c76ed246f7e','魚相忘亭','李石','宋','宋诗','song-poetry','','[]','通塗合西南，達人戒同異。',120,'全唐诗/poet.song.116000.json','["通塗合西南，達人戒同異。", "二魚各自魚，是魚豈有二。", "濶處海茫茫，波濤適相戲。", "笑我湖上亭，鱗鬣紛族類。", "情知我非魚，此意魚或是。", "欣然得所適，相見不相遇。", "魚行我無心，我得魚亦遂。", "藻荇披秋光，水與天嫵媚。", "明月貼湖心，照見魚不寐。", "我琴無殺聲，螗蜋勿余忌。"]'),
('11f42313-b102-487c-9da5-e34686692273','九日遊天竺','李石','宋','宋诗','song-poetry','','[]','霞影塔觜紅，嵐光佛頭綠。',144,'全唐诗/poet.song.116000.json','["霞影塔觜紅，嵐光佛頭綠。", "沙明疎柳外，尋路遶湖曲。", "遠客誰與俱，斯遊未爲獨。", "佳處心自領，未易語童僕。", "應接敢憚煩，山水相追逐。", "此間有魚鳥，怪我來不速。", "都城無閒官，旬謁廢休沐。", "幸茲九日臨，及此秋氣淑。", "醺酣豈無分，登眺寧免俗。", "起行九里松，試插一枝菊。", "西風莫欺客，破帽雙鬢禿。", "未敢醉向人，藕泉潄新馥。"]'),
('785b8e42-8166-4a11-9cd6-ffe0f3f58bd5','秋曉','李石','宋','宋诗','song-poetry','','[]','床頭窗眼白，秋曙溜以光。',96,'全唐诗/poet.song.116000.json','["床頭窗眼白，秋曙溜以光。", "暗蛩亦念曉，唧唧話夜長。", "披衣看天東，誰與搴扶桑。", "急風吹雲翳，高樹摇青蒼。", "疎疎沍寒蕊，散作菊雨凉。", "此景豈虛屬，老火候已藏。", "一室清浄緣，竹陰覆縑緗。", "手拊霜雪枝，隠几待衆芳。"]'),
('987ab62d-342a-47af-aefd-1bb6fc2cba55','送范至能制置','李石','宋','宋诗','song-poetry','','[]','孔子不到秦，右軍念西岷。',156,'全唐诗/poet.song.116000.json','["孔子不到秦，右軍念西岷。", "劍關鐵嶺江，與世隔紅塵。", "天亦惜祕境，我豈世間人。", "天上紫微郎，筆端演絲綸。", "跨象桂林郡，騎鯨芙蓉津。", "五嶺與三峽，緣雲躡星辰。", "憶公玉帳初，草木生華春。", "豢龍赤城家，長生定前身。", "扁舟載西子，五湖浮海濱。", "莫作去來想，雪山輕重均。", "况從尺一招，甘泉問鬼神。", "廟謨蓍龜舊，鼎味桃李新。", "虞衡備編載，我亦願卜鄰。"]'),
('7a949b9f-dcde-4285-a4f9-25fa89d2a992','送楊德源','李石','宋','宋诗','song-poetry','','[]','葛楠合翠蓋，上有菩提坊。',120,'全唐诗/poet.song.116000.json','["葛楠合翠蓋，上有菩提坊。", "大江僅一線，風動雲氣祥。", "地靈生俊傑，醖釀成文章。", "墨池子雲家，在蜀無他楊。", "君家好兄弟，接武遊名場。", "我昔夢見之，青衫水仙郎。", "修廉貫白日，孝義感雨暘。", "官滿喜可賀，綵衣得升堂。", "遲君臺閣歸，侍立香案傍。", "寄書問衰疾，老矣慰蒼浪。"]'),
('42afc93d-8c22-4d78-8dff-1b517fc97c8d','謝馮濟遠惠端硯','李石','宋','宋诗','song-poetry','','[]','學道本屢空，所積豈爲貧。',180,'全唐诗/poet.song.116000.json','["學道本屢空，所積豈爲貧。", "我生無長物，有輒恐累身。", "挾塊公子伯，陶土帝者仁。", "可惜水玉姿，下與瓦礫親。", "吾子泮林舊，文采含青春。", "江湖挹餘波，謂此席上珍。", "方正自溫潤，玉德如其人。", "潦倒竟何用，厚德山岳均。", "愧非筆札才，不堪演絲綸。", "三召已三逐，琬琰甘猥塵。", "抆拭置前列，濯以天漢津。", "斯文儻未喪，六經要鋪陳。", "大易伏羲祖，春秋丘明臣。", "琢磨三益友，几案增日新。", "定非注蟲魚，與世書鳳麟。"]'),
('4fc7ea5e-c0bc-4d25-9b1a-14a08a2cb771','蜂蟻','李石','宋','宋诗','song-poetry','','[]','乳蜂十蟻圍，小蜂兩翼弱。',216,'全唐诗/poet.song.116000.json','["乳蜂十蟻圍，小蜂兩翼弱。", "三蟻掣蜂首，四蟻曳蜂脚。", "三蟻相後前，捍圉行且却。", "蜂母正憑怒，有蠆無敢作。", "相視母子心，如被蛇豕虐。", "蟻行蜂母隨，衆力豈易撥。", "彼嫌大樹小，且幸神龍涸。", "自謂無誰何，利吻得所嚼。", "蠅虎伺其便，儇然才一躍。", "中道取蜂去，意外可遥度。", "蟻羣不自量，出力互相搏。", "蠅虎跳擲高，細碎紛迸落。", "餘黨尚未解，尺寸歸路邈。", "三帥本伐戴，反爲鄭所掠。", "孟明意取鄭，二殽遭晉薄。", "世路蜂蟻羣，巇險逞攘攫。", "向來騶虞仁，未似蟻虎惡。", "吾詩儻可佩，捧腹聊一噱。"]'),
('d278118c-5222-4871-bdfd-99682d13a76f','次蒲尉韻','李石','宋','宋诗','song-poetry','','[]','斯言誠虛筌，遮眼漫盈紙。',168,'全唐诗/poet.song.116000.json','["斯言誠虛筌，遮眼漫盈紙。", "冷暖當自知，此味如飲水。", "誰肯落驕榮，還來共枯悴。", "待渠轉船頭，著力與風值。", "最憐氣炎炎，可上不可下。", "青天與白日，信有覆杯夜。", "空林鳥雀喧，村巷牛羊窄。", "童子候簷楹，喜此扣門客。", "客來踏青苔，曳杖入林薄。", "只許老梅官，謂我門無雜。", "我貧無娛客，相視笑不止。", "向來諸阮間，容我亦與此。", "陶然見天真，客亦憐我醉。", "罷休明復來，酒賤肯勤置。"]'),
('72aa459f-d745-402a-a481-1b9a5371a56b','贈楊教授','李石','宋','宋诗','song-poetry','','[]','讀書要身榮，得祿爲親喜。',132,'全唐诗/poet.song.116000.json','["讀書要身榮，得祿爲親喜。", "端知絳帳華，乃在綵衣裏。", "冷官多澹泊，有道足甘旨。", "登堂四壁餘，發帙照案几。", "尚有老孟光，環以三穉子。", "一笑扶鶴髮，相見折屐齒。", "出門顧諸生，正事歌錫爾。", "生朝適餘暇，湯餠慶弧矢。", "衆客集清辰，好語塞兩耳。", "我有海上方，剩泛盃中蟻。", "永爲萱堂壽，勝飲菊潭水。"]'),
('904ce44f-2cfc-4950-b85e-c0d1d5b64dcb','送陸務觀','李石','宋','宋诗','song-poetry','','["\u897f\u6e56"]','近別已不易，遠別良更難。',240,'全唐诗/poet.song.116000.json','["近別已不易，遠別良更難。", "莫作遠近想，便覺宇宙寬。", "聚散與出處，等以道眼看。", "君去便鄉國，我留爲親懽。", "吳蜀視旅亭，隨處寓以安。", "誰能詫凡見，鷃翮齊鵬摶。", "是家好門地，羽儀耀朝端。", "竹西丞相客，冀北幕府官。", "清廟瑚璉器，仙人承露盤。", "談笑翰墨香，芳佩雜茝蘭。", "雪山笏拄頤，碧玉高巑岏。", "鋒車促收召，買舟繫江干。", "瞿塘浪粘天，怒濤駕風湍。", "西湖軟紅路，塔級層旃檀。", "還來捧御床，剖腹呈琅玕。", "前修席玉鉉，舊事追金鑾。", "潦倒困災患，名節空彫殘。", "不假子夏蓋，敢彈貢禹冠。", "隔濶如昨夢，道義期歲寒。", "日邊一紙書，時煩問加餐。"]'),
('1a4f7b6f-c8fb-4304-8404-d7f84aa1c9c6','楊德彝立春日携詩遠訪次韻','李石','宋','宋诗','song-poetry','','[]','鞭笞土牛子，鼓舞勾芒神。',156,'全唐诗/poet.song.116000.json','["鞭笞土牛子，鼓舞勾芒神。", "初開一歲籥，已有五日陳。", "胡爲松桂老，强逐桃李新。", "自言草玄客，頗愛鄭子真。", "雖云公卿貴，虛名竟成塵。", "况我已三黜，素志無一伸。", "遂去田舍畔，得與漁樵親。", "奉母缺祿食，菜飽不敢嗔。", "夫君亦人子，等是我輩人。", "青鞋裹白足，烏帽遮長身。", "襟期訪鄭老，酒伴尋南隣。", "吾文天未拯，古道日以堙。", "登壇要先歃，更約明年春。"]'),
('23f0e245-8396-44ee-a541-98bbcb2f7948','直方大','李石','宋','宋诗','song-poetry','','[]','梧桐角可磨，江沙玉能錯。',120,'全唐诗/poet.song.116000.json','["梧桐角可磨，江沙玉能錯。", "由來剛强徒，未易勝軟弱。", "是在六二坤，對病可爲藥。", "吾生任天真，三者不自度。", "中年坐齟齬，出語遭擊搏。", "官居寄委蛇，晴窗傍林壑。", "泉乳發深竇，竹萌抱新籜。", "不習其在茲，玩爻情所託。", "一字得一師，聖賢如可作。", "坐待韋編翁，爲我解禪縛。"]'),
('5ae64138-9caf-431f-8443-2c146c8972f8','石室','李石','宋','宋诗','song-poetry','','[]','來爲人所愛，去爲人所思。',144,'全唐诗/poet.song.116000.json','["來爲人所愛，去爲人所思。", "君看文與高，慈惠蜀之師。", "至今窟中像，凜凜建立時。", "知非伯有室，定是桐鄉祠。", "蜀人愛二公，遠與千載期。", "其間幾灰劫，付與一炬吹。", "保此歲崢嶸，不動山四維。", "東家好鄰里，豈任惡少窺。", "祠前二古柏，外乾中不萎。", "勿作剪伐想，恐是神明遺。", "可憐牆壁間，峩冠劍拄頤。", "烈士不平氣，好在淮西碑。"]'),
('a51692ea-647e-47fd-ad17-5529575c537e','憂旱','李石','宋','宋诗','song-poetry','','[]','清和氣始交，候火未可熾。',120,'全唐诗/poet.song.116000.json','["清和氣始交，候火未可熾。", "雨師偶失職，焰焰使人畏。", "東湖冷如氷，捨此誰止沸。", "猊吻呀不吐，濁泥點枯翠。", "農田不難料，焦灼凜生意。", "西南有重屯，百萬方振臂。", "自今數秋成，一飽儻可冀。", "蛟龍卧慵懶，朱鳥誇羽翅。", "吾生老文園，肺渴不自慰。", "安得挽天河，併爲洗兵氣。"]'),
('bb8d1330-e672-492e-85a2-a1f5dc78a4fa','送王郁教授','李石','宋','宋诗','song-poetry','','[]','陰山多風埃，白日下雨雹。',144,'全唐诗/poet.song.116000.json','["陰山多風埃，白日下雨雹。", "君子何必陋，士氣見淳樸。", "巴江亦能騷，蘭陵善爲學。", "斯文隨所化，後輩仰先覺。", "褐衣懷美質，隠隠含山璞。", "先生來何遲，絢秀待追琢。", "板輿行不難，雙鴈度雲邈。", "未嫌一簞蔬，頗勝五鼎渥。", "教人此其本，何異墊巾角。", "我昔困虀鹽，爲子得妙斵。", "王明躬孝治，正要夔典樂。", "小試臺閣資，還來侍經幄。"]'),
('51526379-c8a9-42d9-8db6-16212070ba40','次牟朝佐見贈韻','李石','宋','宋诗','song-poetry','','[]','郡齋冷秋菰，飯客比僧供。',120,'全唐诗/poet.song.116000.json','["郡齋冷秋菰，飯客比僧供。", "如何虀鹽厨，便謂酒肉夢。", "此間百戰場，肥瘠較輕重。", "霜花氣未暖，氷澌硯含凍。", "窗梅眩書燈，厭聽曉角弄。", "鄉心競節物，椒盤已可頌。", "一堂元祐師，翠竹忍留鳳。", "取材有成約，浮海誰與從。", "翻然著鞭先，逸足未易鞚。", "他日仇池書，爲記小有洞。"]'),
('7d48282b-e8dc-4080-9567-208563cf8878','芝草','李石','宋','宋诗','song-poetry','','[]','邊上秋風生，衆芳感蕭瑟。',144,'全唐诗/poet.song.116000.json','["邊上秋風生，衆芳感蕭瑟。", "何由九地底，一氣回暖脈。", "官居類僧坊，忽有芝草坼。", "駢跗間紅紫，合蓋暈黄白。", "秋菌苦爭氣，渠自凡眼窄。", "此理豈人爲，信我匪天厄。", "年餘竊邊廩，菜飽固不擇。", "謬政鬼所笑，敢望神意格。", "山中合歡桃，隴上六歧麥。", "一年獲三瑞，助我動行色。", "歸來及受釐，藉口緩誅責。", "從今歸商山，舉手謝樵客。"]'),
('8c31175f-79ec-4840-84db-be7304e38478','次范宰韻','李石','宋','宋诗','song-poetry','','[]','三仙白雲鄉，地與人境異。',204,'全唐诗/poet.song.116000.json','["三仙白雲鄉，地與人境異。", "金巵老翁泉，玉盤秋水芰。", "誰歟肯下食，三仙入夢寐。", "一笑謂我言，隨處類投畀。", "蟆頤霜雪山，危步踏森翠。", "山間多君子，一飯豈易致。", "詩書寬褐姿，曾何問名位。", "家傳元祐學，口語自嫵媚。", "頗識李夫子，一官若無意。", "善惡政亦殊，天心各緣類。", "大哉聖人經，春秋不書瑞。", "但得好麥禾，風雨煩筆記。", "屢書不一書，金玉文彩被。", "物物胡爲來，根荄異形氣。", "便欲獻天子，明時乞宣示。", "斯文儻有作，士子歌既醉。", "我亦採民言，請付圖牒吏。"]'),
('5a698d1b-2fee-42d5-99e9-b6105327e617','嚴一飛惠余一唯圖書贊其上甚佳石更名忠恕圖置之座右以爲居官奉母之規再用眩字韻','李石','宋','宋诗','song-poetry','','[]','善水沃沸焦，善藥調瞑眩。',120,'全唐诗/poet.song.116000.json','["善水沃沸焦，善藥調瞑眩。", "吾豈斯人徒，屏開慈母面。", "丹青解人意，二字出素練。", "孝哉耘瓜子，傷根豈所願。", "升堂致一唯，出門成兩見。", "遂令李老書，不入韓非傳。", "吾家桃李園，力行未敢倦。", "明知政事拙，稍覺言語賤。", "四科定誰先，袖手氷入硯。", "會請無言師，寬處著方便。"]'),
('7b0ce9d6-f131-4de4-9c1a-6dd30b146ad3','覓德醇菊花','李石','宋','宋诗','song-poetry','','[]','春秋書不雨，十日九日乾。',108,'全唐诗/poet.song.116000.json','["春秋書不雨，十日九日乾。", "向來陳菊根，半掃黄葉殘。", "施施蒼松獨，耿耿秋竹單。", "仙官轉物手，半畝不作難。", "芟籬扶弱幹，團翠蒙朱欄。", "一株萬寶釘，風露鳴珊珊。", "兒輩凡眼窄，詫作舉首看。", "折君清霜枝，照我秋水寒。", "年饑學辟穀，準擬充朝餐。"]'),
('e07dad7a-6abb-4af1-b0ad-4ff7764f78cb','九日同胡子遠携三子以重陽能插菊花無分韻','李石','宋','宋诗','song-poetry','','["\u897f\u6e56"]','去年萬里客，仰看秋雲孤。',120,'全唐诗/poet.song.116000.json','["去年萬里客，仰看秋雲孤。", "今年返南畝，頗復懷西湖。", "今日果何日，淑氣天四隅。", "憑高送遠目，風景未覺殊。", "試問先生菊，何如朝士萸。", "莫作去來想，渺渺同一區。", "久客負隣里，置酒煩招呼。", "起登舍畔山，山色定有無。", "澹烟與晴日，醉眼相模糊。", "我老腰脚頑，健倒須兒扶。"]'),
('62c2b6a6-a68f-4c49-b2c8-31afe699cc18','題黄筌牡丹花下貓','李石','宋','宋诗','song-poetry','','[]','紅英艷雲霞，綠葉足風雨。',96,'全唐诗/poet.song.116000.json','["紅英艷雲霞，綠葉足風雨。", "牡丹花未開，生意妙誰主。", "丹青强摸索，閉目想未睹。", "天巧非人工，神凝志良苦。", "竦然花下貓，蜂喧聒如鼓。", "醉眼不成睡，花氣日亭午。", "黄生與我意，盤礴一轉語。", "我老花無情，鉛粉付兒女。"]'),
('0c624835-bcae-4814-a194-b47c984eb3bb','次韻宇文守携酒相訪','李石','宋','宋诗','song-poetry','','[]','天雷裂山崖，驟雨翻盆盎。',144,'全唐诗/poet.song.116000.json','["天雷裂山崖，驟雨翻盆盎。", "田畝懷政最，草木知治狀。", "使君富經術，暫屈乘一障。", "黄堂燕清香，比屋醉春釀。", "文章出指授，學校均幼壯。", "獨我困樊籠，老矣神不王。", "尋醫詩未免，勉力追絕唱。", "滔滔原夫輩，感此舍人樣。", "旌旗出幽扉，俎豆忽迂訪。", "小摘情益親，村舂未忍相。", "蜀叟初不識，漢墨拜奇貺。", "從今門張羅，一任臺無餉。"]'),
('6e4c1ad9-1dd8-4784-a87f-798b476b974b','次張益州芝草十二韻','李石','宋','宋诗','song-poetry','','[]','紹興己卯武成廟，廟殿之棟三秀芝。',320,'全唐诗/poet.song.116000.json','["紹興己卯武成廟，廟殿之棟三秀芝。", "學官奔走暨多士，日遶百匝不暫離。", "欲奏九重望恩幸，寒餓水火如切肌。", "先期到堂白宰相，宰相曰可甚易爲。", "樂工伶倫飾金玉，擬薦清廟裁歌詩。", "石時官忝博士職，豈敢立論超等夷。", "曰此五行金沴木，木不曲直嘗聞之。", "將軍鷹揚兆異氣，弄兵往往憂潢池。", "矧今裕民民未裕，聖慮日軫天下饑。", "斯言一出自拭目，再召再逐彌歲時。", "山東山西將與相，一天雨露均無私。", "喜聞謀帥用鄉士，乖崖以來無此奇。", "目之所覩世有異，口不敢言人更知。", "頃年喋血岷峨下，啟此厲階端自誰。", "種芋從今我田喜，漚麻却得吾水滋。", "中和薰蒸感瑞物，雪山增重陰雲披。", "昔人佳政喜傳授，便謂子産勝子皮。", "江南諸子識我語，帳下未忍驕羣兒。", "商山一曲似可作，出處恐笑山翁癡。", "不如去學赤松子，掉舌三寸爲帝師。"]'),
('44b4db1a-5f1d-457b-89db-015a44c7e1c4','山舫','李石','宋','宋诗','song-poetry','','[]','君家屋中作山舫，開窗看山篷背上。',64,'全唐诗/poet.song.116000.json','["君家屋中作山舫，開窗看山篷背上。", "兩峯高並玉玲瓏，大孤小孤無此樣。", "主人釀酒書滿船，讀書飲酒酣且眠。", "應笑周郎赤壁下，龍驤萬斛風動天。"]'),
('60996498-f07e-4249-9bac-062314b64761','馮震野航','李石','宋','宋诗','song-poetry','','[]','蓬萊弱水三萬里，片帆風便一日耳。',128,'全唐诗/poet.song.116000.json','["蓬萊弱水三萬里，片帆風便一日耳。", "世間衆水集枯溝，鼃黽自誇河伯秋。", "况於平地鑿戶牖，此豈有水仍推舟。", "先生彈鋏太不惡，昔人野航今改作。", "明知此意不爲魚，船頭船尾千卷書。", "笭箵活計大如斗，欲駕雷電凌空虛。", "白波漲天須少待，小劫未遲蒼鬢改。", "安排去作踏浪兒，幾度桑田變成海。"]'),
('a9de0431-5aec-499c-8c36-5cd370379d37','送僧南遊','李石','宋','宋诗','song-poetry','','[]','天下香火如東林，雷劉勝迹猶可尋。',112,'全唐诗/poet.song.116000.json','["天下香火如東林，雷劉勝迹猶可尋。", "阿師跳出矮屋下，萬里抱被雲水深。", "汝家老演舊行處，江梅樹樹前時吟。", "可憐此老今已矣，門戶久冷懷語音。", "去年送圭今送汝，演子兩虎不易擒。", "吾詩最慳亦何用，且爲向來衣鉢重。", "逢圭問我强健時，猶抱黄經戀虀甕。"]'),
('8c17bbe5-a37f-4327-be04-ebbc2a8ca2c1','次韻何思召求中江縣學額','李石','宋','宋诗','song-poetry','','[]','九州多士各有貢，大小之物隨土宜。',272,'全唐诗/poet.song.116000.json','["九州多士各有貢，大小之物隨土宜。", "養材學校此其本，背本逐末寧不悲。", "偏將土木奉釋老，盡室奔走愚無知。", "君子居鄉有宓賤，小人願學如樊遲。", "聖門二者今戰勝，文星不用天盤推。", "一朝化出孔子廟，唾手如有神明司。", "文翁以來節度府，羽翼此邑天西維。", "春秋俎豆列二祀，晝夜几硯嚴十師。", "荀卿許從異戶入，子貢只得肩牆窺。", "我生一官五講席，所至凍雀栖寒枝。", "自從上庠吏外學，行德自謂心無欺。", "眼看旄頭拂紫彗，左文右武今何時。", "塗侯居鄉足領袖，金橐相與傾其私。", "自聞盛事喜欲舞，出力敢後吾人期。", "黄庭細書不足道，籠鵝尚可尋羲之。", "澹臺斬龍由搏虎，書成有似二子爲。", "高山仰止不無意，鵬翼九萬雲天垂。"]'),
('52b901eb-6f3d-498b-9d9c-488a4f34deb4','王家亭池','李石','宋','宋诗','song-poetry','','[]','涪川勝處城之西，萬松直上王家池。',112,'全唐诗/poet.song.116000.json','["涪川勝處城之西，萬松直上王家池。", "池心有亭無四壁，五月菡萏生淪漪。", "向來城中望山上，但見一抹深黛眉。", "却從山中望諸處，雲霧平野光參差。", "飛鴻羣往山數點，陣馬萬匹江東馳。", "眼前景物費酬答，中有隠几無言師。", "題詩他日要人識，君家有叔良不癡。"]'),
('00868083-6226-4ce4-b789-34ffb1f82e7c','次韻唐立夫永川五柳堂堂李齊年所建十年間三易名立夫作令爲復之','李石','宋','宋诗','song-poetry','','[]','我與李侯初不熟，但聞弦歌政聲速。',160,'全唐诗/poet.song.116000.json','["我與李侯初不熟，但聞弦歌政聲速。", "永川鷄犬數山外，迄今語言猶可錄。", "向來官舍卜清疎，把酒橫琴僅容足。", "眼前可無起予者，故作斜川著行錄。", "不妨奄有靖節名，此堂岌岌柳英英。", "易名伐樹公則去，名尚可復柳易生。", "唐侯初來理前事，收拾神名還舊地。", "坐令軒冕爭奪心，各有田園蕭散意。", "古人陳迹那復論，丈夫志氣高入雲。", "因知特起豪傑士，不待西伯還明君。"]'),
('7f785b90-a088-4e78-9cdc-8162b1d1f54b','張紹賢以詩索佩刀次韻復還之','李石','宋','宋诗','song-poetry','','[]','喜不至流怒不悲，句中銛鋒解人頤。',96,'全唐诗/poet.song.116000.json','["喜不至流怒不悲，句中銛鋒解人頤。", "氷霜凜凜笑一吷，三尺有喙金玉詞。", "二惠肯來但獨步，明光殿中文繡具。", "便當携此上青雲，天子方深南北慮。", "吾今老矣君可思，吹毛之珍何所施。", "和詩反刀三歎息，莫把神槌困鈍錐。"]'),
('79090184-e01a-43ca-ae95-126bf40757ac','題金馬碧鷄神祠','李石','宋','宋诗','song-poetry','','[]','持節使者來自天，玉皇遣問金碧仙。',128,'全唐诗/poet.song.116000.json','["持節使者來自天，玉皇遣問金碧仙。", "蜀山嵯峨九折外，瓊樓絳闕迷風煙。", "騑騑蹴踏長楸道，喔喔下鳴芝草田。", "漢家一瑞恐難致，殺人自要身長年。", "麒麟鳳凰不知愛，僊物未忍隨拘牽。", "至今滇昆水含怒，怒迸海脈浮平川。", "資中男子文章伯，執筆金鑾殿中客。", "碧鷄飛去却飛來，此地遂爲金馬宅。"]'),
('a0082b8b-c924-4414-8fbc-09256783a126','謝楊壽卿惠香木拄杖','李石','宋','宋诗','song-poetry','','[]','夜郎溪中七香木，長身一握如紫玉。',112,'全唐诗/poet.song.116000.json','["夜郎溪中七香木，長身一握如紫玉。", "向來蠻村已自奇，恥與龍涎鬭餘馥。", "誓將膂力奉君子，度越山巖走窮谷。", "夫君得此不自珍，要當助我扶衰獨。", "憶昨與君騎竹馬，健力隨羣走黄犢。", "看看四十老形具，此物胡爲苦催促。", "世間行險豈吾徒，且卧方舟同結足。"]'),
('1c6d8f9f-71fb-441d-8888-33eb8809349f','三藏梨','李石','宋','宋诗','song-poetry','','[]','沉黎廳前三藏梨，老虎鬚牙龍甲皮。',96,'全唐诗/poet.song.116000.json','["沉黎廳前三藏梨，老虎鬚牙龍甲皮。", "我來與國惜喬木，尚幸出屋繁孫枝。", "春風千花玉葉碎，秋日萬子金圓垂。", "問禪誰是栢樹子，聽訟漫逐棠陰移。", "雪香樓頭終日坐，紙尾自書三百顆。", "他時若問相公槐，我爲改名羅漢果。"]'),
('25c5a49c-8eb3-49d8-a71d-82eff96b86b0','徐童子彈琴極聰慧詩勉其學','李石','宋','宋诗','song-poetry','','[]','髧如丫角垂兩耳，口誦黄庭調綠綺。',128,'全唐诗/poet.song.116000.json','["髧如丫角垂兩耳，口誦黄庭調綠綺。", "諸公拂榻乃肯留，疑是前時徐孺子。", "我琴掛壁久不彈，浙聲分作蜀聲看。", "但得古人指下趣，轉覺良工心事難。", "欣然過我同一笑，舊曲重聞如再少。", "咸韶本自鳳凰鳴，箏笛任誇蚯蚓竅。", "孺子孺子年更癡，十三大勝陶家兒。", "阿端不識六與七，隨分牽衣覓梨栗。"]'),
('ca2a9c7f-38ef-4ff8-bdf9-9511e6e72055','贈墨手道人寄晁子止即用子止韻','李石','宋','宋诗','song-poetry','','[]','夷門道人墨爲手，藝如巫咸日中走。',64,'全唐诗/poet.song.116000.json','["夷門道人墨爲手，藝如巫咸日中走。", "逢人便與墨模糊，西里自妍東里醜。", "不須更相邑中黔，面比烏鴉色未深。", "爲擡墨手高處問，我手何如君子心。"]'),
('d0f3e46f-05d3-4929-b156-42002fa66f6e','挽船','李石','宋','宋诗','song-poetry','','[]','羣兒生長輕江湖，上船下船誰使驅。',160,'全唐诗/poet.song.116000.json','["羣兒生長輕江湖，上船下船誰使驅。", "江牽百丈沙水澀，岸上風雪兼泥塗。", "下循枯葦鵝鴨亂，上控絕壁猿猱呼。", "可憐進寸得退尺，挽脚不住頭欲扶。", "均之兩兩窮性命，我自有罪非爾辜。", "二年學省一不補，天子幸赦憐其愚。", "一船放歸小如葉，滿載豈有海上珠。", "琴書之外求長物，去時未有來時無。", "爾曹憐我共努力，歸路尚遠天西隅。", "泊船且醉花柳岸，爲爾尚肯滿眼沽。"]'),
('7a2aa0b1-7aa0-4156-ac8c-250634a5d92e','喜雨謠','李石','宋','宋诗','song-poetry','','[]','春氷摇凍春水肥，小風卷沙梅雪飛。',64,'全唐诗/poet.song.116000.json','["春氷摇凍春水肥，小風卷沙梅雪飛。", "東皇勸人作耕織，天雨粒粒機中絲。", "田家喜說新年話，苔青映門竹枝亞。", "有錢輸官官不嗔，滿地黄金不論價。"]'),
('5fb74964-a8a4-42bd-a068-9e6708bdfca6','次韻趙彥膚柏梁體送張道錄','李石','宋','宋诗','song-poetry','','[]','烊銅作梁劍棧編，峽江百丈青雲緣。',160,'全唐诗/poet.song.116000.json','["烊銅作梁劍棧編，峽江百丈青雲緣。", "峽山鳥道飛翩翩，蜀仙自得壺中天。", "丈人口訣誰與傳，青城一炷心香烟。", "縈藤絡蔓紫翠牽，清河鍊師天上仙。", "玉華樓高瞰平川，白日下界黑鬼纏。", "帝曰汝往予詳延，鼎轉九丹書八篇。", "清風來翔明月前，夏日不暍冬不綿。", "青騾白鶴忘歲年，是家仙種張祖先。", "椒子紅熟丹浴泉，釀成白酒斗十千。", "先生日日貪醉眠，爲我寄語來日邊。"]'),
('10aefb11-a509-431e-9345-72780a076f3f','遊銅梁縣雲巖','李石','宋','宋诗','song-poetry','','[]','我來雲巖夏初吉，巖洞向晚開新蟾。',227,'全唐诗/poet.song.116000.json','["我來雲巖夏初吉，巖洞向晚開新蟾。", "晴空飄飄雨花坐，護此燕几垂飛簷。", "老僧閉門一榻外，但有瓶鉢雲火匳。", "人間日車手可熱，道上火繖官爭炎。", "不知此地蔭冰雪，崖花石蔓駢濃纖。", "傳聞仙人有蛻骨，玉塔未許窺幽潛。", "行人各走記名姓，浪費粉板相黐黏。", "不知蘇黄巖上字，端有妙處垂緗縑。", "至今巖泉瀉千仞，似與二老爭森嚴。", "斯游與子固不薄，一餉喜逐清賞兼。", "稽首林間古石佛，面目慈悲雄鬚髯。", "狐狸騎項鼠遶膝，蒼苔蘚剝侵裙襜。", "我願石佛須少忍，欺善怕惡神所殲。", "君不見邇來石佛勝銅鬼，會煮翁仲烹飛廉。"]'),
('1eb274b2-3588-431c-9bfa-e87baadcad32','余所藏李文才畫鶴甚奇偉歲久縑爛各缺一趾偶有善工爲補之','李石','宋','宋诗','song-poetry','','[]','高軒得意翔雲間，妙畫匿迹縑素殘。',80,'全唐诗/poet.song.116000.json','["高軒得意翔雲間，妙畫匿迹縑素殘。", "柱頭老丁留語後，兀兀無趾如叔山。", "不妨萬里戢六翮，顧步下啄芝田寬。", "方舟惜鶴並惜畫，一夔之足萬金價。", "莫將凡筆補丹青，謬作身輕一鳥下。"]'),
('391da965-7d20-4dde-8cda-15cb39d88bee','郭宰生朝','李石','宋','宋诗','song-poetry','','[]','汾陽家世郎官星，百里隠隠聞雷聲。',128,'全唐诗/poet.song.116000.json','["汾陽家世郎官星，百里隠隠聞雷聲。", "德人所至有別樣，不向尺箠求能名。", "上官嗔駡吏束濕，日下廩庾堆如京。", "此時桃李出談笑，溪邑井井山風清。", "東林香火遠公社，長官得暇來尋盟。", "雲間春茗試新瀹，月裏禪心須細評。", "今朝還有壽者相，松椿龜鶴紛喧爭。", "高人著意供一默，富貴浮雲雙眼明。"]'),
('ff1b9056-2e54-4dbc-bb5b-b478fcd4ffdc','夏旱','李石','宋','宋诗','song-poetry','','[]','四月旱火坤西維，湫潭百丈滄江湄。',144,'全唐诗/poet.song.116000.json','["四月旱火坤西維，湫潭百丈滄江湄。", "潭中老龍帝所御，偃蹇不任世俗羈。", "招呼頻費香火誠，去則甚速來何遲。", "炎官火傘日輪午，一塵不動天琉璃。", "火光之中興白霧，風伯鼓鞴雷奮椎。", "黑雲壓城白晝暝，倒瀉銀漢傾天池。", "帝勅九烏以震死，血飽龍吻紛淋漓。", "再拜謂龍曷少霽，龍與我職均有司。", "商霖儻可通帝夢，正直炯炯唯龍知。"]'),
('7b7d2085-5b63-41ed-b528-982ea1366c14','贈開元觀李法師','李石','宋','宋诗','song-poetry','','[]','射虎將軍鬚髮白，老作三茅洞中客。',64,'全唐诗/poet.song.116000.json','["射虎將軍鬚髮白，老作三茅洞中客。", "羣仙呼去問姓名，謂是前時李八百。", "天孫乞與雲錦衣，白日化爲仙鶴飛。", "赤城山下百花市，賣符賣藥沽酒歸。"]'),
('a0f77ee4-ee2d-4038-9275-60dc1c6172d4','放魚','李石','宋','宋诗','song-poetry','','[]','三年計日作放生，薄俸時分及魚鳥。',160,'全唐诗/poet.song.116000.json','["三年計日作放生，薄俸時分及魚鳥。", "別來湖山幽絕處，下者遨遊上輕矯。", "西歸短棹送春波，忍見長魚困縈繞。", "修鱗戢錦紛半破，健尾舒紅時一掉。", "不惟咫尺迷藻蘋，正恐須臾觜葱蓼。", "吾曹仁術隨所用，圉圉洋洋誰不曉。", "恥與雞蟲較得失，况乃牛羊分大小。", "只今命脫猛火燃，不用口銜明月皎。", "臨流祝魚從此去，彈指寃親一時了。", "要將頭角動風雷，未厭藏身且深渺。"]'),
('5d80d05e-87fc-46ec-b3e5-ae9b4a0d910a','周公禮殿','李石','宋','宋诗','song-poetry','','[]','蜀侯作頖錦水湄，先聖先師同此室。',256,'全唐诗/poet.song.116000.json','["蜀侯作頖錦水湄，先聖先師同此室。", "巍然夫子據此座，殿以周公名自昔。", "聖人兩兩如一家，均是周人先後出。", "想見東家中夜夢，猶與公孫同衮舄。", "斯文授受乃關天，不爲漢唐加損益。", "我時來視俎豆事，重是漢人斤斧迹。", "漢宮制度九天上，散落人間此其一。", "多因豐屋起戎心，獨此數椽綿歲歷。", "規模𡺑嵲東魯似，氣象縹緲西岷敵。", "竹松猶是斯干詩，風雨方知隆棟吉。", "雖然漢獻來至今，閲世已多駒過隙。", "中間豈無鳥鼠慮，妙斵不知難輒易。", "工師不揆亂如麻，敢向般門言匠石。", "詩書譬彼尚闕文，後學如何補遺逸。", "祖龍非意竊登牀，蝌蚪有心來壞壁。", "舊章僅在命如絲，誰勒吾詩勝丹漆。"]'),
('fefca395-1e27-4c39-a235-c05804a3fe03','禮殿聖賢圖','李石','宋','宋诗','song-poetry','','[]','成都名畫窟，所至妙宮牆。',242,'全唐诗/poet.song.116000.json','["成都名畫窟，所至妙宮牆。", "風流五代餘，軌躅參隋唐。", "其間禮殿晉畫爲鼻祖，未數後來鴻雁行。", "畫者果誰歟，或云名收人姓張。", "右軍問蜀守，墨帖求縑緗。", "乃知前輩人，不愛時世粧。", "范瓊杜措李懷衮，仙荒佛怪驅喝雷電筆意窺渺茫。", "不若收所畫，上自皮羽之服下至垂衣裳。", "盤古衆支派，帝霸皇與王。", "君臣分聖賢，有如虎豹龍鳳殊文章。", "視之若有見，日月星象空中垂耿光。", "聽之如有聞，銜牙玉佩鳴以鏘。", "三古以降歷今世，視聽所感猶一堂。", "乃知此畫自神品，碌碌餘子非所望。", "吾道久已屈，二氏爭頡頏。", "豈唯牧也見絀餘子下，而有公議老我雙鬢蒼。"]'),
('7bed611c-b341-45ed-ab74-4ace8ea6a74f','蝦蟆碚','李石','宋','宋诗','song-poetry','','[]','水晶宮中玉蝦蟆，多年栖息嫦娥家。',170,'全唐诗/poet.song.116000.json','["水晶宮中玉蝦蟆，多年栖息嫦娥家。", "忍饑不及一夜啗明月，天帝怒爾謫下三峽脚手猶爬沙。", "婪酣大肚飽清氣，但見瓊流珠液百尺垂唅呀。", "峽人只作泉水看，不知元和潄嚥猶是月之華。", "從來至味不可說，陸羽只作第四誇。", "可憐提瓶肥羜子，强飲百斛莫救肝膽邪。", "我聞老蟾之酥乃仙藥，能使風草化作黄金芽。", "何如閉口自潤澤，換爾醜質生角牙。", "會當騎爾却上月宮去，下看桑海渺渺凌蒼霞。"]'),
('98bf80b9-d769-42b1-acca-2a107d9b2ed6','題陰山七騎圖','李石','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','回巖客子賣墨人，諸孫賣筆筆有神。',128,'全唐诗/poet.song.116000.json','["回巖客子賣墨人，諸孫賣筆筆有神。", "墨翁已入蓬萊殿，筆孫有愧中書君。", "邇來小孫兼好畫，兩幅溪藤七匹馬。", "虎狼避路狐兔藏，朔風吹沙霜滿野。", "邛崍關頭大渡河，使君五馬千丈坡。", "獵將一圍看蠻走，醉敲銅鼓蠻踏歌。", "急收此畫人莫識，矍鑠之翁誇筆墨。", "不如再泛洞庭船，袖中一劍隨飛仙。"]'),
('cebeb8b9-7f95-439a-a356-80942258b6a1','問趙有方乞琴','李石','宋','宋诗','song-poetry','','[]','公子年時尚奇偉，大劍橫腰髮衝起。',128,'全唐诗/poet.song.116000.json','["公子年時尚奇偉，大劍橫腰髮衝起。", "自言學道晚有得，心靜無波古潭水。", "平戎萬卷喑不吐，蟠向胸中作宮徵。", "眼明慣識嶧陽材，手製教成古綠綺。", "人生會費幾兩屐，巧處才容一張紙。", "許多黑瘦肯忍饑，枵腹悲鳴聒人耳。", "公子公子贈我來，明珠白璧遭沉埋。", "我家老馬解仰秣，渠家煮鶴充枯柴。"]'),
('a8089230-b134-4601-8c31-0cbd63b5720d','宇文子友以詩來覓酒','李石','宋','宋诗','song-poetry','','[]','玻璃江深麥初熟，引水細舂比炊玉。',64,'全唐诗/poet.song.116000.json','["玻璃江深麥初熟，引水細舂比炊玉。", "老守齋鉢自有餘，端爲吾民憂不足。", "荔枝堂前紅數栽，倚樹讀書門不開。", "收麥入厨催釀酒，客問遣騎何時來。"]'),
('a41a66cf-e1ef-45d7-b9b8-d47ed35de889','彭州行邑道中','李石','宋','宋诗','song-poetry','','[]','四月少雨百草熱，山中小麥皆乾枯。',64,'全唐诗/poet.song.116000.json','["四月少雨百草熱，山中小麥皆乾枯。", "溪水不流牛缺飲，連耞未動妻典襦。", "布穀催耕鳩婦怨，早得一雨淋汝面。", "老夫枕書卧晚凉，農自忍饑官飽飯。"]'),
('4406772f-6bc3-4a84-a3a5-c6847381d469','贈楊尉送湫水','李石','宋','宋诗','song-poetry','','[]','天上妥雨水鳴渠，一龍任責固有餘。',128,'全唐诗/poet.song.116000.json','["天上妥雨水鳴渠，一龍任責固有餘。", "今年水來雨不集，彭民不及江中魚。", "以堰致水高百尺，靈湫在淵爍紅日。", "彭民怨龍不怨人，龍則有職誰之失。", "九峯仙官梅子真，豢龍有術龍不嗔。", "去年作堰今請湫，二者兼得蘇彭民。", "東湖別駕但捧腹，卧聽蕭蕭響疎竹。", "往來莫便輕泥塗，軟脚有酒爲君沽。"]'),
('db1dfd78-f9d6-4aa4-bcc2-036b20167c4d','東山行','李石','宋','宋诗','song-poetry','','[]','龍池山頭喚龍起，見說花開龍亦喜。',163,'全唐诗/poet.song.116000.json','["龍池山頭喚龍起，見說花開龍亦喜。", "喜將一雨洗山光，曉漲初分兩谿水。", "東山渡橋煙霞簇，山半亭臺艷桃李。", "入門一徑海棠花，紅玉爲枝霞作蘂。", "仙花自有龍麝氣，拂拂晴風香十里。", "木蘭高下色不同，青紫朱綠黄白紅。", "遊人隠映錦繡谷，山鳥動摇霜雪叢。", "我來酌泉弄花樹，花光正在水影中。", "君不見三碉城邊百草熱，渡瀘將軍不得歇。", "何似兩仙樵斧郎，一局坐忘春晝長。"]'),
('23fe8d99-9635-4794-8af7-c6564f33f4af','資聖看畫','李石','宋','宋诗','song-poetry','','[]','資聖名藍妙畫窟，前佛崢嶸連後佛。',64,'全唐诗/poet.song.116000.json','["資聖名藍妙畫窟，前佛崢嶸連後佛。", "栴檀級上金琅璫，五月寒風吹佛骨。", "我來看畫瞻仙容，丹青古殿開天龍。", "薝蔔花開日亭午，妙音破睡聞鳴鐘。"]'),
('54e82c71-f86d-4bbb-9e7d-90ccd447a04f','送叔規','李石','宋','宋诗','song-poetry','','[]','鳳臺却望桑麻川，殘僧孤客同一年。',144,'全唐诗/poet.song.116000.json','["鳳臺却望桑麻川，殘僧孤客同一年。", "我窮自取君更苦，只有布襪青行纏。", "松楠陰陰水邊寺，一餉欵尋香火緣。", "筆端落盡蔬笋氣，胸次不留荆棘田。", "窮冬衣褐露黑肘，半夜風雪寒詩肩。", "時於連牀乞被卧，睡到日午鐘魚傳。", "今朝別我眉色好，得得西謁騎鯨仙。", "自云老矣世塗熟，獨有此老無人憐。", "更須南去共舟楫，竹火江茶譚夜禪。"]'),
('96279401-db86-4b96-87f6-f99b5ffe914f','送范穎胄','李石','宋','宋诗','song-poetry','','[]','君之家爲夔龍氏，龍之威神爪牙利。',160,'全唐诗/poet.song.116000.json','["君之家爲夔龍氏，龍之威神爪牙利。", "豈肯因人下求食，拏攫風雷隨所嗜。", "問君世學今幾傳，翰墨諸仙侈名位。", "後來諸孫穎與路，元祐衣冠相整治。", "春秋大易蜀有師，我獲升堂時問義。", "江邊喬木殊未改，重來忍唾成都地。", "感君遺文遠相訪，凜凜高風今不墜。", "梅花道路寬作程，瓠葉杯盤同此味。", "少年赤手弄霜雪，想見倚門遲歲餽。", "還家莫道囊橐空，客子夜寒仍少睡。"]'),
('24fc70d3-e55d-47d5-b828-245225182dc0','送新趙宰','李石','宋','宋诗','song-poetry','','[]','身作涪江未歸客，更送行人出南陌。',112,'全唐诗/poet.song.116000.json','["身作涪江未歸客，更送行人出南陌。", "行人磊落高皇孫，桃李賨城看朱白。", "高才觸事無不爾，百里莫嫌民社窄。", "魯恭卓茂意何者，豈有居官名赫赫。", "不須打鴨驚鴛鴦，抵几疾書呼五百。", "阿奴公退在眼底，可以彈琴把書冊。", "此時尚及詩筒來，談笑千山萬山隔。"]'),
('2f37bdcf-bf38-46a5-a5d7-5129d0029a16','贈張聽聲','李石','宋','宋诗','song-poetry','','[]','人言鼻聽無如龍，聽不以耳乃反聾。',144,'全唐诗/poet.song.116000.json','["人言鼻聽無如龍，聽不以耳乃反聾。", "未若水母本無目，隔水響應相鳴雄。", "我持此理問張瞍，廢目任耳偏能聰。", "忍聞此聲亦憒憒，俗囂政在羣鳴中。", "枉將蟻動作牛鬭，妄遣蚊聚成雷公。", "昔人樂歸瞽其職，五音六律詩人矇。", "我琴三尺玉橫膝，欲廣舜孝歌時雍。", "游魚舞獸解人意，此意憂樂斯民同。", "瞍乎洗耳試一聽，莫似北客歌南風。"]'),
('2853a501-c968-4037-be77-771b1d6568e7','石經堂','李石','宋','宋诗','song-poetry','','[]','我來一登石經堂，從以諸生行兩廡。',384,'全唐诗/poet.song.116000.json','["我來一登石經堂，從以諸生行兩廡。", "諸生讀經半白頭，問以始終箝不語。", "我聞此經昔中都，郎中所隸乃其祖。", "邇來離亂已亡失，楷本僅能傳蜀土。", "蜀王閏位供掃除，獨此仍爲盛時取。", "爲將嚴鐍守重扃，護以繚垣崇邃宇。", "列之學官豈無意，不但闕文存夏五。", "大開明鏡別妍媸，時扣洪鐘諧律呂。", "後生不復事丹鉛，抵死唯知守藤楮。", "字音隨口妄蜺霓，點畫分毫謬魚魯。", "日月當天空委照，盲俗相欺紛莫覩。", "石經雖古奈爾何，人競傳今不傳古。", "行行矧肯捩眼覷，蘚剝苔封費撐拄。", "堅鑱僅免飽蟫魚，隘道爭來宅狐鼠。", "此間鄒人儻借問，爲問石經誰是主。", "憶昨敲門肆訶斥，幾度循牆誇傴僂。", "登登閣閣隠金槌，耳聒散空垂雹雨。", "蠟薰煤染連作卷，玉軸錦裝如束杵。", "豈無一物媚權豪，幾紙才堪博圭組。", "爾之所得固么麽，我則何由寬擊拊。", "一槌只作一字訛，訛至萬千那復數。", "石經之害此其大，縱有鬼神誰可禦。", "憶昔嘗爲博士官，首善堂中容接武。", "心知不是世間書，雲漢森然城百堵。"]'),
('f0b2a847-eefa-4cd3-b428-bd250ceea3c6','謝楊壽卿送雙鴨用香木拄杖韻','李石','宋','宋诗','song-poetry','','[]','我家羣雞真似木，君家雙鴨重如玉。',112,'全唐诗/poet.song.116000.json','["我家羣雞真似木，君家雙鴨重如玉。", "情知此物不敢烹，未忍戛羹求剩馥。", "傳聞深村水田裏，翠羽成羣蔽溪谷。", "喬仙兩舄不用多，尺紙長鬚慰幽獨。", "牆頭瓠壺舍下笋，喚作蒸鵝烹健犢。", "前時饞客錯歡喜，益水添薪費煎促。", "主人此外北窗風，飯後乳甌初睡足。"]'),
('ed4d3605-ff8b-4ef2-9fb1-4134f18ebc5b','舟中示開并寄圓','李石','宋','宋诗','song-poetry','','[]','三年獨客思親淚，灑作錢塘大江水。',193,'全唐诗/poet.song.116000.json','["三年獨客思親淚，灑作錢塘大江水。", "却乘此水得西歸，兩淚急收成一喜。", "庾公樓下江月春，拍手中流逢小麟。", "駸駸逼人出瘦骨，懔懔似我今長身。", "夜船燈火無乃是，猶似夢中論夢事。", "小鵬有翅未能來，獨學膺門想憔悴。", "一官外物等去留，來未足喜去莫憂。", "虀鹽敢有去國恨，菽水未免還家羞。", "峽江之人走雲雨，送船迎船聞疊鼓。", "君不見並舍紫薇郎，頗願生還見鄉土。", "我今歸來四壁空，兩窗萬軸南北風。", "杜門忍饑吾與汝，文字穮蔉祈年豐。"]'),
('f9fc36ff-33ad-431b-9a5d-a5b1931e8000','同韓子東賞牡丹','李石','宋','宋诗','song-poetry','','[]','嗚嗚曉角春風送，日日官身隨鳥動。',128,'全唐诗/poet.song.116000.json','["嗚嗚曉角春風送，日日官身隨鳥動。", "但知敲榜負佳辰，縱有芳菲難入夢。", "起尋北郭新雨後，愁見西山含雪凍。", "茅茨雖暖豈宜花，笑我此行真鑿空。", "向來洛下定真譜，只許姚花充物貢。", "只今老病陪少年，駑騎何能追駿鞚。", "便將花裓問天女，欲返田園尋二仲。", "此花含笑我不言，且插一枝風帽重。"]'),
('09d4cca8-a8e3-4544-afbf-d0a94dbcabf7','訪范師山房','李石','宋','宋诗','song-poetry','','[]','野步山圍合，春生物自欣。',48,'全唐诗/poet.song.116000.json','["野步山圍合，春生物自欣。", "溪聲如聽雨，松色欲摩雲。", "謝客推門入，支郎半坐分。", "林間携小隊，不敢散鴉羣。"]'),
('0c4a4aa3-efb3-4bbc-a1f4-eef11b03153b','送客','李石','宋','宋诗','song-poetry','','[]','送客川原路，憐渠田舍秋。',48,'全唐诗/poet.song.116000.json','["送客川原路，憐渠田舍秋。", "沙晴分野徑，林斷出溪流。", "馬瘦諸公後，鴟夷一醉謀。", "泮林無酒伴，頗爲老兵留。"]'),
('d3c62aa4-a95c-48b5-88fd-0ddcaf62779d','送勾龍教授','李石','宋','宋诗','song-poetry','','[]','廣漢川原迥，重江秋水多。',48,'全唐诗/poet.song.116000.json','["廣漢川原迥，重江秋水多。", "橋邊金作鴈，湖上酒如鵝。", "豈有雒書出，轉添巴字訛。", "泥塗滯行客，之子惜經過。"]'),
('f59fce4f-315c-493c-b37c-7281606594bc','宿鍾陽僧寺','李石','宋','宋诗','song-poetry','','[]','遠客來投宿，高人已閉門。',48,'全唐诗/poet.song.116000.json','["遠客來投宿，高人已閉門。", "白沙分遠水，紅樹带烟村。", "僻徑逢僧覓，登山見佛尊。", "清風惜秋稼，積雨掃雲屯。"]'),
('5ac2a5ba-0a26-4286-a466-3299b0c70cb1','謝劉韶美送酒','李石','宋','宋诗','song-poetry','','[]','別恨連湖海，驚心閲歲年。',48,'全唐诗/poet.song.116000.json','["別恨連湖海，驚心閲歲年。", "思君愁北闕，將母上西天。", "更酌鵝黄酒，如浮鴨綠川。", "不須憂九折，忠孝得雙全。"]'),
('ea52a632-de40-45c0-904d-716109376ce0','與程端卿相別峽中共繫船瀼東留一日','李石','宋','宋诗','song-poetry','','[]','宦路隨驚鵲，家山隔斷鴻。',48,'全唐诗/poet.song.116000.json','["宦路隨驚鵲，家山隔斷鴻。", "荒椽秋雨過，疎竹暗泉通。", "千騎尋城北，雙舟憶瀼東。", "我詩雖未好，聊爲使君窮。"]'),
('708a1fe1-82f9-4d24-a49a-b7abc49f9e1e','送程榮州被召二首  其一','李石','宋','宋诗','song-poetry','','[]','客向江南去，人言冀北空。',48,'全唐诗/poet.song.116000.json','["客向江南去，人言冀北空。", "賈生前席念，嚴助薦賢衷。", "畫舫摇澄綠，飛車近軟紅。", "舊遊應未改，尺紙問歸鴻。"]'),
('274a9c30-1a70-4550-8230-e848269dd09c','送程榮州被召二首  其二','李石','宋','宋诗','song-poetry','','[]','出處人情異，寒暄節物殊。',48,'全唐诗/poet.song.116000.json','["出處人情異，寒暄節物殊。", "脚輕貪遠路，眼轉隔重湖。", "近例占郎宿，頻年已守符。", "盛時人與地，尺一費招呼。"]'),
('f1aaca2c-aff5-4483-87c8-ec1e5c309b5b','感懷','李石','宋','宋诗','song-poetry','','[]','五日轉一候，百年能幾春。',48,'全唐诗/poet.song.116000.json','["五日轉一候，百年能幾春。", "雨苔堆碧色，風蘂委紅塵。", "神晤又何說，交疎莫强親。", "杜門誰是伴，杯酒聖賢人。"]'),
('087cfc46-a01c-4575-a02b-b04a5c7f77c5','眉州鹿鳴宴  其一','李石','宋','宋诗','song-poetry','','[]','大比周三歲，登名蜀一涯。',48,'全唐诗/poet.song.116000.json','["大比周三歲，登名蜀一涯。", "聖賢元祐學，父子老蘇家。", "類省登槐市，清秋艷桂華。", "生平晁董業，親策對褒嘉。"]'),
('9eefb698-1e78-4b27-af94-fa82ee083aac','眉州鹿鳴宴  其二','李石','宋','宋诗','song-poetry','','[]','六六成鱗吹，呦呦賦鹿鳴。',48,'全唐诗/poet.song.116000.json','["六六成鱗吹，呦呦賦鹿鳴。", "三仙隨勸駕，千佛要題名。", "俎豆初筵秩，衣冠習俗榮。", "例須煩舉送，我亦魯諸生。"]'),
('254e0402-5c8b-4f56-afdc-5a610599dcae','五更一點月照窗几以爲曉也披衣視之雪厚至尺許喜甚賦詩','李石','宋','宋诗','song-poetry','','[]','雪片成孤立，蟾華與共游。',48,'全唐诗/poet.song.116000.json','["雪片成孤立，蟾華與共游。", "從教驚蜀犬，曾是喘吳牛。", "蹲石依松瘦，寒溪映竹流。", "遥知明歲稔，携酒上南樓。"]'),
('11a3b72a-d695-4ce3-94e6-4dc8b5f1e3f6','諸葛菜','李石','宋','宋诗','song-poetry','','[]','郡圃耡荒雪，家山斸淺沙。',48,'全唐诗/poet.song.116000.json','["郡圃耡荒雪，家山斸淺沙。", "只今諸葛菜，何似邵平瓜。", "小摘情何厚，長齋氣自華。", "官烹與私炙，隨處即生涯。"]'),
('de17fbf7-15bb-476f-8039-52747663ab70','次韻馮涪州見寄','李石','宋','宋诗','song-poetry','','[]','寄語巴中客，頻頻鑷鬢霜。',48,'全唐诗/poet.song.116000.json','["寄語巴中客，頻頻鑷鬢霜。", "峽雲春夢遠，江月夜珍藏。", "才刃應多暇，詞鋒恨太剛。", "僧鄰雨花地，何日再升堂。"]'),
('f4a91c99-cbae-4ba7-a916-000b05fe523b','寄賈元鎮并問楊似賢譚德稱','李石','宋','宋诗','song-poetry','','[]','客子推移地，聞雞敢晏眠。',48,'全唐诗/poet.song.116000.json','["客子推移地，聞雞敢晏眠。", "酒樓春夜雨，柳岸早行天。", "龍卧風雷宅，蠶叢錦繡川。", "譚楊兩州教，記我別時年。"]'),
('909bacff-fad3-4227-8298-a592a192ae4a','題鹿頭關石鄉祠','李石','宋','宋诗','song-poetry','','[]','古戍經秋暮，危梯迸野泉。',48,'全唐诗/poet.song.116000.json','["古戍經秋暮，危梯迸野泉。", "鹿頭關上廟，驥足縣中仙。", "山疊疑無地，江寬欲放天。", "英雄今已矣，自喜慣風烟。"]'),
('2d32e609-ec2b-419e-9446-2b9e01005c19','題白塔古迹二首  其一','李石','宋','宋诗','song-poetry','','[]','境物三禪勝，叢林十里村。',48,'全唐诗/poet.song.116000.json','["境物三禪勝，叢林十里村。", "寺僧晨掃地，樵客夜過門。", "瑞像西山映，乾文北斗翻。", "名場薰竈突，悵望塔中尊。"]'),
('baa81b9c-2986-4fa0-9df3-f05c020aa880','題白塔古迹二首  其二','李石','宋','宋诗','song-poetry','','[]','塔倒峰巒影，鐘埋澗谷音。',48,'全唐诗/poet.song.116000.json','["塔倒峰巒影，鐘埋澗谷音。", "二賢苔像古，四虎竹泉深。", "炬火携歸路，經臺喚隔林。", "人頭連地脈，古迹備幽尋。"]'),
('a6e9da3e-565d-4a71-b883-8001263464a6','天彭行縣','李石','宋','宋诗','song-poetry','','[]','公館靜寥寥，園亭景物饒。',48,'全唐诗/poet.song.116000.json','["公館靜寥寥，園亭景物饒。", "溪光明短彴，樹影蔭危譙。", "山鳥忽雙下，池魚時一跳。", "主人王事簡，文酒日逍遥。"]'),
('94a1c0dc-1172-410b-bb7f-323188688a4e','過永壽縣','李石','宋','宋诗','song-poetry','','[]','驅馬上危坂，暮鞭摇客愁。',48,'全唐诗/poet.song.116000.json','["驅馬上危坂，暮鞭摇客愁。", "峯巒驚滿目，咫尺擬回頭。", "紅樹映野店，白雲藏縣樓。", "須知此北下，地底見豳州。"]'),
('1c2c9816-ec7a-4f7a-8fbb-34f421209478','謝勝老惠胡桃','李石','宋','宋诗','song-poetry','','[]','浮海黄池近，還山白雪高。',48,'全唐诗/poet.song.116000.json','["浮海黄池近，還山白雪高。", "禪如石佛樣，學带楚人騷。", "我欲懷金橘，師能遺木桃。", "釣魚船上客，此句可連鼇。"]'),
('89192408-2092-41ae-907c-4fe390bf3522','金山驛','李石','宋','宋诗','song-poetry','','[]','晚泊金山驛，風生玉宇秋。',48,'全唐诗/poet.song.116000.json','["晚泊金山驛，風生玉宇秋。", "荒苔蝕佳句，喬木惜名流。", "鼠穴飛泉入，蛛絲積雨收。", "何須嘆人物，華屋與山丘。"]'),
('f8e22258-be23-4d9b-913e-14d5e7144407','送澄師還昭覺','李石','宋','宋诗','song-poetry','','[]','遠出蒙霜雪，重來歷歲時。',48,'全唐诗/poet.song.116000.json','["遠出蒙霜雪，重來歷歲時。", "贈師拄杖子，似我簸箕兒。", "芳草隨西度，巖花向北垂。", "莫忘香一瓣，滄海白鷗期。"]'),
('e5431d8f-5757-4bad-9161-409b758b42bc','夢西曹夜直','李石','宋','宋诗','song-poetry','','[]','再任雖祠祿，多年本爲親。',48,'全唐诗/poet.song.116000.json','["再任雖祠祿，多年本爲親。", "青縑猶夢寐，綵服困風塵。", "老境人情變，韶華物色新。", "只堪携茗椀，禪觀對幽人。"]'),
('9c39f958-43ed-4be0-8873-3f0bf74f077d','雪二首  其一','李石','宋','宋诗','song-poetry','','[]','客宦成分戍，人誰笑牧蠻。',48,'全唐诗/poet.song.116000.json','["客宦成分戍，人誰笑牧蠻。", "三碉橫塞外，兩澗拆雲間。", "鳥與花爭樹，春隨雪入山。", "功名成索寞，何以慰親顔。"]'),
('8a184b99-d6ad-439a-ab15-4ddfe5a141fc','雪二首  其二','李石','宋','宋诗','song-poetry','','[]','歲事頻年惡，心知一飽難。',48,'全唐诗/poet.song.116000.json','["歲事頻年惡，心知一飽難。", "只愁無此雪，得句不言寒。", "酒薄何妨聖，梅清合進官。", "老兵憐我意，赤脚唱平安。"]'),
('38d88ada-63a9-4cfa-9ab7-7575e11e0aee','寒食','李石','宋','宋诗','song-poetry','','[]','夜泊依漁市，天寒問酒家。',48,'全唐诗/poet.song.116000.json','["夜泊依漁市，天寒問酒家。", "燼餘缸吐粟，凘合硯生花。", "月浸江妃冷，波喧海若誇。", "漂摇隨水宿，鳬雁寄生涯。"]'),
('e442c8bb-144b-4745-bf08-dc1610e1dac0','閒居二首  其一','李石','宋','宋诗','song-poetry','','[]','七歲投閒日，渾如未第初。',48,'全唐诗/poet.song.116000.json','["七歲投閒日，渾如未第初。", "牛衣困襤縷，鶴飯愧粗疎。", "聖有杯中露，朝無別後書。", "溫尋皆舊學，風雨歲時餘。"]'),
('213b9d04-c251-4f76-b44c-1c83bc849e26','閒居二首  其二','李石','宋','宋诗','song-poetry','','[]','吠畝三番聘，林泉一客逋。',48,'全唐诗/poet.song.116000.json','["吠畝三番聘，林泉一客逋。", "君方借唇吻，我自惜頭顱。", "日月松偕老，江湖橘可奴。", "昭文雖未鼓，洗耳即良圖。"]'),
('a42765f5-1341-43f8-916e-d8a78453be42','黎州鹿鳴宴','李石','宋','宋诗','song-poetry','','[]','聖化如時雨，吾門自教風。',48,'全唐诗/poet.song.116000.json','["聖化如時雨，吾門自教風。", "文翁來蜀郡，常衮在閩中。", "夔足無多用，鼇頭只獨雄。", "諸君携手上，名姓廣寒宮。"]'),
('660d3fd3-1ea6-4b89-a932-dd43a5b7d573','九日類試院雨中制司送酒關子二首  其一','李石','宋','宋诗','song-poetry','','[]','學省三年別，文闈九日同。',48,'全唐诗/poet.song.116000.json','["學省三年別，文闈九日同。", "登高遲麴糵，避濕到芎藭。", "田舍飄零後，江湖震蕩中。", "忍將憂國淚，滴向菊花叢。"]'),
('8f8da147-da73-4900-a25f-5d351001bef9','九日類試院雨中制司送酒關子二首  其二','李石','宋','宋诗','song-poetry','','[]','老去輕時節，憂來稔歲年。',48,'全唐诗/poet.song.116000.json','["老去輕時節，憂來稔歲年。", "黄花關上戍，青草渡頭船。", "望眼知誰屬，歸心只自憐。", "僅霑微祿在，未敢計良田。"]'),
('eff7c526-33e6-40f2-96c8-67ffeeb3527a','周參政惠書唁及亡兒開二首  其一','李石','宋','宋诗','song-poetry','','[]','顙馬非才具，蝸牛惜弊廬。',48,'全唐诗/poet.song.116000.json','["顙馬非才具，蝸牛惜弊廬。", "歲時甘伏枕，風雨阻來車。", "藥裹衣巾內，梅花酒盞疎。", "江湖慰寂寞，一紙故人書。"]'),
('91a5d095-293c-48c3-b124-f7998a1f3f97','周參政惠書唁及亡兒開二首  其二','李石','宋','宋诗','song-poetry','','[]','取士平軒鑑，吾兒死布衣。',48,'全唐诗/poet.song.116000.json','["取士平軒鑑，吾兒死布衣。", "招魂荒草墓，寃鬼泣松扉。", "推挽無遺力，擠排已覺非。", "存亡佩陳誼，舍此更誰歸。"]'),
('9520ad65-320d-4135-8102-e3beaee1d876','沉黎四首  其一','李石','宋','宋诗','song-poetry','','[]','民俗瀕蠻詔，邊城異土宜。',48,'全唐诗/poet.song.116000.json','["民俗瀕蠻詔，邊城異土宜。", "竹筒連水脈，板屋怯風吹。", "藥叟鴉隨噪，樵童虎不窺。", "愛山來九折，人笑此翁癡。"]'),
('03ddb36b-49e2-4119-be95-0cd92fc4e8ac','沉黎四首  其二','李石','宋','宋诗','song-poetry','','[]','蜀相披荒壘，唐人拓密林。',48,'全唐诗/poet.song.116000.json','["蜀相披荒壘，唐人拓密林。", "四川襟带重，六詔霧雲深。", "鹽米成民業，珠犀作吏箴。", "官閒無一事，閉閤念親心。"]'),
('e28b0f29-17dc-4140-bd27-57005a72449d','沉黎四首  其三','李石','宋','宋诗','song-poetry','','[]','古屋雲栖洞，深湖水拍橋。',48,'全唐诗/poet.song.116000.json','["古屋雲栖洞，深湖水拍橋。", "吏閒知學稼，民樂自歌樵。", "官監頻添牧，蕃商不費招。", "老夫便午睡，風惡任飄摇。"]'),
('96645cf5-ea42-442b-acd9-183f20de67f2','沉黎四首  其四','李石','宋','宋诗','song-poetry','','[]','九折山圍市，雙溪水浸田。',48,'全唐诗/poet.song.116000.json','["九折山圍市，雙溪水浸田。", "號風吹客袖，落雪舞蠻氊。", "塞上尋歸馬，波間畏跕鳶。", "此生隨所適，老去合乘邊。"]'),
('078d65b2-d016-48a9-8647-34aeb878a315','雙鶴','李石','宋','宋诗','song-poetry','','[]','積雨催寒早，江湖渺障川。',48,'全唐诗/poet.song.116000.json','["積雨催寒早，江湖渺障川。", "黄花到十月，白髮已三年。", "酒盡遲村餉，詩成得晝眠。", "低回看雙鶴，鎩翮欲摩天。"]'),
('f4e1dab9-ce99-420b-8d4f-61391b3987de','天彭受代遷靜正堂以代者未到漫興二首  其一','李石','宋','宋诗','song-poetry','','[]','客宦去未得，山風來不遲。',48,'全唐诗/poet.song.116000.json','["客宦去未得，山風來不遲。", "東湖霜後冷，北斗夜深移。", "老檜新翻葉，狂花故著枝。", "憂時恐無補，祇益鬢絲垂。"]'),
('2dd62597-798a-4c16-86dd-db1fab5ea666','天彭受代遷靜正堂以代者未到漫興二首  其二','李石','宋','宋诗','song-poetry','','[]','罷戍成遷次，投閒想故居。',48,'全唐诗/poet.song.116000.json','["罷戍成遷次，投閒想故居。", "風霜欺老大，書信卜交疎。", "黄葉頻供掃，青山炯自如。", "斯文身健在，歸及歲之餘。"]'),
('1296205c-2d8e-4b1b-bb08-2d392bb8c337','拌毫筆','李石','宋','宋诗','song-poetry','','[]','管城無別派，毛族競分支。',48,'全唐诗/poet.song.116000.json','["管城無別派，毛族競分支。", "公子兔三穴，大夫羊五皮。", "端能開句眼，未肯畫愁眉。", "若問結繩祖，先從六畫推。"]'),
('05139191-816a-42f3-a5d4-a382bd218b24','方舟二首  其一','李石','宋','宋诗','song-poetry','','[]','頗笑方舟拙，聊因拙自誇。',48,'全唐诗/poet.song.116000.json','["頗笑方舟拙，聊因拙自誇。", "家無三日穀，園有四時花。", "池靜魚吞墨，松高鶴護砂。", "著書逢好處，快癢得仙爬。"]'),
('c7d2e885-e48f-449a-8e6f-92c926b9dc82','方舟二首  其二','李石','宋','宋诗','song-poetry','','[]','物我相軒輊，乘除只自知。',48,'全唐诗/poet.song.116000.json','["物我相軒輊，乘除只自知。", "兒臨池上字，母養鏡中絲。", "竹靜泉生乳，花深地産芝。", "舊時雙燕子，來往亦儀儀。"]'),
('8edbc2fe-bdcc-49b6-8233-6333b13421df','山亭三首  其一','李石','宋','宋诗','song-poetry','','[]','春日山亭飯，青枝古樹陰。',48,'全唐诗/poet.song.116000.json','["春日山亭飯，青枝古樹陰。", "親朋知老病，田舍豈初心。", "月白水泉瑩，花多煙霧深。", "酒邊防惡俗，醉語費披尋。"]'),
('3ed689aa-1bdb-4a25-b2b6-9ea5de437704','山亭三首  其二','李石','宋','宋诗','song-poetry','','[]','人誰憐老子，我自類癡兒。',48,'全唐诗/poet.song.116000.json','["人誰憐老子，我自類癡兒。", "愛草留荒徑，疏泉入小池。", "春風隨處是，晴日與花宜。", "好客能相貸，携鋤出短籬。"]'),
('1a866c1f-b911-4e07-be05-101dbf0a79bc','山亭三首  其三','李石','宋','宋诗','song-poetry','','[]','小圃依山入，危亭隠磴斜。',48,'全唐诗/poet.song.116000.json','["小圃依山入，危亭隠磴斜。", "林塘掃寒雨，籬落卧疎花。", "處士七松宅，先生五柳家。", "柴門何所待，倚杖數昏鴉。"]'),
('36d57e29-b3a0-4e01-abc2-b5eed25926d5','舟次湖口追憶任明府','李石','宋','宋诗','song-poetry','','[]','重來又十年，山水故凄然。',48,'全唐诗/poet.song.116000.json','["重來又十年，山水故凄然。", "獨鴈仍爲旅，雙鳬已作仙。", "濁流分蜀派，青色聚淮烟。", "石上罾魚者，猶言縣令賢。"]'),
('748445f0-7c2f-49d3-b61e-fe54acae4718','長松奉寄鄭察院','李石','宋','宋诗','song-poetry','','[]','漢使西來雪瘴深，龍蛇窟宅費披尋。',64,'全唐诗/poet.song.116000.json','["漢使西來雪瘴深，龍蛇窟宅費披尋。", "只知筇竹通中國，何似長松種上林。", "槐省銜杯蒙舊識，楓庭躡履聽歸音。", "昔人九折回車地，笑我何由慰母心。"]'),
('843eb8a2-c24a-46ad-8c95-4bb73101b4ca','木蘭','李石','宋','宋诗','song-poetry','','[]','大渡河邊瘴霧濃，邛崍關下木蘭紅。',64,'全唐诗/poet.song.116000.json','["大渡河邊瘴霧濃，邛崍關下木蘭紅。", "得州自昔連江雨，此地仍多出竅風。", "一笑萱花親念遠，三生藜杖子心同。", "莫緣險阻欺方寸，忠信元來處處通。"]'),
('831c02bb-192e-460b-b54d-531221c25f41','謝人惠新火','李石','宋','宋诗','song-poetry','','[]','六龍杲杲看推移，也有分光蔀屋時。',64,'全唐诗/poet.song.116000.json','["六龍杲杲看推移，也有分光蔀屋時。", "作古遠知燧人氏，至今猶說介之推。", "扣門自此人皆有，暗室從來我不欺。", "冷竈無煙知幾日，憑誰乞米試晨炊。"]'),
('cba316d6-d99b-470c-8589-8fd5d47900d2','題捫參亭','李石','宋','宋诗','song-poetry','','[]','林盤谷轉走縈紆，兩腋乘風上太虛。',64,'全唐诗/poet.song.116000.json','["林盤谷轉走縈紆，兩腋乘風上太虛。", "塵世似將玄圃隔，仙宮元在赤城居。", "著鞭欲跨鸞凰去，舐鼎曾嫌鷄犬餘。", "尺帚何當上霄漢，夜捫星斗步庭除。"]'),
('a5b4cdd3-4312-4301-9ecd-2620e4864e40','至喜亭','李石','宋','宋诗','song-poetry','','[]','歸路巴人處處逢，巴人舟楫語音同。',64,'全唐诗/poet.song.116000.json','["歸路巴人處處逢，巴人舟楫語音同。", "雪霜寒谷殘年後，雲雨陽臺昨夢空。", "沙水清能延月白，峽林香欲試春紅。", "飯山雖瘦無奇語，至喜亭中著醉翁。"]'),
('7fd49838-b21e-4069-94ab-9086333a47fc','羽扇亭','李石','宋','宋诗','song-poetry','','[]','十里山光紺碧圍，瘴煙收盡溢春暉。',64,'全唐诗/poet.song.116000.json','["十里山光紺碧圍，瘴煙收盡溢春暉。", "黄紬睡美聞衙唱，白羽風高入指揮。", "樓角片雲隨鴈去，谿頭驟雨送龍歸。", "君王若問安邊策，苜蓿漫山戰馬肥。"]'),
('07cca05a-a611-4124-bb98-e83fb7f686d9','蠻王妻俗呼縣君來黎州錦領烏氊自跨馬而至','李石','宋','宋诗','song-poetry','','[]','一自昭君向北遷，花魂千載却南旋。',64,'全唐诗/poet.song.116000.json','["一自昭君向北遷，花魂千載却南旋。", "歌聲不動先含笑，粉面無施任自然。", "羞整雲鬟多戴笠，欲呈錦袖漫開氊。", "夜來大渡河邊過，青蓋金羈穩上船。"]'),
('17c23d19-9085-4e73-a4b6-644dfde1887e','禱雪堋口廟','李石','宋','宋诗','song-poetry','','[]','岷峨皎皎玉千峰，只欠平川一尺融。',64,'全唐诗/poet.song.116000.json','["岷峨皎皎玉千峰，只欠平川一尺融。", "土霧不成雲外霰，江沙半雜夜來風。", "針頭可惜丘中麥，堋口來祈應上公。", "飽死侏儒果何意，連年調度戰聲中。"]'),
('f397704d-191f-4706-b9f5-9d37b6109e10','雪  其一','李石','宋','宋诗','song-poetry','','[]','羨他雪色一般同，點綴蒼蒼滓太空。',64,'全唐诗/poet.song.116000.json','["羨他雪色一般同，點綴蒼蒼滓太空。", "白比蝦蟆終蝕月，輕如蝴蝶亂隨風。", "不容著跡無人處，漫借餘光似我窮。", "翠竹疎梅成佛地，未嫌凍立此山中。"]'),
('9378538e-4fe3-4b50-ac41-4513132a892e','雪  其二','李石','宋','宋诗','song-poetry','','[]','大地纖毫色色空，寥天望極一鴻濛。',64,'全唐诗/poet.song.116000.json','["大地纖毫色色空，寥天望極一鴻濛。", "夜凝冷浸梅魂月，朝拂輕回縞带風。", "身世密移塵境外，乾坤收入玉壺中。", "虛堂瑞草瓊林合，壓盡蓬萊第一峰。"]'),
('7a4b7f43-b0ae-46ff-be7f-63e04467ea93','同王夔州探梅','李石','宋','宋诗','song-poetry','','[]','莫因紅紫媚樓臺，潔白光中處處栽。',64,'全唐诗/poet.song.116000.json','["莫因紅紫媚樓臺，潔白光中處處栽。", "香骨未應春雪妒，素心偏向暖風開。", "清樽妙賞今誰健，曉角年光不用催。", "別後西歸玉堂約，詩筒只有月邊來。"]'),
('4ef85a91-63f9-40a3-b3a0-f0bcebc244e7','送牟堯文','李石','宋','宋诗','song-poetry','','[]','別久無辭道路難，敝裘依舊據征鞍。',64,'全唐诗/poet.song.116000.json','["別久無辭道路難，敝裘依舊據征鞍。", "五湖我已遭風逆，三逕君能犯雪寒。", "下榻莫嫌烹瓠葉，倚門正及頌椒盤。", "一杯少味仍相送，折得梅花带笑看。"]'),
('14d03cef-e770-4275-bbf2-651987d0c6b7','一笑','李石','宋','宋诗','song-poetry','','[]','一笑真成亟負余，可人懶散費招呼。',64,'全唐诗/poet.song.116000.json','["一笑真成亟負余，可人懶散費招呼。", "忘言摩詰元無病，健倒盧仝不用扶。", "野葛三餐莫予毒，桃花幾度約吾徒。", "杜門人與春偷老，風雨聲中長白鬚。"]'),
('2bfe06b9-b9cc-450d-8cbb-36c0e260c2c1','送虞樞密還朝','李石','宋','宋诗','song-poetry','','[]','一官齒髮老侵尋，金馬當年博陸沉。',64,'全唐诗/poet.song.116000.json','["一官齒髮老侵尋，金馬當年博陸沉。", "樽俎笑談人不見，璣衡造化我無心。", "曾瞻玉鼎三嵎近，便覺朱門百仞深。", "忍使王陽行九折，囚山未敢廢南音。"]'),
('00013e7f-7d8b-4c39-8a29-9fa5ec61c43e','次韻賈文學見贈','李石','宋','宋诗','song-poetry','','[]','方舟不似逆風船，船上燒香穩坐禪。',64,'全唐诗/poet.song.116000.json','["方舟不似逆風船，船上燒香穩坐禪。", "五鼓紞如隨鳥動，一春老矣學蠶眠。", "黄梅半熟雨不止，白髮也應天見憐。", "頼有比隣賈詩老，醉中相對聳詩肩。"]'),
('ccc873fd-8b93-482e-90dd-ce5310c25e17','和楊子土牛之什','李石','宋','宋诗','song-poetry','','[]','陌上花開又一春，起來酒伴覓南鄰。',64,'全唐诗/poet.song.116000.json','["陌上花開又一春，起來酒伴覓南鄰。", "煙霞笑我雖成疾，霜雪於君恐不仁。", "柏葉殊思金馬舊，柳枝偏向土牛新。", "相忘已約形骸外，老守先能墮醉巾。"]'),
('4e04268f-5246-40d7-bcac-87c02b44b8e1','禮殿','李石','宋','宋诗','song-poetry','','[]','雨老苔荒墨色昏，漢人兩序姓名存。',64,'全唐诗/poet.song.116000.json','["雨老苔荒墨色昏，漢人兩序姓名存。", "六經絲竹升堂後，千古衣冠此地尊。", "但使高文無廢祀，只今揚馬未招魂。", "寥寥蜀學誰爲倡，東去江流注海門。"]'),
('c4ae9436-4ae9-4447-9f5e-afcc95143208','送周行可','李石','宋','宋诗','song-poetry','','[]','國風惆悵黍離離，只有周郎五字詩。',64,'全唐诗/poet.song.116000.json','["國風惆悵黍離離，只有周郎五字詩。", "得見大巫今索矣，可憐小子孰裁之。", "心如廢井憑誰汲，語到修門未可期。", "此別更須留好句，梅花窗外見相思。"]'),
('cb5fe6ac-ab18-4f59-93ba-257a4ae99570','東湖感事二首  其一','李石','宋','宋诗','song-poetry','','[]','桃李洲中別一春，雪山肯爲障紅塵。',64,'全唐诗/poet.song.116000.json','["桃李洲中別一春，雪山肯爲障紅塵。", "鬼神半夜應憐我，魑魅今朝不喜人。", "煙雨晦明窗外眼，風霜來去樹邊身。", "細思只合歸耕好，並舍何由笑我貧。"]'),
('c4b1b7fa-e0f0-4516-9725-67646d2b4e30','東湖感事二首  其二','李石','宋','宋诗','song-poetry','','[]','一官職檄冷秋氷，盡日量書接夜燈。',64,'全唐诗/poet.song.116000.json','["一官職檄冷秋氷，盡日量書接夜燈。", "老去髭鬚無可染，秋來面目自生憎。", "湖通堰尾聽泉激，日出山尖見雪層。", "結習未除江海客，不忘回首夢觚稜。"]'),
('cd72c8ce-2e09-48bc-b391-36e23fadf46d','黄筌畫屏','李石','宋','宋诗','song-poetry','','[]','阿筌千頃本胸中，學道分明畫手同。',64,'全唐诗/poet.song.116000.json','["阿筌千頃本胸中，學道分明畫手同。", "筆削來追麟獲後，丹青爲洗馬羣空。", "登堂欲與修遺履，穴戶何由返大弓。", "尚有滄溟垂素壁，且防蠅誤污屏風。"]'),
('2b2bd46b-258d-4b34-b3b5-cb5b6095178e','遠去親側浩然歸心再用韻','李石','宋','宋诗','song-poetry','','[]','指點西來海上峰，此間魑魅我能逢。',64,'全唐诗/poet.song.116000.json','["指點西來海上峰，此間魑魅我能逢。", "果何所補身先老，豈不懷歸意已濃。", "騏驥羣中憐短褐，龍蛇窟裏倚長松。", "一堂四相經行處，洒掃雲烟覓舊蹤。"]'),
('0f489e30-5d88-48d1-8a8f-6b11fce81511','彭門春日','李石','宋','宋诗','song-poetry','','[]','不似閒人立道傍，豈將老眼眩韶光。',64,'全唐诗/poet.song.116000.json','["不似閒人立道傍，豈將老眼眩韶光。", "溝塍綠漲春容潤，籬落紅披曉吹狂。", "薄有生涯隨處是，苦無心緒逐人忙。", "西歸官路成遷次，回指江湖似故鄉。"]'),
('4a5ff675-9910-4469-a289-0da5a9abe539','又送馬氏兄弟歸彭門','李石','宋','宋诗','song-poetry','','[]','山程趼足肯相從，未厭崎嶇易道東。',64,'全唐诗/poet.song.116000.json','["山程趼足肯相從，未厭崎嶇易道東。", "二馬僊風還舊觀，六鼇香餌看新功。", "北田夜誦披蓮蘂，東閣春歸折桂叢。", "努力錦衣雙拜手，壽盃堂上雪髯翁。"]'),
('9e223924-ddfd-4382-b889-893a960aef6b','食枸杞貓頭筍','李石','宋','宋诗','song-poetry','','[]','一毛沼沚未宜輕，甘脆提携慰客情。',64,'全唐诗/poet.song.116000.json','["一毛沼沚未宜輕，甘脆提携慰客情。", "仙狗吠林堪小摘，乳貓蹲竹得春萌。", "齒牙風露雖云美，口腹朝昏只旋營。", "尚獻一芹裨玉食，天庖回首隔重城。"]'),
('2050e4a4-2898-4339-9af5-b6fb1ec0dc36','再次韻計教授','李石','宋','宋诗','song-poetry','','[]','糟丘盡醉國人狂，誰似東家禮義鄉。',64,'全唐诗/poet.song.116000.json','["糟丘盡醉國人狂，誰似東家禮義鄉。", "萬卷短檠磨歲月，一生寒硯敵氷霜。", "飯牛坐待扶桑白，戰馬初歸塞草黄。", "奏牘三千君未晚，殿幃正要上書囊。"]'),
('6c010433-5248-40e5-b173-17680e852bb1','春水','李石','宋','宋诗','song-poetry','','[]','倚杖河邊記水痕，眼明喜見白鷗羣。',64,'全唐诗/poet.song.116000.json','["倚杖河邊記水痕，眼明喜見白鷗羣。", "雨聲夜向九峰瀉，江勢朝來三堰分。", "窟宅蛟龍元自擅，鄰家鷄犬要相聞。", "我師一飽關天意，收拾晴風放密雲。"]'),
('758bd242-d3c3-40b4-a53e-f42c4020516d','次韻李判官見贈','李石','宋','宋诗','song-poetry','','[]','鬚髯殘雪兀陳編，煬者何由更避煙。',64,'全唐诗/poet.song.116000.json','["鬚髯殘雪兀陳編，煬者何由更避煙。", "榮宦君方收晚歲，論交我亦得忘年。", "佐州相與營杯水，有路從今出甕天。", "一日尚能千里駕，此間老驥不須鞭。"]'),
('ddccb585-292d-4868-8c2a-127fc2e4ff6b','寄知來弟','李石','宋','宋诗','song-poetry','','[]','霏霏寒日隕清霜，勃勃陰風出土囊。',64,'全唐诗/poet.song.116000.json','["霏霏寒日隕清霜，勃勃陰風出土囊。", "尺木未階龍久蟄，銜蘆不穩鴈斜行。", "仕塗田舍成三已，世態江湖合兩忘。", "無術憂民緣底瘦，一杯豆粥爇心香。"]'),
('87dba406-67d7-41e6-baf9-20851fe4601f','市進馬寒甚','李石','宋','宋诗','song-poetry','','[]','邊雲寒色與愁濃，酒味何由入頰紅。',64,'全唐诗/poet.song.116000.json','["邊雲寒色與愁濃，酒味何由入頰紅。", "眼看飛鳶來墮水，心隨去騎欲追風。", "親朋立望千山外，笑語殊思一餉同。", "問舍求田吾已决，不於湖海較窮通。"]'),
('95fa5262-aa30-49a1-804e-499f1296b3ff','到沉黎舉家瞶氣上如聾者踰月乃愈醫人云此瘴氣也','李石','宋','宋诗','song-poetry','','[]','儋史之孫病耳翁，人佯謂我與真同。',64,'全唐诗/poet.song.116000.json','["儋史之孫病耳翁，人佯謂我與真同。", "蚊飛鬢外年時事，鵲噪愁邊晚更空。", "老去鹿皮終可隠，聽如龍鼻反能聰。", "昭文不鼓非無意，勉爲慈親奏凱風。"]'),
('81db675d-eada-414c-9e3d-d4a04a27e5ad','天彭得解','李石','宋','宋诗','song-poetry','','[]','一第楓宸歲月深，槐花杯酒喜同斟。',64,'全唐诗/poet.song.116000.json','["一第楓宸歲月深，槐花杯酒喜同斟。", "真成冀北空羣馬，便作雙南滿地金。", "計上八人才子數，筆端四海狀元心。", "蜀天九萬看鵬運，側耳潮頭駕捷音。"]'),
('b280a170-a540-4da2-8209-bd335852a78b','李新仲圭同遊醮壇歸以詩告別次韻','李石','宋','宋诗','song-poetry','','[]','別去名場歎滯留，肯來空谷話清幽。',64,'全唐诗/poet.song.116000.json','["別去名場歎滯留，肯來空谷話清幽。", "知君有約趨金馬，笑我無心對白鷗。", "千頃量陂能却老，一編家學莫他求。", "相將杖履題詩處，跨鹿山頭記舊遊。"]'),
('8f9fe1e7-d7b2-47d1-8db6-10e683ada1ce','苦胃不出二首  其一','李石','宋','宋诗','song-poetry','','[]','眇小酲醲總見欺，顛狂苦訴有誰知。',64,'全唐诗/poet.song.116000.json','["眇小酲醲總見欺，顛狂苦訴有誰知。", "五音鶑自調歌舌，百藥蜂能釀蜜脾。", "世態只堪春睡美，鬢絲偏與落花宜。", "欲因耆舊尋鄉路，投劾翻然恐未遲。"]'),
('0d34a74f-96fa-4574-8d27-588f4c5cc251','苦胃不出二首  其二','李石','宋','宋诗','song-poetry','','[]','鳴禽百囀柳三眠，窗戶陰晴任雨煙。',64,'全唐诗/poet.song.116000.json','["鳴禽百囀柳三眠，窗戶陰晴任雨煙。", "芍藥櫻桃春殿後，芎藭麥麴病爭先。", "奉親滿眼欠一飽，去國憂心今五年。", "南北風塵江兩岸，不妨明月釣魚船。"]'),
('a0bc3a81-ed7a-4a9d-ba55-dc17e95b2c88','邊州警報','李石','宋','宋诗','song-poetry','','[]','翠圍矗矗亂山稠，蜑雨蠻烟凍不收。',64,'全唐诗/poet.song.116000.json','["翠圍矗矗亂山稠，蜑雨蠻烟凍不收。", "赤白囊來逢此歲，青黄穀熟又深秋。", "一官忍恥隨人後，數口全生敢自謀。", "蟣蝨有心空地上，蒼生難答兩宮憂。"]'),
('d8fcdeaa-b3a9-4764-99f1-dc21a7d5ed3e','謝處道貺墨用與德醇韻','李石','宋','宋诗','song-poetry','','[]','十八公家四十圍，凌烟勳業在臨池。',64,'全唐诗/poet.song.116000.json','["十八公家四十圍，凌烟勳業在臨池。", "掌中烏玉勞分餉，世上玄經只自知。", "頗覺陳人空面目，誰能閙處損心脾。", "又須什襲牢藏苦，共看河沙指後期。"]'),
('877efc65-1718-47f8-84e2-201dcb935f68','送蘇漢傑','李石','宋','宋诗','song-poetry','','[]','萬里來歸道路長，兩年身寄水雲鄉。',64,'全唐诗/poet.song.116000.json','["萬里來歸道路長，兩年身寄水雲鄉。", "僅餘文字縑緗富，猶带湖山草木香。", "從此定應懸箔去，卑之且說踏槐忙。", "逢君客地成乖隔，相送江干問草堂。"]'),
('bce13074-d78f-4c3a-b29f-39c1c4db402b','送處道','李石','宋','宋诗','song-poetry','','[]','上馬挑書束破裘，宦情薄處不宜秋。',64,'全唐诗/poet.song.116000.json','["上馬挑書束破裘，宦情薄處不宜秋。", "二年拄笏山雖好，十舍浣花江合流。", "此處移文尋舊社，尚因奇字憶方舟。", "西川儻有東來鴈，莫道曾無截鐙留。"]'),
('bc7c7bd2-91c5-41de-a920-9d92b0fb52b9','重陽','李石','宋','宋诗','song-poetry','','[]','得得浮家帝里遊，西歸節物共南州。',64,'全唐诗/poet.song.116000.json','["得得浮家帝里遊，西歸節物共南州。", "羣鷗自得水空闊，遠客肯因船滯留。", "千頃白蘋風掠岸，一年黄菊雨深秋。", "醉名未忍成狂率，任脫烏紗笑白頭。"]'),
('7938d13f-3e78-46a2-8a6e-a8345b5be24f','再用九日韻答何邵卿二首  其一','李石','宋','宋诗','song-poetry','','[]','老蝶凌風作晚狂，小春爭得媚寒鄉。',64,'全唐诗/poet.song.116000.json','["老蝶凌風作晚狂，小春爭得媚寒鄉。", "池邊團碧擎殘雨，林末輕紅拒薄霜。", "笑我何時書竹帛，似君依舊踏槐黄。", "相尋一醉能來否，枉費公家壓酒囊。"]'),
('52776f61-f31a-4ab2-9bac-008c1c2430c8','再用九日韻答何邵卿二首  其二','李石','宋','宋诗','song-poetry','','[]','習氣仍餘酒後狂，十年坐斥醉中鄉。',64,'全唐诗/poet.song.116000.json','["習氣仍餘酒後狂，十年坐斥醉中鄉。", "讀書窗外千堆雪，利劍床頭一匣霜。", "收拾微吟追李杜，研摩小楷逼蘇黄。", "他文消遣隨兒輩，頗笑翁癡作一囊。"]'),
('b60474d4-d279-4798-926e-e255aef62a8c','挽沈提刑','李石','宋','宋诗','song-poetry','','[]','金馬堂堂有陸沉，斯人出處可重尋。',64,'全唐诗/poet.song.116000.json','["金馬堂堂有陸沉，斯人出處可重尋。", "豸冠議論回天力，繡節平反念母心。", "一代師承無別派，百年朋舊託遺音。", "便當佳傳磨蒼翠，桐桂森然欲出林。"]'),
('5209b8ab-493c-4260-974a-eeeabae31457','挽何與時','李石','宋','宋诗','song-poetry','','[]','留滯周南隔要津，尚餘家傳付堅珉。',64,'全唐诗/poet.song.116000.json','["留滯周南隔要津，尚餘家傳付堅珉。", "才高未覺儒冠誤，句好仍傳樂府新。", "諸子尚能頻屈指，一門今有幾朱輪。", "吾鄉水鏡君應恨，聳壑昂霄會有人。"]'),
('a9cf8110-5323-493c-b890-0ea01e8dd479','留別何十五','李石','宋','宋诗','song-poetry','','[]','修程雲水遶蒼茫，馬上春風薜荔香。',64,'全唐诗/poet.song.116000.json','["修程雲水遶蒼茫，馬上春風薜荔香。", "此去雞豚思舊社，且憑魚鴈到他鄉。", "窮途偪仄風波惡，客路消磨歲月長。", "別後空階聞夜雨，令人還憶水曹郎。"]'),
('c81bde99-4481-42cd-8622-d894802ba2c5','九日與一飛諸友飲菊','李石','宋','宋诗','song-poetry','','[]','五年去國若爲歡，九日逢秋强自寬。',64,'全唐诗/poet.song.116000.json','["五年去國若爲歡，九日逢秋强自寬。", "樹攪冰霜驚歲晚，山圍霧雨試朝寒。", "不關鳥帽隨風落，只把紅萸對俗看。", "惟有東湖無可遣，一杯香泛落英餐。"]'),
('8a1aa4cc-fbf1-406f-9141-0865a4703935','送王應祥','李石','宋','宋诗','song-poetry','','[]','進取雖狂我不狂，跨鼇今日鄭公鄉。',64,'全唐诗/poet.song.116000.json','["進取雖狂我不狂，跨鼇今日鄭公鄉。", "未偕西蜀三年計，來訪東湖九月霜。", "桃李山城漫紅白，橘橙峽路看青黄。", "修門萬里逢嚴助，剩剖琅玕出錦囊。"]'),
('4a38e43f-cded-4afc-9a4f-0d19b117d4c4','次韻誼夫九日憶去歲共遊東林','李石','宋','宋诗','song-poetry','','[]','菜飽無期歲已侵，高談何處著幽深。',64,'全唐诗/poet.song.116000.json','["菜飽無期歲已侵，高談何處著幽深。", "二年旅寄不堪說，九日盟寒那復尋。", "此地有時容醉玉，寒花無數吐秋金。", "與君成是無詩句，聞道西山似竹林。"]'),
('b6960c6d-1c58-4e13-98d2-80f672720c22','展峰亭','李石','宋','宋诗','song-poetry','','[]','起來蛛網罥茅簷，脫葉飛飛却倒粘。',64,'全唐诗/poet.song.116000.json','["起來蛛網罥茅簷，脫葉飛飛却倒粘。", "十月風光成嫵媚，一林霜氣自深嚴。", "幽花已老何人摘，村酒無多喜客添。", "收拾江湖閒望眼，展峰亭上數山尖。"]'),
('9ed44162-45fc-4930-8e43-48a7b03e0464','禱雨','李石','宋','宋诗','song-poetry','','[]','吾家何必自耕耘，淮上新添戰馬羣。',64,'全唐诗/poet.song.116000.json','["吾家何必自耕耘，淮上新添戰馬羣。", "聖水洑流天漢永，顛風扇雪地爐焚。", "但教東海無寃氣，便可西郊放密雲。", "浪遣蛇醫與龍鬭，邈然天聽若無聞。"]'),
('5602c14c-9dbd-41a0-9501-ad192a2950f5','次韻喜雨','李石','宋','宋诗','song-poetry','','[]','雲色垂軒潑墨深，夜聞蕭瑟振枯林。',64,'全唐诗/poet.song.116000.json','["雲色垂軒潑墨深，夜聞蕭瑟振枯林。", "自憐一榻清凉意，想見千畦饜飫心。", "共道蘇天私此澤，後來商旱更誰霖。", "公歸還記田田葉，坐看荷珠自勸斟。"]'),
('f6659f80-cfc7-480a-b5af-6feb1e7fe0bd','公實公衍伯仲相訪云木犀再花香橘新摘也併以爲惠且將以佳篇因次韻','李石','宋','宋诗','song-poetry','','[]','桂屏立壁杳難攀，畫舫層層碧玉欄。',64,'全唐诗/poet.song.116000.json','["桂屏立壁杳難攀，畫舫層層碧玉欄。", "未覺香風披蕊晚，向來白雪避花繁。", "秋深犀子仍奔殿，夜迥珠星得走盤。", "二妙沓來成伯仲，恨無瓊玖出毫端。"]'),
('765b55ff-51b2-40e0-9183-46d658efebc3','石蒙恩召還以病留滯度歲賦此詩道別呈諸同官','李石','宋','宋诗','song-poetry','','[]','三馳旌聘合翻然，萬里君恩荷記憐。',64,'全唐诗/poet.song.116000.json','["三馳旌聘合翻然，萬里君恩荷記憐。", "肯許老饕同守歲，且因春酒介新年。", "風傳鷁首五湖浪，雪漲蟆頤一脈泉。", "他日堂中元祐脚，只堪誦說學蘇仙。"]'),
('c5d38d99-1116-4c02-8fd4-05ee45662eb7','謝彭守送花','李石','宋','宋诗','song-poetry','','["\u897f\u6e56"]','別去名園走路塵，啼粧猶浥露痕新。',64,'全唐诗/poet.song.116000.json','["別去名園走路塵，啼粧猶浥露痕新。", "且陪東閣諸侯客，粗了西湖一半春。", "試與清泉召魂魄，已驚黄蠟損精神。", "回頭却憶風流守，金粉珊珊墮舞茵。"]'),
('7b247a09-dedd-4f2e-86a4-7f3597f5174e','古柏二首  其一','李石','宋','宋诗','song-poetry','','[]','驕榮落盡雪霜浮，偃蹇空貽社櫟羞。',64,'全唐诗/poet.song.116000.json','["驕榮落盡雪霜浮，偃蹇空貽社櫟羞。", "濡染東家雖借潤，風烟西爽亦宜秋。", "皮災已覺神明露，心在猶懷剪伐憂。", "鐵鏁何當絆龍脚，夜深雷雨捲潭湫。"]'),
('53ca0788-efad-43bf-8e40-515d2b3149bd','古柏二首  其二','李石','宋','宋诗','song-poetry','','[]','思人誰復念婆娑，窟室崖陰未易磨。',64,'全唐诗/poet.song.116000.json','["思人誰復念婆娑，窟室崖陰未易磨。", "四十圍間看溜雨，三千年後數恒河。", "不堪與世供狙杙，尚許遺民占鳥窠。", "從此便名夫子樹，匡人斤斧奈予何。"]'),
('05f80c28-7874-41f6-a542-04ff87e75cec','秋月','李石','宋','宋诗','song-poetry','','[]','望崖相送欲凌虛，未擬邊州作陋居。',64,'全唐诗/poet.song.116000.json','["望崖相送欲凌虛，未擬邊州作陋居。", "法令牛毛紛可笑，使君馬尾自能書。", "白雲度嶺愁方寸，黄瘴埋沙費掃除。", "列㦸橫琴果何擇，一窗秋月竹踈踈。"]'),
('85de7c29-8a70-4f09-8050-a3eae7d16620','除夕','李石','宋','宋诗','song-poetry','','[]','又是投閒歲欲除，閒中因得著工夫。',64,'全唐诗/poet.song.116000.json','["又是投閒歲欲除，閒中因得著工夫。", "園林香雪梅先透，庭院清風竹自呼。", "未厭夜寒燒榾柮，已貪曉色進屠蘇。", "巧名尚喜新年在，碌碌人應笑阿奴。"]'),
('43636327-1b34-4898-ad7e-82aeed17209d','陪韓守劉村看牡丹','李石','宋','宋诗','song-poetry','','[]','洛陽舊譜隔芳園，姚魏尋香作返魂。',64,'全唐诗/poet.song.116000.json','["洛陽舊譜隔芳園，姚魏尋香作返魂。", "端爲名花肯迂路，定知春色落深村。", "日中半醉如含恨，雨後幽姿未忍言。", "上苑分明有餘地，野芹何獨遡金門。"]'),
('2acf0655-c6c9-40e9-b560-c04ab7eb055f','用之相訪忽憶漢孫不得一脈以死用前韻','李石','宋','宋诗','song-poetry','','[]','叩門剝啄涕霑襟，忽憶僧孫病骨侵。',64,'全唐诗/poet.song.116000.json','["叩門剝啄涕霑襟，忽憶僧孫病骨侵。", "壁上卧龍香線斷，柱間題鳳墨痕深。", "倉皇不瞑思君眼，輾轉猶希住世心。", "真意自天渠信否，贈篇聊當閣中箴。"]'),
('6845557d-526d-42f7-9c4e-118f86578d4e','到夔門呈王待制','李石','宋','宋诗','song-poetry','','[]','手挈東風上水關，鳳書迎日看新班。',64,'全唐诗/poet.song.116000.json','["手挈東風上水關，鳳書迎日看新班。", "五湖家世烏衣巷，三峽樓臺赤甲山。", "畫㦸門開春晝永，卧龍帳穩海波閒。", "安危大計須公等，天定應知即賜環。"]'),
('4c588dd1-ce5f-45a0-81cc-e1107cee423f','題師永錫知縣畫老竹枯木二首  其一','李石','宋','宋诗','song-poetry','','[]','霜雪倚巖樹，霧雲秋水槎。',24,'全唐诗/poet.song.116000.json','["霜雪倚巖樹，霧雲秋水槎。", "且須高著眼，上有曇鉢花。"]'),
('ae0578c0-0a50-4236-bdac-a7eb9a530f8a','題師永錫知縣畫老竹枯木二首  其二','李石','宋','宋诗','song-poetry','','[]','水墨三十年，一枝更一節。',24,'全唐诗/poet.song.116000.json','["水墨三十年，一枝更一節。", "工夫不爭多，儘立庭下雪。"]'),
('f1d05fb1-2495-45e2-bf64-30ca499a9dff','題李都畫枯木','李石','宋','宋诗','song-poetry','','[]','毫端看運斤，筆老木亦老。',24,'全唐诗/poet.song.116000.json','["毫端看運斤，筆老木亦老。", "莫畫春風枝，秋來厭枯槁。"]'),
('a0191ff2-ad85-4de3-8475-d8431c3b5271','次韻趙榮州題蘆鴈畫','李石','宋','宋诗','song-poetry','','[]','畢弋橫前路，江湖寄此身。',24,'全唐诗/poet.song.116000.json','["畢弋橫前路，江湖寄此身。", "平沙下雙鴈，不見問津人。"]'),
('d4019f72-4074-44e6-9a3d-66175972b549','水仙花二首  其一','李石','宋','宋诗','song-poetry','','[]','碧雲玉搔頭，對景山月皎。',24,'全唐诗/poet.song.116000.json','["碧雲玉搔頭，對景山月皎。", "霜靜在更深，風香我先曉。"]'),
('69b8d763-af0e-4f9e-9776-5248620b995f','水仙花二首  其二','李石','宋','宋诗','song-poetry','','[]','肌膚剪秋水，垂雲出龍宮。',24,'全唐诗/poet.song.116000.json','["肌膚剪秋水，垂雲出龍宮。", "我意得子珮，笑許無言中。"]'),
('d5eb7b74-e373-4082-8ff1-495dde8e0d41','叱馭橋','李石','宋','宋诗','song-poetry','','[]','鸞鳳飛緣壁，虹蜺下飲溪。',24,'全唐诗/poet.song.116000.json','["鸞鳳飛緣壁，虹蜺下飲溪。", "一家蠻瘴裏，九折夕陽西。"]'),
('572496c4-2ed8-42f1-ae78-e7f255f13726','謁武侯廟','李石','宋','宋诗','song-poetry','','[]','此地蛟龍伏，中原蛇豕多。',24,'全唐诗/poet.song.116000.json','["此地蛟龍伏，中原蛇豕多。", "借君白羽扇，萬馬飲黄河。"]'),
('91362c9b-844b-4f8d-87e6-4436b1269ed5','蠟梅二首  其一','李石','宋','宋诗','song-poetry','','[]','黄昏澹烟晴，風健香骨透。',24,'全唐诗/poet.song.116000.json','["黄昏澹烟晴，風健香骨透。", "煉金呈赤心，山月惜孤瘦。"]'),
('82921d06-6c66-45d7-9bd6-c31f1d35a7bc','蠟梅二首  其二','李石','宋','宋诗','song-poetry','','[]','莫學卧鬢花，嬌黄媚粉額。',24,'全唐诗/poet.song.116000.json','["莫學卧鬢花，嬌黄媚粉額。", "仙官道家粧，靜處立標格。"]'),
('911edf4d-8701-431c-a9fb-639b8800fc64','鷄鳴關','李石','宋','宋诗','song-poetry','','[]','關路入雲平，泥塗自送迎。',24,'全唐诗/poet.song.116000.json','["關路入雲平，泥塗自送迎。", "書生無馬癖，客子效鷄鳴。"]'),
('c05a2519-b1f2-46d4-a677-7f0b2f1bb483','次韻張當進題神君廟','李石','宋','宋诗','song-poetry','','[]','桂檝方東泛，荷衣已出塵。',24,'全唐诗/poet.song.116000.json','["桂檝方東泛，荷衣已出塵。", "曲江尋相業，猶是姓張人。"]'),
('dbdbddff-a000-4ac6-bd27-7ae87fcf3b02','子夜春歌二絕  其一','李石','宋','宋诗','song-poetry','','[]','新挑錦字書，倒指歲月遠。',24,'全唐诗/poet.song.116000.json','["新挑錦字書，倒指歲月遠。", "愁眉要深黛，燈花已堪剪。"]'),
('f289a305-cc6a-4a38-8418-b9743426ed16','子夜春歌二絕  其二','李石','宋','宋诗','song-poetry','','[]','瘦玉薄薄衫，暈燈和月冷。',24,'全唐诗/poet.song.116000.json','["瘦玉薄薄衫，暈燈和月冷。", "獨夜不禁春，梨花碎簾影。"]'),
('bb66680d-bf0a-45dc-b228-1fd5c81747e6','題蘇氏巽風閣','李石','宋','宋诗','song-poetry','','[]','巽風起東南，大地萬物小。',24,'全唐诗/poet.song.116000.json','["巽風起東南，大地萬物小。", "吳門共延矚，匹練橫江表。"]'),
('7b83889a-6083-43e4-af99-759d61ca359b','扇子詩  其一','李石','宋','宋诗','song-poetry','','[]','雨挹春紅淺，風酣晚蘂稠。',24,'全唐诗/poet.song.116000.json','["雨挹春紅淺，風酣晚蘂稠。", "看花不著意，何事亦關愁。"]'),
('750142cf-e4ba-4369-bcd7-98fe21141fb0','扇子詩  其二','李石','宋','宋诗','song-poetry','','[]','斯文悔少作，自謂老更工。',24,'全唐诗/poet.song.116000.json','["斯文悔少作，自謂老更工。", "不是舍人樣，合住此山中。"]'),
('95e7bd90-cf1c-4e15-bbf3-93eee645cff0','扇子詩  其三','李石','宋','宋诗','song-poetry','','[]','芳草遞春風，三山立桂叢。',24,'全唐诗/poet.song.116000.json','["芳草遞春風，三山立桂叢。", "柳條隨駕綠，花蘂上林紅。"]'),
('72e9b18c-2741-483b-9be4-ffbe09712fbd','扇子詩  其四','李石','宋','宋诗','song-poetry','','[]','釧動香飄麝，簪低鬢拂鴉。',24,'全唐诗/poet.song.116000.json','["釧動香飄麝，簪低鬢拂鴉。", "休遮笑裏面，用此庭前花。"]'),
('658d3989-38f2-48cd-bc86-d06cb6eaeb72','扇子詩  其五','李石','宋','宋诗','song-poetry','','[]','火老不知秋，螢飛風露下。',24,'全唐诗/poet.song.116000.json','["火老不知秋，螢飛風露下。", "和月立梧桐，幽人宜獨夜。"]'),
('edde6427-08c9-4c18-be15-e0a9e87f8d77','扇子詩  其六','李石','宋','宋诗','song-poetry','','[]','竹影月來去，荷香風送迎。',24,'全唐诗/poet.song.116000.json','["竹影月來去，荷香風送迎。", "南窗枕書卧，醉眼看山橫。"]'),
('bc743124-9112-4c69-8e99-0de096032549','扇子詩  其七','李石','宋','宋诗','song-poetry','','[]','水浸菩提坐，風傳戒定香。',24,'全唐诗/poet.song.116000.json','["水浸菩提坐，風傳戒定香。", "藕根金鎖骨，花面玉毫光。"]'),
('c991b1ea-875b-4419-90f9-235c436b4c7e','扇子詩  其八','李石','宋','宋诗','song-poetry','','[]','月下九九仙，雲間七七泉。',24,'全唐诗/poet.song.116000.json','["月下九九仙，雲間七七泉。", "喚起吹簫子，跨鶴飛上天。"]'),
('e5f5b147-e500-41ed-a292-5493e7b59757','扇子詩  其九','李石','宋','宋诗','song-poetry','','[]','積雨莓苔色，秋風松桂林。',24,'全唐诗/poet.song.116000.json','["積雨莓苔色，秋風松桂林。", "莫隨蓬鬢改，黄落見真心。"]'),
('eed3fc4c-5eb4-48aa-812d-4bcf6014d266','扇子詩  其一○','李石','宋','宋诗','song-poetry','','[]','海濶千江輳，風翻大浪隨。',24,'全唐诗/poet.song.116000.json','["海濶千江輳，風翻大浪隨。", "六鼇元未足，不是下鈎遲。"]'),
('07b7b801-f08e-4023-8788-b65211bf6d6d','扇子詩  其一一','李石','宋','宋诗','song-poetry','','[]','薰蒸香積厨，精鑿午齋飯。',24,'全唐诗/poet.song.116000.json','["薰蒸香積厨，精鑿午齋飯。", "飯後且放參，林下香一瓣。"]'),
('40ae5709-abe5-46d6-9f3b-2ad1c457ded1','扇子詩  其一二','李石','宋','宋诗','song-poetry','','[]','黑風吹海立，雲水渺三韓。',24,'全唐诗/poet.song.116000.json','["黑風吹海立，雲水渺三韓。", "蓑笠漁舟裏，無心下釣竿。"]'),
('a0ab86ce-fe3d-4711-9bb3-9150bff22cb4','扇子詩  其一三','李石','宋','宋诗','song-poetry','','[]','江海翱翔地，舟行岸自移。',24,'全唐诗/poet.song.116000.json','["江海翱翔地，舟行岸自移。", "無心波浪裏，鷗鳥不須疑。"]'),
('7cdbce30-866e-401d-83fb-d39480464f24','扇子詩  其一四','李石','宋','宋诗','song-poetry','','[]','引手折纖枝，月邊簪玉兒。',24,'全唐诗/poet.song.116000.json','["引手折纖枝，月邊簪玉兒。", "好與一杯酒，酒香知是誰。"]'),
('6f7e92e6-64d1-4be7-8982-2f8583545f3c','扇子詩  其一五','李石','宋','宋诗','song-poetry','','[]','衆水秋風勁，羣鷗白雪和。',24,'全唐诗/poet.song.116000.json','["衆水秋風勁，羣鷗白雪和。", "只宜閒坐釣，湖海老烟蓑。"]'),
('196baa0d-9b59-4b3c-8c0a-492b567b61da','扇子詩  其一六','李石','宋','宋诗','song-poetry','','[]','風雨樓上笛，燒春寬作程。',24,'全唐诗/poet.song.116000.json','["風雨樓上笛，燒春寬作程。", "眉峯須小蹙，梅子彈九青。"]'),
('7131b202-1d7b-47bf-b11f-615beb269db3','扇子詩  其一七','李石','宋','宋诗','song-poetry','','[]','露冷蘂珠珮，五湖雲水深。',24,'全唐诗/poet.song.116000.json','["露冷蘂珠珮，五湖雲水深。", "一枝春好在，先寄月邊心。"]'),
('59198525-c251-41d5-a57e-12c11e05688d','秋月二首  其一','李石','宋','宋诗','song-poetry','','[]','夜榻近虛簷，獨卧玉蟾冷。',24,'全唐诗/poet.song.116000.json','["夜榻近虛簷，獨卧玉蟾冷。", "梧桐氣先奪，端不礙清影。"]'),
('093cfb68-2ccb-457a-84d8-5186740ed1e9','秋月二首  其二','李石','宋','宋诗','song-poetry','','[]','江草半黄落，江雨催授衣。',24,'全唐诗/poet.song.116000.json','["江草半黄落，江雨催授衣。", "衣中有斷線，客子秋念歸。"]'),
('8ee077b3-01c6-407e-8326-cf81feed71c0','感事  其一','李石','宋','宋诗','song-poetry','','[]','一水遮金騎，諸州辦甲衣。',24,'全唐诗/poet.song.116000.json','["一水遮金騎，諸州辦甲衣。", "書生投筆硯，隨口說兵機。"]'),
('d008abfd-dd23-471e-90b4-62515bf650d7','感事  其二','李石','宋','宋诗','song-poetry','','[]','老大年光迫，纖花又一春。',24,'全唐诗/poet.song.116000.json','["老大年光迫，纖花又一春。", "鵲占風外歲，雞唱雨中晨。"]'),
('1217f91b-e073-4c43-b948-5096f9f6a29e','感事  其三','李石','宋','宋诗','song-poetry','','[]','一徑清如掃，柴門霽影多。',24,'全唐诗/poet.song.116000.json','["一徑清如掃，柴門霽影多。", "苔莓因鶴啄，非是客經過。"]'),
('978bb45a-f8cb-401d-b8a0-c0e92c3f4249','感事  其四','李石','宋','宋诗','song-poetry','','[]','三起復三眠，吹花漲雨烟。',24,'全唐诗/poet.song.116000.json','["三起復三眠，吹花漲雨烟。", "浮萍增采色，輕壓綠池蓮。"]'),
('07b7b8be-c930-4b91-b958-bdb180fc45d5','感事  其五','李石','宋','宋诗','song-poetry','','[]','苔掃彌旬雨，花開數日晴。',24,'全唐诗/poet.song.116000.json','["苔掃彌旬雨，花開數日晴。", "蝶輕矜鬼翅，鶑巧學僮聲。"]'),
('4e07af21-0656-4d11-bfcc-e45962ed3c2c','感事  其六','李石','宋','宋诗','song-poetry','','[]','綴綴復翹翹，金絲並玉條。',24,'全唐诗/poet.song.116000.json','["綴綴復翹翹，金絲並玉條。", "酴醾與楊柳，結託上青霄。"]'),
('c1cc4621-0906-4bf1-bf8e-120849a5820e','感事  其七','李石','宋','宋诗','song-poetry','','[]','踏碓村舂急，繰車並舍忙。',24,'全唐诗/poet.song.116000.json','["踏碓村舂急，繰車並舍忙。", "雀桃紅綴吻，鶑粟碧成囊。"]'),
