('adcfc3b5-ae34-4477-8ac0-53982f5da9d5','扇子詩  其七○','李石','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','親見廬山面目來，翻經臺上月輪開。',32,'全唐诗/poet.song.116000.json','["親見廬山面目來，翻經臺上月輪開。", "山間長物渾無用，多斫雲根入蜀栽。"]'),
('1a0d65e4-f946-47fc-be3e-a67eb18a59dd','扇子詩  其七一','李石','宋','宋诗','song-poetry','','[]','素縑咫尺十分圓，淡墨濃陰畫手傳。',32,'全唐诗/poet.song.116000.json','["素縑咫尺十分圓，淡墨濃陰畫手傳。", "惟恐動摇天地窄，只應掌上握山川。"]'),
('58001013-7c1d-456c-829e-9185fb610f22','扇子詩  其七二','李石','宋','宋诗','song-poetry','','[]','𦨴艚市中漁者漁，茅屋岸上居人居。',32,'全唐诗/poet.song.116000.json','["𦨴艚市中漁者漁，茅屋岸上居人居。", "陽坡細草馬隨鹿，烟水靜花鷗趁魚。"]'),
('b382249f-fd41-44c4-a7b0-9502fe87606d','扇子詩  其七三','李石','宋','宋诗','song-poetry','','[]','嫋嫋腰肢翠拂眉，河東柳家嬌女兒。',32,'全唐诗/poet.song.116000.json','["嫋嫋腰肢翠拂眉，河東柳家嬌女兒。", "江南烟雨樓百尺，樓上何人題好詩。"]'),
('8ab18131-94b8-4f41-8f31-e7a821238001','扇子詩  其七四','李石','宋','宋诗','song-poetry','','[]','黄金坐擁佛衣紅，風動荷花香動風。',32,'全唐诗/poet.song.116000.json','["黄金坐擁佛衣紅，風動荷花香動風。", "鼻觀浮香誰領會，嫦娥夜泊水晶宮。"]'),
('4cae1f5c-8f87-4d8b-8719-7e25b787eb5f','扇子詩  其七五','李石','宋','宋诗','song-poetry','','[]','芙蓉香泛白蘋洲，楊柳吹花玉雪浮。',32,'全唐诗/poet.song.116000.json','["芙蓉香泛白蘋洲，楊柳吹花玉雪浮。", "且喜兩邊無一事，五更鼓角月當樓。"]'),
('c82b2788-9627-4913-91c1-8e69c9bebfb3','扇子詩  其七六','李石','宋','宋诗','song-poetry','','[]','花自爲王橘自奴，便應次第問東湖。',32,'全唐诗/poet.song.116000.json','["花自爲王橘自奴，便應次第問東湖。", "芳菲未礙滄浪色，照水吟詩鑷白鬚。"]'),
('e1f8fbb7-5ec5-49a4-a665-a2d79738076f','扇子詩  其七七','李石','宋','宋诗','song-poetry','','[]','上頭圓蓋下方盤，中夾癡憨白肉圓。',32,'全唐诗/poet.song.116000.json','["上頭圓蓋下方盤，中夾癡憨白肉圓。", "九竅八骸渾不識，更來底處覓心安。"]'),
('69ed0c3d-1d59-49fa-b4b9-a4c0aedbce1e','扇子詩  其七八','李石','宋','宋诗','song-poetry','','[]','誰將弱水隔蓬萊，對酒思君眼倦開。',32,'全唐诗/poet.song.116000.json','["誰將弱水隔蓬萊，對酒思君眼倦開。", "醉夢只堪逢故舊，五更酒醒却歸來。"]'),
('174d4f9b-554f-44f7-b40e-6fd610add2dd','扇子詩  其七九','李石','宋','宋诗','song-poetry','','[]','愛他國色艷傾城，老衲心城百萬兵。',32,'全唐诗/poet.song.116000.json','["愛他國色艷傾城，老衲心城百萬兵。", "便使有情何足動，幻花况是本無情。"]'),
('de42203d-cc14-41ee-a838-4923c07ac2b3','扇子詩  其八○','李石','宋','宋诗','song-poetry','','[]','未容穀雨淚胭脂，且趁晴風小小吹。',32,'全唐诗/poet.song.116000.json','["未容穀雨淚胭脂，且趁晴風小小吹。", "鏡裏日高酣睡起，也須瘦了一分肌。"]'),
('11694c16-4b1b-445e-ae20-0e953d55762c','扇子詩  其八一','李石','宋','宋诗','song-poetry','','[]','先生種柳懶低頭，骯髒門前也可羞。',32,'全唐诗/poet.song.116000.json','["先生種柳懶低頭，骯髒門前也可羞。", "莫向東風弄霜雪，且隨風勢衮成毬。"]'),
('c5e92bc3-1841-4dad-9cd9-5e20f20e5d18','扇子詩  其八二','李石','宋','宋诗','song-poetry','','[]','本來騎鶴上揚州，不學老君誇白頭。',32,'全唐诗/poet.song.116000.json','["本來騎鶴上揚州，不學老君誇白頭。", "丈夫要活三百歲，獨在中書二十秋。"]'),
('37de8063-f336-4e34-882d-5411b82e536e','扇子詩  其八三','李石','宋','宋诗','song-poetry','','[]','只教人喜莫教嗔，此是天公最至仁。',32,'全唐诗/poet.song.116000.json','["只教人喜莫教嗔，此是天公最至仁。", "吹落吹開俱有意，閒花野草漫爭春。"]'),
('fcf3a66a-e95c-48a2-8fe8-507d9f9816ff','扇子詩  其八四','李石','宋','宋诗','song-poetry','','[]','變將冬暖作春寒，葉上霜痕苦未乾。',32,'全唐诗/poet.song.116000.json','["變將冬暖作春寒，葉上霜痕苦未乾。", "菜甲麥苗須少待，扶輪何日上長安。"]'),
('7d5f06ee-6ddd-420f-9d31-236a2230eabd','扇子詩  其八五','李石','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','洞庭波浪五湖秋，縹緲雲霄帝子樓。',32,'全唐诗/poet.song.116000.json','["洞庭波浪五湖秋，縹緲雲霄帝子樓。", "樓上故人窮骨相，簫韶聲裡認仙舟。"]'),
('3e0ed802-3eea-4275-8f37-6f8dcf45a4bb','扇子詩  其八六','李石','宋','宋诗','song-poetry','','[]','碧海鯨魚掣釣綸，後生立意要求新。',32,'全唐诗/poet.song.116000.json','["碧海鯨魚掣釣綸，後生立意要求新。", "求新未必勝如舊，蘇李元來是古人。"]'),
('a86ff32a-145a-4090-9517-3b07fce2e0c9','扇子詩  其八七','李石','宋','宋诗','song-poetry','','[]','蠟面吹香細細斟，青梅不厭綠杯深。',32,'全唐诗/poet.song.116000.json','["蠟面吹香細細斟，青梅不厭綠杯深。", "鶑兒燕子能饒舌，要問先生學醉吟。"]'),
('5f14284a-97b2-46fd-9eaf-f7f927dd2e04','扇子詩  其八八','李石','宋','宋诗','song-poetry','','[]','栩栩齁齁睡足仙，華山濃睡一千年。',32,'全唐诗/poet.song.116000.json','["栩栩齁齁睡足仙，華山濃睡一千年。", "龜兒不食龍兒蟄，睡裏人間變海田。"]'),
('31502ff1-7895-40cc-be6b-276171ce890e','一飛居憂題扇贈之','李石','宋','宋诗','song-poetry','','[]','南山雪色老於菟，鏡裏功名鑷鬢鬚。',32,'全唐诗/poet.song.116000.json','["南山雪色老於菟，鏡裏功名鑷鬢鬚。", "袖裹白巾渠信否，罇前一擲看呼盧。"]'),
('2e120bbf-1e71-40ac-af61-3e1890ea401b','王真畫桃花玉頰兒扇','李石','宋','宋诗','song-poetry','','[]','飛上桃花玉頰兒，小紅輕踏碧萎蕤。',32,'全唐诗/poet.song.116000.json','["飛上桃花玉頰兒，小紅輕踏碧萎蕤。", "莫教啄破枝頭雨，怕見臙脂淚點垂。"]'),
('c1e92136-d4b3-4196-9c18-e636ecb243fc','犒蠻給衣','李石','宋','宋诗','song-poetry','','[]','氈裘重譯裹風腥，改襲衣冠拜舞輕。',32,'全唐诗/poet.song.116000.json','["氈裘重譯裹風腥，改襲衣冠拜舞輕。", "不是兩階蒙聖化，應將五餌笑書生。"]'),
('34527570-e9fb-4581-b72a-eb9bf51e3bd5','德輝郎君名嘉橘其小字也書來云修嘉辰故事並蒙惠二尊悵然有感二首  其一','李石','宋','宋诗','song-poetry','','[]','風高準擬整烏巾，簪菊難逢酒主人。',32,'全唐诗/poet.song.116000.json','["風高準擬整烏巾，簪菊難逢酒主人。", "爲語閉門投轄子，一般麴糵萬家春。"]'),
('03598221-2040-428e-a75f-8ab0ae4afb76','德輝郎君名嘉橘其小字也書來云修嘉辰故事並蒙惠二尊悵然有感二首  其二','李石','宋','宋诗','song-poetry','','[]','逐客佳晨省醉眠，出門未辦杖頭錢。',32,'全唐诗/poet.song.116000.json','["逐客佳晨省醉眠，出門未辦杖頭錢。", "却因厨釀分雙榼，添入詩圖作九仙。"]'),
('cd884df7-c2af-41e4-89b6-f06596cb7503','次韻季真留別','李石','宋','宋诗','song-poetry','','[]','即物那知身是客，黄花空自委籬東。',32,'全唐诗/poet.song.116000.json','["即物那知身是客，黄花空自委籬東。", "淚痕已逐西風盡，只有悲秋寫未窮。"]'),
('62e7c3b1-bc38-43d2-bfab-65059e464dfd','秋夜待月','李石','宋','宋诗','song-poetry','','[]','白毫光裏玉魂飛，留看常娥醉魄迷。',32,'全唐诗/poet.song.116000.json','["白毫光裏玉魂飛，留看常娥醉魄迷。", "一任簷牙沸蝙蝠，忍將明鏡照狐狸。"]'),
('757ddcc8-2cf0-4eef-b5a5-5f33b59797f6','九日四首  其一','李石','宋','宋诗','song-poetry','','[]','從來醒醉不關渠，肯爲籬邊問所須。',32,'全唐诗/poet.song.116000.json','["從來醒醉不關渠，肯爲籬邊問所須。", "冷笑淵明癡望眼，只堪把菊佩茱萸。"]'),
('f254a0a4-ccd3-4913-8087-d54a7f19c3bd','九日四首  其二','李石','宋','宋诗','song-poetry','','[]','癡兒索錢要沽酒，吾豈紿兒囊已羞。',32,'全唐诗/poet.song.116000.json','["癡兒索錢要沽酒，吾豈紿兒囊已羞。", "乃翁作詩須汝和，覓句共登西北樓。"]'),
('cea25e8c-5747-4670-8a17-17912c878caf','九日四首  其三','李石','宋','宋诗','song-poetry','','[]','昔人卧聽門前雪，我亦坐看籬下花。',32,'全唐诗/poet.song.116000.json','["昔人卧聽門前雪，我亦坐看籬下花。", "不是雨多門自掩，情知歲惡酒難賒。"]'),
('05c57497-4848-42d6-b70d-4a6e3e57883e','九日四首  其四','李石','宋','宋诗','song-poetry','','[]','典裘貿布得杯觴，俗認虛名作醉鄉。',32,'全唐诗/poet.song.116000.json','["典裘貿布得杯觴，俗認虛名作醉鄉。", "溪雨山風妬酒色，踈籬冷蘂逐人忙。"]'),
('45575252-000e-461a-ac06-c328ec346526','大渡河魚甚美皆巨口細鱗鱖也本草以鱖爲石桂魚','李石','宋','宋诗','song-poetry','','[]','小躍氷泉玉不如，細生仍得芼春蔬。',32,'全唐诗/poet.song.116000.json','["小躍氷泉玉不如，細生仍得芼春蔬。", "莫將北海金虀鱠，輕比西江石桂魚。"]'),
('001bef6c-8286-4f00-842f-dd5ed5b15310','喚魚亭','李石','宋','宋诗','song-poetry','','[]','湖水涵空雪浸崖，老龍以下聽差排。',32,'全唐诗/poet.song.116000.json','["湖水涵空雪浸崖，老龍以下聽差排。", "從今分鉢供魚餠，日與隨鐘具一齋。"]'),
('1d9e9cef-c43b-4966-802c-f0790945698b','謝韞玉送炭','李石','宋','宋诗','song-poetry','','[]','佛頂分明火焰高，黑瑿何事助焦熬。',32,'全唐诗/poet.song.116000.json','["佛頂分明火焰高，黑瑿何事助焦熬。", "只銷一酌梅花雪，我已官曹似水曹。"]'),
('2e0952ee-3b1b-429a-b1e5-cbb866b0e684','寄題用之太丞真意閣','李石','宋','宋诗','song-poetry','','[]','真醫曾活水中龍，三卷奇書玉笈中。',32,'全唐诗/poet.song.116000.json','["真醫曾活水中龍，三卷奇書玉笈中。", "酒熟定應登傑閣，與龍對酌海螺紅。"]'),
('681c2a49-7ebd-45ad-9390-f03e8304f49a','殿柱記','李石','宋','宋诗','song-poetry','','[]','蒼龍甲戌歲，修築周公殿。',180,'全唐诗/poet.song.116000.json','["蒼龍甲戌歲，修築周公殿。", "文翁至高君，學校已再變。", "順考興平年，寔紀漢之獻。", "或云鍾會書，入木字隠見。", "自獻而至會，朔曆斗杓轉。", "會初入蜀時，意不止弱禪。", "有如猿猱繫，百巧欲伺便。", "殺女不作難，機鋒劇刀箭。", "會書固出繇，家法素所善。", "至學艾筆跡，暮夜走郵傳。", "老昭豈易欺，真僞猝難辨。", "欺昭爾尚可，蜀士多秀彥。", "當其下筆時，寧不愧顔面。", "雖蒙黼藻文，不揜糞土賤。", "周公儻有靈，白日下雷電。"]'),
('5f85a022-c92d-4eee-8c3d-b7974cc07e6a','左右生題名','李石','宋','宋诗','song-poetry','','[]','蜀地雖遠天之涯，蜀人只隔一水巴。',144,'全唐诗/poet.song.116000.json','["蜀地雖遠天之涯，蜀人只隔一水巴。", "自從文翁建此學，此俗化爲齊魯家。", "泮林春風桑椹熟，集鼓坎坎聞晨撾。", "諸生堂奧分左右，相比以立如排衙。", "九牧之金充歲貢，搜出精礦遺其沙。", "卿雲褒武皆蜀秀，虎豹各自雄鬚牙。", "兩京得人廣數路，忍使丘中留子嗟。", "不然題名百許輩，無一顯者何謂耶。", "我亦典學老從事，試向坐中尋孟嘉。"]'),
('97e688d4-6241-485a-9837-7b2263225e2c','秦城二絕  其一','李石','宋','宋诗','song-poetry','','[]','泮林堂後面崢嶸，不道詩書恨未平。',32,'全唐诗/poet.song.116000.json','["泮林堂後面崢嶸，不道詩書恨未平。", "瓜蔓深坑餘鬼哭，此間學校倚秦城。"]'),
('ea4eb9dc-db49-4e10-a980-cef37460c1b6','秦城二絕  其二','李石','宋','宋诗','song-poetry','','[]','塹成雉堞繞蠶叢，漢棧分明蜀徼通。',32,'全唐诗/poet.song.116000.json','["塹成雉堞繞蠶叢，漢棧分明蜀徼通。", "只說金牛能誑客，已輸巴粟到關中。"]'),
('ea570d6b-ec96-4d1d-8e2e-12abb0c62db2','題環碧亭','李石','宋','宋诗','song-poetry','','[]','十里漣漪陸瑁湖，一亭幽絕重先居。',64,'全唐诗/poet.song.116000.json','["十里漣漪陸瑁湖，一亭幽絕重先居。", "雲根數朵排青闥，泉沫雙流濺綠裾。", "竹鎖斷橋飛雁鶩，荷侵凉檻蔭龜魚。", "洛園還許人同樂，時向林間望小車。"]'),
('14111f32-cb87-43ef-8963-cdcce97c1c64','千葉梅  其一','李石','宋','宋诗','song-poetry','','[]','荼䕷薰肌屑沉水，郁李注臉勻丹砂。',32,'全唐诗/poet.song.116000.json','["荼䕷薰肌屑沉水，郁李注臉勻丹砂。", "子真吳市變名姓，仙種自是成一家。"]'),
('e7282449-9986-4981-8946-86b3c8fa4970','千葉梅  其二','李石','宋','宋诗','song-poetry','','[]','一株女仙瓊玉蕊，千葉化佛冰雪團。',32,'全唐诗/poet.song.116000.json','["一株女仙瓊玉蕊，千葉化佛冰雪團。", "且袖今時宰相手，領取前輩儒生酸。"]'),
('00c6b753-65f9-4e12-990b-0d8de14cae94','千葉梅  其三','李石','宋','宋诗','song-poetry','','[]','接花莫接南北枝，姑射仙人冰雪肌。',32,'全唐诗/poet.song.116000.json','["接花莫接南北枝，姑射仙人冰雪肌。", "一塵不食自然瘦，紅紅紫紫糠籺肥。"]'),
('c6764328-1914-478e-a61d-8d5995fe1264','千葉梅  其四','李石','宋','宋诗','song-poetry','','[]','野芋接花一日事，刻玉作楮三年工。',32,'全唐诗/poet.song.116000.json','["野芋接花一日事，刻玉作楮三年工。", "此家妙有轉物手，老圃寬褐藏春風。"]'),
('293cafdc-6a36-451f-9f67-15c71dfcadc2','瞿唐峽','李石','宋','宋诗','song-poetry','','[]','花開歸去客在船，人道雲安有杜鵑。',32,'全唐诗/poet.song.116000.json','["花開歸去客在船，人道雲安有杜鵑。", "峽山無路續百丈，胡獼上樹拊聯天。"]'),
('62975449-c752-40aa-b2ce-a40fd0fdb4a6','峽中','李石','宋','宋诗','song-poetry','','[]','峽水方中駐，歸舟泝蜀門。',48,'全唐诗/poet.song.116000.json','["峽水方中駐，歸舟泝蜀門。", "竹枝聲處處，梅蕊雪村村。", "來去山巒笑，啼號地主恩。", "幸然窮性命，不必賦招魂。"]'),
('87a129d6-a6b9-4d12-85e9-746efa24a687','句  其一','李石','宋','宋诗','song-poetry','','[]','便令巴水濃如酒，巴邑巴村醉花柳。',16,'全唐诗/poet.song.116000.json','["便令巴水濃如酒，巴邑巴村醉花柳。"]'),
('fe951d2f-9db4-4274-b726-60c9bf4572c1','句  其二','李石','宋','宋诗','song-poetry','','[]','留船買魚作寒節。',8,'全唐诗/poet.song.116000.json','["留船買魚作寒節。"]'),
('21fe3d73-2615-4c36-84a9-813b8de6f18b','偈頌十八首  其一','釋師體','宋','宋诗','song-poetry','','[]','五藴出頭一段空，同門出入不相逢。',32,'全唐诗/poet.song.116000.json','["五藴出頭一段空，同門出入不相逢。", "無量劫來賃屋住，到頭不識主人公。"]'),
('4bc345aa-ae34-41f0-af6a-58780e4062a5','偈頌十八首  其二','釋師體','宋','宋诗','song-poetry','','[]','童頂雲衣野興濃，清齋淡話有何窮。',32,'全唐诗/poet.song.116000.json','["童頂雲衣野興濃，清齋淡話有何窮。", "春歸簷幕千家雨，月滿樓臺一笛風。"]'),
('9643d38a-e430-40dc-921b-fe84c528ae4b','偈頌十八首  其三','釋師體','宋','宋诗','song-poetry','','[]','塗灰抹土添光彩，社舞村歌笑己躬。',64,'全唐诗/poet.song.116000.json','["塗灰抹土添光彩，社舞村歌笑己躬。", "堪笑當年獃得好，百無一解訴心空。", "星拱北，水朝東，月落千江體一同。", "能向海門深處輥，行船誰怕打頭風。"]'),
('a6824e4d-42b8-4b7f-b9f2-f6d900be5c71','偈頌十八首  其四','釋師體','宋','宋诗','song-poetry','','[]','西土尊師故紙羅，南方歷祖葛藤窠。',64,'全唐诗/poet.song.116000.json','["西土尊師故紙羅，南方歷祖葛藤窠。", "臨風剔起透青眼，跟脚從頭覷破那。", "阿呵呵，會也麽，尺水休誇一丈波。", "幕天蓆地生涯闊，敵勝吹毛不用磨。"]'),
('7a300493-15fc-4a04-9d74-2434ed25a257','偈頌十八首  其五','釋師體','宋','宋诗','song-poetry','','[]','不守師承不會禪，饑來喫飯困來眠。',32,'全唐诗/poet.song.116000.json','["不守師承不會禪，饑來喫飯困來眠。", "平常肯恃拳頭大，冷地乾贏空劫前。"]'),
('cb7bcbec-7f26-4396-acdf-95a637b7f57e','偈頌十八首  其六','釋師體','宋','宋诗','song-poetry','','[]','目擊泄天機，梅天散花雨。',68,'全唐诗/poet.song.116000.json','["目擊泄天機，梅天散花雨。", "稽首毗盧師，和南法身主。", "風光遍大千，捏在毫端聚。", "多劫修來是浪傳，一念不生傾肺腑。", "從此兒孫遍世間，活計清虛爭檢古。"]'),
('dabd6031-332c-40cf-82fc-9487a3a0de77','偈頌十八首  其七','釋師體','宋','宋诗','song-poetry','','[]','麤疎带出蓮花笠，濟楚披來糞掃衣。',64,'全唐诗/poet.song.116000.json','["麤疎带出蓮花笠，濟楚披來糞掃衣。", "拈起少林無孔笛，左瞻右盼兩頭吹。", "聲聲慢，拍拍隨，聽者雖多和者稀。", "曲徧欲休休不得，知音知後更誰知。"]'),
('83c7c686-8b48-4bb5-aa2f-94c1bbf16977','偈頌十八首  其八','釋師體','宋','宋诗','song-poetry','','[]','少室無師句，曹溪絕學禪。',24,'全唐诗/poet.song.116000.json','["少室無師句，曹溪絕學禪。", "渾家鬼擘口，五逆不成寃。"]'),
('31eb7162-5ed8-4c2d-a92d-ab99c9ad1b8e','偈頌十八首  其九','釋師體','宋','宋诗','song-poetry','','[]','文殊三處度夏，彌勒一味放憨。',42,'全唐诗/poet.song.116000.json','["文殊三處度夏，彌勒一味放憨。", "善財走百十城，達磨九年面壁。", "恢闡拈花微笑，光揚布髮掩泥。"]'),
('755f1387-8c8c-4c7e-abfd-bbe34cd45b8b','偈頌十八首  其一○','釋師體','宋','宋诗','song-poetry','','[]','一拳也是打爺來，未有輸贏莫放開。',32,'全唐诗/poet.song.116000.json','["一拳也是打爺來，未有輸贏莫放開。", "割捨拍盲窮性命，觜喎鼻塌見全材。"]'),
('a32e846c-bdc1-43e1-b9bb-ba187734a9a9','偈頌十八首  其一一','釋師體','宋','宋诗','song-poetry','','[]','道妙休云所得遲，不離聞見分明極。',64,'全唐诗/poet.song.116000.json','["道妙休云所得遲，不離聞見分明極。", "檻外一聲婆餠焦，黄頭碧眼斷消息。", "斷消息，最條直，是虎何須更插翼。", "蒼龍平地起波瀾，萬仞峯頭轟霹靂。"]'),
('c7448d36-93cb-42e2-a7d6-208f3955c427','偈頌十八首  其一二','釋師體','宋','宋诗','song-poetry','','[]','口朝鼻孔無空過，眼蓋胡鬚有古風。',32,'全唐诗/poet.song.116000.json','["口朝鼻孔無空過，眼蓋胡鬚有古風。", "信彩骨頭花十八，等閒擲出滿盆紅。"]'),
('b7eaed6c-9fb7-44f9-9e39-e01ee4d36ff1','偈頌十八首  其一三','釋師體','宋','宋诗','song-poetry','','[]','夤緣過夏又經冬，難易當知好惡同。',64,'全唐诗/poet.song.116000.json','["夤緣過夏又經冬，難易當知好惡同。", "肚裏饑瘡無聒擾，堂中生炭滿爐紅。", "挑灰弄火非相許，闊論高談定不容。", "疊足跏趺描不就，眼空烟景振宗風。"]'),
('515e8fd1-030f-403c-b20e-8c3bad3c519f','偈頌十八首  其一四','釋師體','宋','宋诗','song-poetry','','[]','天際雲翻墨，江頭浪輥花。',56,'全唐诗/poet.song.116000.json','["天際雲翻墨，江頭浪輥花。", "胡僧無鑑識，特地渡流沙。", "赤骨歷窮擔片板，顛癡㪍癩豎雙眉。", "驀生做處難名狀，佛祖當頭聽指揮。"]'),
('674390c9-1c22-4b35-8a32-42c08f692211','偈頌十八首  其一五','釋師體','宋','宋诗','song-poetry','','[]','虎穴魔宮闊步挨，毀僧謗佛不安排。',32,'全唐诗/poet.song.116000.json','["虎穴魔宮闊步挨，毀僧謗佛不安排。", "無明三毒令人怕，是我寃家一樣乖。"]'),
('ec87b6df-e171-430f-8520-beffc68a2953','偈頌十八首  其一六','釋師體','宋','宋诗','song-poetry','','[]','耳有重輪非差事，胸題卍字亦尋常。',32,'全唐诗/poet.song.116000.json','["耳有重輪非差事，胸題卍字亦尋常。", "腰間不束三條篾，萬頃風煙一草堂。"]'),
('a78248b6-f0ce-44e4-bbd1-1c8705c2879a','偈頌十八首  其一七','釋師體','宋','宋诗','song-poetry','','[]','暗撒驪珠成瓦礫，閒傾鴆毒是醍醐。',32,'全唐诗/poet.song.116000.json','["暗撒驪珠成瓦礫，閒傾鴆毒是醍醐。", "寃將恩報滅胡種，舉眼無親真丈夫。"]'),
('f2fe93d2-00f3-4cc2-a403-3aa30e8a18e5','頌古十四首  其一','釋師體','宋','宋诗','song-poetry','','[]','妙峯孤頂無知識，百十城遊喪善財。',32,'全唐诗/poet.song.116000.json','["妙峯孤頂無知識，百十城遊喪善財。", "樓閣若還彈指見，分明有眼不曾開。"]'),
('49da7bc3-ecf6-4504-8257-c38a8bc5813e','頌古十四首  其二','釋師體','宋','宋诗','song-poetry','','[]','棒頭落節來翻本，閃電光中立信旗。',32,'全唐诗/poet.song.116000.json','["棒頭落節來翻本，閃電光中立信旗。", "殃害叢林無說處，幾人錯認口頭肥。"]'),
('441d166c-6c4f-41f7-8ac8-9b8d5859cb85','頌古十四首  其三','釋師體','宋','宋诗','song-poetry','','[]','坦然古路勿迂疎，霽月凉風動十虛。',32,'全唐诗/poet.song.116000.json','["坦然古路勿迂疎，霽月凉風動十虛。", "毗目善財當日事，好如潘閬倒騎馿。"]'),
('812f6ef9-3eda-4433-8e39-a4c877cfb66c','頌古十四首  其四','釋師體','宋','宋诗','song-poetry','','[]','門庭推倒亂縱橫，火迸星飛無路行。',32,'全唐诗/poet.song.116000.json','["門庭推倒亂縱橫，火迸星飛無路行。", "赤契分明基業在，依前淺種又深耕。"]'),
('33ee8737-0526-4855-a7bb-4917bd1c039f','頌古十四首  其五','釋師體','宋','宋诗','song-poetry','','[]','桃花零落眼方開，自謂風流孰可陪。',32,'全唐诗/poet.song.116000.json','["桃花零落眼方開，自謂風流孰可陪。", "叵耐玄沙忒偏黨，却來醉後便添盃。"]'),
('031e7984-40d4-43f0-8a46-df2d6d2c67b0','頌古十四首  其六','釋師體','宋','宋诗','song-poetry','','[]','早朝心悶三盃酒，午後頭昏一椀茶。',32,'全唐诗/poet.song.116000.json','["早朝心悶三盃酒，午後頭昏一椀茶。", "入夜脫衣伸脚睡，五更走起眼瞇𥊚。"]'),
('38122f13-b6f1-40a1-b6b0-08a08efacdad','頌古十四首  其七','釋師體','宋','宋诗','song-poetry','','[]','陽春白雪非難和，藻鑑氷壺豈足觀。',32,'全唐诗/poet.song.116000.json','["陽春白雪非難和，藻鑑氷壺豈足觀。", "一把柳絲收不得，和風搭在玉欄干。"]'),
('d6ef77a0-e005-4f6a-bf2b-b36f985d8b86','頌古十四首  其八','釋師體','宋','宋诗','song-poetry','','[]','眼空四海恣縱橫，鼻孔遼天信脚行。',32,'全唐诗/poet.song.116000.json','["眼空四海恣縱橫，鼻孔遼天信脚行。", "拏得電光爲火把，却來日午打三更。"]'),
('c09d8fcd-55ef-40c3-a183-b8b2554a4457','頌古十四首  其九','釋師體','宋','宋诗','song-poetry','','[]','和煙釣月是生涯，古策風高未足誇。',32,'全唐诗/poet.song.116000.json','["和煙釣月是生涯，古策風高未足誇。", "欵乃一聲天地闊，祖師何必渡流沙。"]'),
('edf136d1-0b75-4207-9d25-fe321bf2b860','頌古十四首  其一○','釋師體','宋','宋诗','song-poetry','','[]','竹溪煙絕雨才通，無數深紅間淺紅。',32,'全唐诗/poet.song.116000.json','["竹溪煙絕雨才通，無數深紅間淺紅。", "山店落英春寂寂，青旗吹動柳花風。"]'),
('98c9aec2-0a77-4171-a7fe-95eb87bd0e66','頌古十四首  其一一','釋師體','宋','宋诗','song-poetry','','[]','屈節從長也大拚，雪堆斷臂仰高寒。',32,'全唐诗/poet.song.116000.json','["屈節從長也大拚，雪堆斷臂仰高寒。", "鐵牛鞭起熊峯下，一吸黄河徹底乾。"]'),
('d6f0d5a0-822c-4c38-b01a-076a2239df54','頌古十四首  其一二','釋師體','宋','宋诗','song-poetry','','[]','雨色和煙匝四維，眼皮未綻若爲窺。',32,'全唐诗/poet.song.116000.json','["雨色和煙匝四維，眼皮未綻若爲窺。", "等閒覷破金剛際，坦蕩無因役路岐。"]'),
('f3919b65-f9f3-44f4-8c3a-56bf6017e4c7','頌古十四首  其一三','釋師體','宋','宋诗','song-poetry','','[]','添錢買得漏燈盞，洗脚長拖破草鞋。',32,'全唐诗/poet.song.116000.json','["添錢買得漏燈盞，洗脚長拖破草鞋。", "翻著襴衫歌雪曲，倒携蓆帽趕村齋。"]'),
('46d7f8ff-0fda-4ecc-8731-bcfdb1e010d4','頌古十四首  其一四','釋師體','宋','宋诗','song-poetry','','[]','斫頭瀝血摩訶演，掛肚懸腸薩怛多。',32,'全唐诗/poet.song.116000.json','["斫頭瀝血摩訶演，掛肚懸腸薩怛多。", "惡口小家無盡藏，更將何法度娑婆。"]'),
('cbe06ba1-6993-4ef0-873f-a40552c73549','達磨贊','釋師體','宋','宋诗','song-poetry','','[]','萬福西來老骨撾，不遵行止渡流沙。',32,'全唐诗/poet.song.116000.json','["萬福西來老骨撾，不遵行止渡流沙。", "被人打落當門齒，啞子依前喫苦瓜。"]'),
('091639ae-0ff7-4233-abae-54497bfc4f29','卧蓮翫月觀音贊','釋師體','宋','宋诗','song-poetry','','[]','上絕把茆江月白，下無寸土眼頭寬。',32,'全唐诗/poet.song.116000.json','["上絕把茆江月白，下無寸土眼頭寬。", "青蓮影裏安身法，普與勞生了正觀。"]'),
('d2bad0c0-299f-49f4-bc16-8f9129a562ac','船子贊','釋師體','宋','宋诗','song-poetry','','[]','孤蹤短艇寓江濱，眼蓋乾坤徹骨貧。',32,'全唐诗/poet.song.116000.json','["孤蹤短艇寓江濱，眼蓋乾坤徹骨貧。", "接了夾山鑽入水，至今恩怨不曾分。"]'),
('b5bcc21c-7550-4a77-9a22-19cc470d340b','自贊','釋師體','宋','宋诗','song-poetry','','[]','歲寒節操，水月精神。',38,'全唐诗/poet.song.116000.json','["歲寒節操，水月精神。", "隨所住處，無過任真。", "咦，今古江山今古意，一番雨過一番新。"]'),
('257fc6ac-3528-403a-8c95-4c4e54ce656d','四聖贊  其一','釋師體','宋','宋诗','song-poetry','','[]','稽首釋迦，現千百億。',40,'全唐诗/poet.song.116000.json','["稽首釋迦，現千百億。", "鹽貴米賤，苦趁樂喫。", "瞋喜愛憎，是非聲色。", "日炙風吹，一文不直。"]'),
('0aeb4e82-a5ab-4f9b-bf5e-0149c97127aa','四聖贊  其二','釋師體','宋','宋诗','song-poetry','','[]','稽首觀音，全彰妙有。',40,'全唐诗/poet.song.116000.json','["稽首觀音，全彰妙有。", "鶴唳青霄，鶑啼綠柳。", "鼓響鍾鳴，椎鷄打狗。", "不落諸緣，通身眼手。"]'),
('b14e9e03-0259-4167-b272-0ea6d86b5580','四聖贊  其三','釋師體','宋','宋诗','song-poetry','','[]','稽首文殊，本非延促。',40,'全唐诗/poet.song.116000.json','["稽首文殊，本非延促。", "柏短松長，山青水綠。", "星移斗轉，日行月逐。", "開眼合眼，一切具足。"]'),
('61028f4e-3df3-4018-8a34-5ce31b846c7a','四聖贊  其四','釋師體','宋','宋诗','song-poetry','','[]','稽首普賢，不可思議。',40,'全唐诗/poet.song.116000.json','["稽首普賢，不可思議。", "出頭露面，開言吐氣。", "拍盲擔板，忘恩斷義。", "事無寸長，熏天炙地。"]'),
('696e959b-0d0d-468e-8aa8-972320b46756','總頌','釋師體','宋','宋诗','song-poetry','','[]','釋迦觀音，文珠普賢。',40,'全唐诗/poet.song.116000.json','["釋迦觀音，文珠普賢。", "驀鼻牽來，作一串穿。", "橫拖倒拽，痛報深寃。", "彌天罪過，一任流傳。"]'),
('cbedca90-c9a5-4359-8d5f-105f944d99cb','頌古十首  其一','釋師體','宋','宋诗','song-poetry','','[]','三清道士無仙骨，八教闍梨毀梵書。',32,'全唐诗/poet.song.116000.json','["三清道士無仙骨，八教闍梨毀梵書。", "黑添崑崙舞華鼓，天親無著暗嗟吁。"]'),
('0b2339eb-ab46-48bb-9564-795d36c716ab','頌古十首  其二','釋師體','宋','宋诗','song-poetry','','[]','不見人斑見虎斑，算來莫願見人斑。',32,'全唐诗/poet.song.116000.json','["不見人斑見虎斑，算來莫願見人斑。", "虎斑見後通回避，唯有人斑近最難。"]'),
('44d35354-b05d-47f5-9f52-5dbd621e9d04','頌古十首  其三','釋師體','宋','宋诗','song-poetry','','[]','渾身無處著，驛路倒騎馿。',24,'全唐诗/poet.song.116000.json','["渾身無處著，驛路倒騎馿。", "覽盡瀟湘景，和船入畫圖。"]'),
('c0e113b0-4c75-4e3b-b9f7-fb84a4a06adc','頌古十首  其四','釋師體','宋','宋诗','song-poetry','','[]','越鳥巢南枝，胡馬嘶北風。',48,'全唐诗/poet.song.116000.json','["越鳥巢南枝，胡馬嘶北風。", "狸奴并白牯，寸步不曾通。", "千山都坐斷，萬派盡朝東。", "天王纔合掌，那吒撲帝鍾。"]'),
('03b963c8-ce2a-49d9-8834-4526e4a56ef8','頌古十首  其五','釋師體','宋','宋诗','song-poetry','','[]','假使百千劫，所作業不忘。',24,'全唐诗/poet.song.116000.json','["假使百千劫，所作業不忘。", "因緣會遇時，果報還自受。"]'),
('f4e5079c-9659-448e-9e37-10e38b08deef','頌古十首  其六','釋師體','宋','宋诗','song-poetry','','[]','白石居山人，不住那伽定。',48,'全唐诗/poet.song.116000.json','["白石居山人，不住那伽定。", "拄杖禿却枝，鉢盂倒安柄。", "人草覓寃讎，虛空懸業鏡。", "喝下劍光寒，放行摩竭令。"]'),
('df6f3ca1-8224-4e10-8c1b-a078e5681d4c','頌古十首  其七','釋師體','宋','宋诗','song-poetry','','[]','剔起遮天眼，空王舊話圓。',48,'全唐诗/poet.song.116000.json','["剔起遮天眼，空王舊話圓。", "氣毬剛似鐵，石臼軟如綿。", "苦海無驚浪，紅爐斷火煙。", "莊周蝴蝶夢，舉世若爲原。"]'),
('f6ef5c61-38a9-41f4-9bed-01aef17dc01a','頌古十首  其八','釋師體','宋','宋诗','song-poetry','','[]','著脚孤危草不生，沒棲泊處等閑行。',32,'全唐诗/poet.song.116000.json','["著脚孤危草不生，沒棲泊處等閑行。", "臨風闊却噇空口，斷送渾家入火坑。"]'),
('eaa887c5-b7c9-4c2e-91da-9529409754e6','頌古十首  其九','釋師體','宋','宋诗','song-poetry','','[]','生獰別是一般村，品藻先賢薄後昆。',32,'全唐诗/poet.song.116000.json','["生獰別是一般村，品藻先賢薄後昆。", "掉放孤峰爭合殺，棒頭有眼蓋乾坤。"]'),
('628d2b49-2f5e-40bd-8e77-c78e8133db5e','頌古十首  其一○','釋師體','宋','宋诗','song-poetry','','[]','男兒脚底透長安，得坐披衣肯自謾。',32,'全唐诗/poet.song.116000.json','["男兒脚底透長安，得坐披衣肯自謾。", "三尺冷光輝夜月，一條秋水迸人寒。"]'),
('da5edcfb-c064-4fb2-999b-de79dbe99be1','偈四首  其一','釋師體','宋','宋诗','song-poetry','','[]','年年浴佛在今朝，目擊迦維路不遥。',32,'全唐诗/poet.song.116000.json','["年年浴佛在今朝，目擊迦維路不遥。", "果是當時曾示現，宜乎惡水驀頭澆。"]'),
('38e63242-f084-484e-b87f-af9f9a56ce35','偈四首  其二','釋師體','宋','宋诗','song-poetry','','[]','熱月須摇扇，寒來旋著衣。',24,'全唐诗/poet.song.116000.json','["熱月須摇扇，寒來旋著衣。", "若言空過日，大似不知時。"]'),
('67eab267-4cac-47f0-8514-b04f0a53bd0a','偈四首  其三','釋師體','宋','宋诗','song-poetry','','[]','道生一，無角鐵牛眠少室。',93,'全唐诗/poet.song.116000.json','["道生一，無角鐵牛眠少室。", "一生二，祖父開田說大義。", "二生三，梁間紫燕語呢喃。", "三生萬物，男兒活計離窠窟。", "多處添，少處減，大蟲怕喫生人膽。", "有若無，實若虛，爭掩驪龍明月珠。", "肚無偏僻病，不怕冷油虀。"]'),
('19e717c3-e577-4a91-b810-cbd82f67111f','偈四首  其四','釋師體','宋','宋诗','song-poetry','','[]','依稀苕帚柄，髣髴赤斑蛇。',24,'全唐诗/poet.song.116000.json','["依稀苕帚柄，髣髴赤斑蛇。", "棒下無生忍，臨機不識爺。"]'),
('5bfcce35-53c0-4b0c-8954-a72a95c7f6c1','辭衆偈','釋師體','宋','宋诗','song-poetry','','[]','鐵樹開花，雄雞生卵。',20,'全唐诗/poet.song.116000.json','["鐵樹開花，雄雞生卵。", "七十二年，摇籃繩斷。"]'),
('660ccc91-62ff-419c-a1e9-5690cd6fb130','頌古二十九首  其一','釋師體','宋','宋诗','song-poetry','','[]','走出門風相副稱，東西南北更無人。',32,'全唐诗/poet.song.116000.json','["走出門風相副稱，東西南北更無人。", "看來不得韶陽老，未免兒孫惹客塵。"]'),
('3d9d9cef-c35c-49ce-a88b-e6b19b9f19c5','頌古二十九首  其二','釋師體','宋','宋诗','song-poetry','','[]','肌骨當初赫赤窮，面皮今日厚千重。',32,'全唐诗/poet.song.116000.json','["肌骨當初赫赤窮，面皮今日厚千重。", "撩頭搭尾應更點，嬴賽闍黎齋後鍾。"]'),
('e0bcd431-ca9c-4d15-98a8-bb513756b784','頌古二十九首  其三','釋師體','宋','宋诗','song-poetry','','[]','苦瓠連根苦，同坑無異土。',24,'全唐诗/poet.song.116000.json','["苦瓠連根苦，同坑無異土。", "二千年已前，一火破落戶。"]'),
('9eb634e1-cb7f-4e82-8f8e-35da55f7e467','頌古二十九首  其四','釋師體','宋','宋诗','song-poetry','','[]','陪錢弄傀儡，拚命打鞦韆。',24,'全唐诗/poet.song.116000.json','["陪錢弄傀儡，拚命打鞦韆。", "渾家無眼見，掩面哭蒼天。"]'),
('c77c2256-87cb-4f4c-b3a0-098905fccf14','頌古二十九首  其五','釋師體','宋','宋诗','song-poetry','','[]','是大神呪，四大六根元不有。',86,'全唐诗/poet.song.116000.json','["是大神呪，四大六根元不有。", "是大明呪，三世十方無透漏。", "是無上呪，海印圓光明已久。", "是無等等呪，士農工商各成就。", "何故去年梅，今歲柳，顔色馨香依舊。", "等閒勘破悟桃花，選甚法身藏北斗。"]'),
('286ca6d8-7492-4357-91ad-ae80c446dd93','頌古二十九首  其六','釋師體','宋','宋诗','song-poetry','','[]','君王寶劍不虛施，尊者遭逢也大奇。',32,'全唐诗/poet.song.116000.json','["君王寶劍不虛施，尊者遭逢也大奇。", "從此清風徧寰宇，太平消息幾人知。"]'),
('c27ff697-5fb0-4dee-a9ec-933393c7b65d','頌古二十九首  其七','釋師體','宋','宋诗','song-poetry','','[]','家貧連子屈，事急不由人。',24,'全唐诗/poet.song.116000.json','["家貧連子屈，事急不由人。", "開口露拴索，郎當累近鄰。"]'),
('f5cd3cb9-d538-45d5-868b-2fa940eb29bd','頌古二十九首  其八','釋師體','宋','宋诗','song-poetry','','[]','即心是佛，顢頇淈𣸩。',36,'全唐诗/poet.song.116000.json','["即心是佛，顢頇淈𣸩。", "菽麥不分，光陰飄忽。", "三杯兩碗背爺娘，百怪千妖同一窟。"]'),
('4a673bcb-1c18-471e-b9d2-f75389c03cc5','頌古二十九首  其九','釋師體','宋','宋诗','song-poetry','','[]','動口生荆棘，移身墮野狐。',24,'全唐诗/poet.song.116000.json','["動口生荆棘，移身墮野狐。", "趙州來鬭富，東壁掛葫蘆。"]'),
('2ad15cf7-eb9f-4deb-9e22-fa4691e919d5','頌古二十九首  其一○','釋師體','宋','宋诗','song-poetry','','[]','餓鬼鞭死屍，仙人禮枯骨。',40,'全唐诗/poet.song.116000.json','["餓鬼鞭死屍，仙人禮枯骨。", "野犬吠荒丘，鐵山空突兀。", "六合羣靈競出頭，不知何處爲窠窟。"]'),
('f912c49f-9e48-4bee-a5c6-de385f358dfc','頌古二十九首  其一一','釋師體','宋','宋诗','song-poetry','','[]','克己堂前開飯店，股肱屋裏販揚州。',32,'全唐诗/poet.song.116000.json','["克己堂前開飯店，股肱屋裏販揚州。", "頭戴草鞋呈醜拙，湊成一段好風流。"]'),
('315a3b6e-64e4-4bc5-9398-b7ebdb78eb2d','頌古二十九首  其一二','釋師體','宋','宋诗','song-poetry','','[]','萬里無雲銀漢橫，大方玄路等閑行。',32,'全唐诗/poet.song.116000.json','["萬里無雲銀漢橫，大方玄路等閑行。", "阿爺智量世希有，女子圓光頂𩕳生。"]'),
('d67528c9-80fb-4775-856e-69e304ea97a4','頌古二十九首  其一三','釋師體','宋','宋诗','song-poetry','','[]','義從親處斷，貧向富邊休。',24,'全唐诗/poet.song.116000.json','["義從親處斷，貧向富邊休。", "腰纏十萬貫，騎鶴上揚州。"]');
